window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["artifacts"]={"updatedAt":"2026-07-07","count":419,"artifacts":[{"id":"oan-anh","name":"Oán ảnh","cn":"","aliases":["Lệ nhi"],"category":"phap-bao","categoryLabel":"Pháp bảo đặc thù","phamCap":"không rõ","soHuu":["Liễu Mi"],"trangThai":"đang tồn tại","blurb":"Đứa nhỏ của Vương Lâm và Liễu Mi bị luyện hóa trăm năm thành oán ảnh. Liễu Mi dùng nó như pháp bảo đặc thù để trả thù và khống chế tâm thần Vương Lâm.","detail":"Oán ảnh vốn là đứa nhỏ có quan hệ huyết mạch với Vương Lâm. Liễu Mi luyện hóa nó trăm năm, gieo vào ý thức nó rằng phụ thân đã vứt bỏ nó, rồi đưa ra trước mặt Vương Lâm như một đòn trả thù trực diện vào tâm thần. Khi Liễu Mi gọi Lệ nhi, âm thanh từ oán ảnh trong sương đen khiến Vương Lâm đau đớn như bị xé nát tâm can.","nguon":["@c0635"]},{"id":"tien-ve-khoi-loi","name":"Tiên vệ khôi lỗi","cn":"","aliases":["Tiên vệ"],"category":"phap-bao","categoryLabel":"Khôi lỗi","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang do Vương Lâm điều khiển","blurb":"Khôi lỗi Tiên vệ được Vương Lâm gọi về khi nhận ra oán ảnh trong sương đen. Nó hóa thành bóng ma lớn bao phủ màn sương để ngăn oán ảnh hành động.","detail":"Ngay sau khi cảm nhận quan hệ huyết mạch với oán ảnh, Vương Lâm thu chiêu và gọi Tiên vệ khôi lỗi. Khôi lỗi bao phủ màn sương đen, tạo lớp khống chế để ngăn oán ảnh tiếp tục hành động trong lúc Vương Lâm đối diện Liễu Mi.","nguon":["@c0635"]},{"id":"co-kinh","name":"Cổ kính","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Tiên bảo","phamCap":"Hạ phẩm Tiên bảo","soHuu":["Liễu Mi"],"trangThai":"đang do Liễu Mi sử dụng","blurb":"Hạ phẩm Tiên bảo do Huyễn gia Lão Tổ tặng Liễu Mi. Nàng lấy cổ kính ra để chắn Hoàng tuyền chỉ của Vương Lâm.","detail":"Trong lúc bị Vương Lâm dùng Hoàng tuyền chỉ công kích, Liễu Mi lùi lại và lấy Cổ kính ra phòng ngự. Pháp bảo này được xác nhận là Hạ phẩm Tiên bảo do Huyễn gia Lão Tổ tặng cho nàng.","nguon":["@c0635"]},{"id":"hac-cham-hon-thu-tu","name":"Hắc châm","cn":"","aliases":["Hồn thứ tư"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Liễu Mi"],"trangThai":"đang do Liễu Mi sử dụng","blurb":"Cây châm đen do Liễu Mi phóng ra bằng máu trong lúc nguy cấp. Nó ngăn Thất Tinh kiếm trận và xuyên qua Tịch Diệt chỉ phong trước khi bị Vương Lâm dùng Định khống chế.","detail":"Khi bị Thất Tinh kiếm trận và Tịch Diệt chỉ ép sát, Liễu Mi cắn lưỡi phun máu, từ máu tươi bay ra một cây châm màu đen. Hắc châm còn được gọi là Hồn thứ tư, có thể xoay quanh người nàng để chống kiếm khí và chỉ phong, nhưng bị Vương Lâm thi triển Định khiến khựng lại.","nguon":["@c0635"]},{"id":"thien-nghich-khong-gian","name":"Thiên nghịch không gian","cn":"","category":"phap-bao","categoryLabel":"Không gian pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Không gian trong Thiên nghịch, nơi Vương Lâm đưa oán anh Bình nhi đã bị phong ấn vào để tạm trấn giữ.","detail":"Sau khi dùng cấm chế thu nhỏ và phong ấn oán anh, Vương Lâm đưa Bình nhi vào Thiên nghịch không gian, đồng thời phân một cỗ nguyên thần vào đó để tiếp tục xua oán khí cho con về sau.","nguon":["@c0637"]},{"id":"de-tu-hon-cua-ton-hon-phien","name":"Đệ tử hồn của Tôn Hồn Phiên","cn":"","category":"khac","categoryLabel":"Hồn phách liên quan pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã nhập lại Tôn Hồn Phiên","blurb":"Hồn phách thuộc Tôn Hồn Phiên được Vương Lâm chụp từ hư không và đưa trở lại trong phiên.","detail":"Vương Lâm chụp vào hư không lấy lại đệ tử hồn, nắm trong tay rồi ném vào Tôn Hồn Phiên, nói với Độn Thiên sư phụ rằng đệ tử hồn đã được thu hồi và uy lực của phiên sẽ tái hiện.","nguon":["@c0637"]},{"id":"tinh-la-ban","name":"Tinh La bàn","cn":"","category":"phap-bao","categoryLabel":"Phi hành pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Phi hành pháp bảo hóa thành ngân quang đưa Vương Lâm rời Nhiễm Vân Tinh, lao tới Thiên Huyễn Tinh.","detail":"Sau khi xuyên qua Tỏa Tinh đại trận, Vương Lâm dùng Tinh La bàn. Pháp bảo hóa thành một đạo ngân quang, mang hắn theo vị trí trong ngọc giản của Tôn Tích thẳng tới Thiên Huyễn Tinh.","nguon":["@c0637","@c0672"]},{"id":"ngoc-gian-cua-ton-tich","name":"Ngọc giản của Tôn Tích","cn":"","category":"khac","categoryLabel":"Vật phẩm ghi tin tức","phamCap":"Không rõ","soHuu":["Tôn Tích","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản ghi vị trí Thiên Huyễn Tinh mà Tôn Tích đưa cho Vương Lâm.","detail":"Vị trí Thiên Huyễn Tinh được ghi rõ trong ngọc giản của Tôn Tích. Vương Lâm dựa vào thông tin này, dùng Tinh La bàn lao tới Thiên Huyễn Tinh sau khi rời Nhiễm Vân Tinh.","nguon":["@c0637"]},{"id":"phi-kiem-cua-ton-tich","name":"Phi kiếm của Tôn Tích","cn":"","category":"phap-bao","categoryLabel":"Phi hành pháp bảo","phamCap":"Không rõ","soHuu":["Tôn Tích"],"trangThai":"đang dùng","blurb":"Phi kiếm dưới chân Tôn Tích khi hắn từ thành trì bay ra gặp Vương Lâm.","detail":"Kiếm quang dưới chân Tôn Tích không ổn định khi hắn bay ra khỏi thành, biểu hiện sự sợ hãi sau khi chứng kiến Liễu Mi độc ác và Huyễn gia Lão Tổ từng đích thân tới.","nguon":["@c0637"]},{"id":"tien-bao-truyen-thua-cua-huyen-gia","name":"Tiên bảo truyền thừa của Huyễn gia","cn":"","category":"phap-bao","categoryLabel":"Tiên bảo","phamCap":"Truyền thừa tiên nhân","soHuu":["Huyễn gia"],"trangThai":"đang được Huyễn gia nắm giữ","blurb":"Tiên bảo do tiên nhân Huyễn gia để lại. Đây là một trong các nguyên nhân giúp Huyễn gia giữ địa vị lớn trên Thiên Huyễn Tinh.","detail":"Tiên bảo truyền thừa của Huyễn gia được nhắc trong phần xác lập thế cục ba gia tộc. Chương chưa mô tả hình dáng hoặc công năng cụ thể, chỉ cho biết nó là chỗ dựa quan trọng của Huyễn gia cùng ngọc giản hộ tộc.","nguon":["@c0638"]},{"id":"ngoc-gian-ho-toc-huyen-gia","name":"Ngọc giản hộ tộc Huyễn gia","cn":"","category":"khac","categoryLabel":"Ngọc giản truyền thừa","phamCap":"Truyền thừa tiên nhân","soHuu":["Huyễn gia"],"trangThai":"đang được Huyễn gia nắm giữ","blurb":"Ngọc giản hộ tộc chứa một đạo thần thông do tiên nhân Huyễn gia lưu lại. Nó góp phần khiến Huyễn gia được các thế lực trên Thiên Huyễn Tinh kiêng kị.","detail":"Ngọc giản hộ tộc Huyễn gia là vật truyền thừa của tiên nhân Huyễn gia. Nội dung chính được nhắc là một đạo thần thông bên trong, chưa lộ cách thi triển trong chương này.","nguon":["@c0638"]},{"id":"tui-tru-vat-chua-tien-ngoc-cua-thien-quy-tu","name":"Túi trữ vật chứa Tiên ngọc của Thiên Quỳ Tử","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Chứa Tiên ngọc","soHuu":["Thiên Quỳ Tử","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Túi trữ vật Thiên Quỳ Tử đưa cho Vương Lâm để bồi thường. Vật bên trong là Tiên ngọc, dùng để xoa dịu việc lão đã chặn đường và suýt đắc tội người mà lão tưởng thuộc Lôi Tiên Điện.","detail":"Sau khi Xạ Thần xa hóa Lôi Thú khiến Thiên Quỳ Tử tin Vương Lâm là người Lôi Tiên Điện, lão lập tức đổi thái độ, tuyên bố Thiên gia không tham dự việc Huyễn gia và đưa túi trữ vật chứa Tiên ngọc cho Vương Lâm.","nguon":["@c0638"]},{"id":"vu-kiem-tien","name":"Vũ Kiếm tiên","cn":"","category":"phap-bao","categoryLabel":"Tiên kiếm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vũ Kiếm tiên là cự kiếm trong tay Vương Lâm, do Chu Dật phân ly và truyền thừa. Vương Lâm dùng nó để thi triển Trảm La Quyết khi công kích Huyễn gia đại trận.","detail":"Khi Huyễn gia đại trận bị Lôi Thú và Tiên vệ ép tới cực hạn, Vương Lâm vỗ túi trữ vật lấy ra Vũ Kiếm tiên. Kiếm này được nhắc là pháp bảo do Chu Dật tiền bối phân ly, truyền thừa cho Vương Lâm, và được dùng làm vật dẫn cho Trảm La Quyết.","nguon":["@c0639"]},{"id":"phuc-trach-ngoc-gian","name":"Phúc Trạch ngọc giản","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo / ngọc giản","phamCap":"Chí bảo Huyễn gia, chứa Tiên pháp","soHuu":["Huyễn gia","Huyễn Vô Tình"],"trangThai":"dang-co","blurb":"Chí bảo Huyễn gia do tổ tiên ở Lôi chi Tiên giới lưu lại. Khi Huyễn gia đại trận bị phá, Huyễn Vô Tình mời ngọc giản này ra để đối phó Vương Lâm.","detail":"Phúc Trạch ngọc giản từ trong Nhà Tổ Huyễn gia bay lên, tỏa lực lượng tường hòa và khiến không gian quanh Nhà Tổ như tách thành một thế giới riêng. Dưới pháp quyết của Huyễn Vô Tình, nó hóa thành bóng người phát ra tiên lực nồng đậm, áp chế linh lực trên khắp Thiên Huyễn Tinh và bước tới tấn công Vương Lâm.","nguon":["@c0640"]},{"id":"van-dinh-chi-tinh-cua-chu-dat","name":"Vấn Đỉnh chi tinh của Chu Dật","cn":"","aliases":[],"category":"khac","categoryLabel":"Căn nguyên nguyên khí","phamCap":"Liên quan Vấn Đỉnh","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Căn nguyên giúp nguyên khí của Vương Lâm nhiều hơn tu sĩ Vấn Đỉnh bình thường. Nó được nhắc khi chương giải thích cái giá thi triển Trảm La Quyết.","detail":"Trảm La Quyết cần nguyên khí thân thể và nguyên thần dung hợp chặt chẽ, gây hao tổn lớn cho người thi triển. Vấn Đỉnh chi tinh của Chu Dật khiến nguyên khí trong cơ thể Vương Lâm dồi dào hơn mức thông thường, nhờ đó giảm bớt rủi ro khi dùng kiếm thức này.","nguon":["@c0640"]},{"id":"di-bao-cua-to-tien-huyen-gia","name":"Di bảo của Tổ tiên Huyễn gia","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Tiên bảo mất tích","phamCap":"Tiên bảo","soHuu":["Huyễn gia","Huyễn Vô Tướng"],"trangThai":"mat-tich","blurb":"Tiên bảo do tổ tiên Huyễn gia để lại nhưng đã mất tích cùng Huyễn Vô Tướng nhiều ngàn năm trước. Việc di bảo không xuất hiện khiến Thiên Quỳ Tử và lão già Hứa gia đều chú ý.","detail":"Huyễn Vô Tình nghĩ tới việc di bảo tổ tiên đã mất tích cùng Huyễn Vô Tướng nên không thể dùng trong trận với Vương Lâm, đành mời Phúc Trạch ngọc giản. Thiên Quỳ Tử và lão già Hứa gia cũng nhận ra điểm bất thường khi Huyễn gia không sử dụng món Tiên bảo này.","nguon":["@c0640"]},{"id":"tien-nghich-khong-gian","name":"Tiên Nghịch không gian","cn":"","aliases":[],"category":"khac","categoryLabel":"Không gian đặc thù","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Không gian liên quan Vương Lâm, nơi có Oán Anh. Chương này Vương Lâm nhớ tới Oán Anh trong không gian ấy trước khi gọi con bài trong nguyên thần.","detail":"Khi đối diện bóng người do Phúc Trạch ngọc giản hóa thành, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian với cảm giác đau lòng. Sau đó hắn gọi một tồn tại trong nguyên thần và hứa sau trận sẽ thả tự do.","nguon":["@c0640"]},{"id":"vu-cau-mau-trang-nga","name":"Vụ cầu màu trắng ngà","cn":"","category":"khac","categoryLabel":"Vật tạo bởi tiên lực","phamCap":"Không rõ","soHuu":["hư ảnh Tiên nhân"],"trangThai":"da-dung","blurb":"Vụ cầu do hư ảnh Tiên nhân ngưng tụ trong lòng bàn tay sau khi rút linh khí toàn Thiên Huyễn Tinh. Nó là kết quả trực tiếp của Hoá Tiên Thuật trong trận đối đầu Tán Ma.","detail":"Hư ảnh Tiên nhân chuyển linh lực toàn tinh cầu thành tiên lực rồi ngưng tụ thành vụ cầu màu trắng ngà. Sự xuất hiện của vật này khiến Thiên Huyễn Tinh rơi vào trạng thái không còn chút linh lực nào, buộc Tán Ma dùng thủ đoạn rút tinh hồn để đối lại.","nguon":["@c0641"]},{"id":"tien-son-phap-bao","name":"Tiên sơn pháp bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên bảo","soHuu":["Tham Lang"],"trangThai":"không rõ","blurb":"Pháp bảo Tham Lang từng dùng ở Yêu Linh chi địa để rút Sơn hồn.","detail":"Khi chứng kiến Tán Ma thi triển Trừu hồn trên Thiên Huyễn Tinh, Vương Lâm nhớ lại Tham Lang từng dùng Tiên sơn pháp bảo rút Sơn hồn. So sánh này làm nổi bật quy mô khủng khiếp của việc Tán Ma rút tinh hồn cả tu chân tinh.","nguon":["@c0642"]},{"id":"tui-tru-vat-cua-lieu-mi","name":"Túi trữ vật của Liễu Mi","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Liễu Mi","Vương Lâm"],"trangThai":"Vương Lâm nhận được @c0643","blurb":"Túi trữ vật Liễu Mi để lại trước khi bị cắn nuốt ý cảnh. Nàng dặn nếu Huyễn Vô Tình không giết được Vương Lâm thì phải giao túi này cho hắn.","detail":"Sau biến cố Huyễn gia, Vương Lâm nhận túi trữ vật này theo giao ước mà Liễu Mi đã đặt ra. Bên trong chỉ có một viên đan dược và một khối ngọc giản.","nguon":["@c0643"]},{"id":"vien-dan-duoc-trong-tui-tru-vat","name":"Viên đan dược trong túi trữ vật","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"trong túi trữ vật Liễu Mi @c0643","blurb":"Viên đan dược là một trong hai vật nằm trong túi trữ vật Liễu Mi để lại cho Vương Lâm.","detail":"Chương 643 chỉ nêu trong túi trữ vật của Liễu Mi có một viên đan dược và một khối ngọc giản, chưa nói rõ công dụng của viên đan dược này.","nguon":["@c0643"]},{"id":"ngoc-gian-trong-tui-tru-vat","name":"Ngọc giản trong túi trữ vật","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"trong túi trữ vật Liễu Mi @c0643","blurb":"Khối ngọc giản là vật còn lại trong túi trữ vật Liễu Mi để lại. Nội dung của nó chưa được trình bày trong chương này.","detail":"Vương Lâm phát hiện túi trữ vật Liễu Mi để lại chỉ có một viên đan dược và một khối ngọc giản. Ngọc giản này gắn với di vật cuối cùng của Liễu Mi sau khi nàng tiêu tán.","nguon":["@c0643"]},{"id":"dan-duoc-do-lieu-mi-luu-lai","name":"Đan dược do Liễu Mi lưu lại","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Bình","Vương Lâm"],"trangThai":"đang dùng","blurb":"Đan dược do Liễu Mi lưu lại được dùng để giúp Vương Bình tiêu trừ oán khí. Nó phải phối hợp với thần thông Lôi hệ của Vương Lâm để duy trì quá trình trị liệu lâu dài.","detail":"Sau khi Vương Bình được xác nhận vốn là Oán Anh, số đan dược do Liễu Mi lưu lại trở thành thuốc điều trị cho đứa trẻ. Vương Lâm cho Vương Bình uống hằng ngày, rồi dùng thần thông Lôi hệ khu trừ hắc khí trong thân thể; nếu thiếu quá trình này, thân thể Vương Bình vẫn có nguy cơ trở lại trạng thái cũ.","nguon":["@c0644"]},{"id":"tro-cot-ton-thai","name":"Tro cốt Tôn Thái","cn":"","aliases":[],"category":"khac","categoryLabel":"Di vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"được Vương Lâm cất giữ","blurb":"Di vật còn lại sau khi Tôn Thái qua đời, được Vương Lâm đặt trong túi trữ vật theo lời hứa. Nó đánh dấu sự kết thúc của thời gian Tôn Thái ở bên hai cha con Vương Lâm.","detail":"Sau khi Tôn Thái chết, thi thể lão hóa thành một vò tro cốt. Vương Lâm giữ vò tro cốt ấy trong túi trữ vật, thực hiện lời hứa giữa hai người trước đó.","nguon":["@c0646"]},{"id":"phi-kiem-mau-xanh","name":"Phi kiếm màu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Người đàn ông trung niên cưỡi phi kiếm màu xanh"],"trangThai":"đang sử dụng @c0647","blurb":"Phi kiếm màu xanh dưới chân người đàn ông trung niên bay qua Kỳ Liên phong sau cơn dông. Ánh hàn quang của nó khiến Vương Bình lần đầu chứng kiến cảnh tượng tu sĩ phi hành.","detail":"Phi kiếm màu xanh là pháp bảo phi hành của tu sĩ trung niên xuất hiện trên Kỳ Liên phong. Người này cưỡi kiếm bay qua cầu vồng, nhìn thấy phụ tử Vương Lâm rồi tán thưởng phàm nhân có thể leo tới đỉnh núi trước khi rời đi.","nguon":["@c0647"]},{"id":"ngoc-gian-dua-tin","name":"Ngọc giản đưa tin","cn":"","aliases":["ngọc giản truyền tin"],"category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"Không rõ","soHuu":["Lão nhân cẩm y"],"trangThai":"đã bị bóp nát","blurb":"Vật phẩm truyền tin được lão nhân cẩm y sử dụng sau khi bị Vương Lâm trọng thương. Việc bóp nát ngọc giản báo hiệu khả năng truyền tin hoặc cầu viện bên ngoài.","detail":"Tại Tĩnh Nhã Hiên, sau khi kim đan nứt, lão nhân cẩm y lấy đan dược trong túi trữ vật nuốt vào rồi lập tức bóp nát ngọc giản đưa tin. Hành động này xảy ra ngay sau khi lão bị ánh mắt của Vương Lâm trọng thương vì ra tay với Vương Bình.","nguon":["@c0648"]},{"id":"phu-bai-vuong-phu","name":"Phủ bài Vương Phủ","cn":"","category":"khac","categoryLabel":"Biển phủ","phamCap":"Phàm vật","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Tấm biển mới treo trước đại viện ở thành bắc Kỳ Thủy. Vương Lâm tự tay đề hai chữ Vương Phủ lên đó.","detail":"Sau khi vào đại viện tại Kỳ Thủy thành, Vương Lâm cho tháo phủ bài cũ và thay bằng tấm biển do chính hắn đề hai chữ Vương Phủ. Đại viện từ đó mang danh Vương Phủ, nơi hắn và Vương Bình đối thoại về ba mươi năm phú quý.","nguon":["@c0650"]},{"id":"dai-dinh-mau-den","name":"Đại đỉnh màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"đang dùng","blurb":"Đại đỉnh màu đen là pháp bảo Tham Lang lấy ra khi cảm ứng được bảo vật trên tinh cầu quỷ dị ở La Thiên Bắc Vực.","detail":"Tham Lang nhận ra cảm giác bảo vật trên tinh cầu bị sương mù che phủ giống lần đoạt đại đỉnh năm xưa. Hắn lấy đại đỉnh màu đen từ túi trữ vật, để nó trôi nổi trước mặt rồi theo sau tiến vào màn sương quanh tinh cầu.","nguon":["@c0653"]},{"id":"loi-vong","name":"Lôi võng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"hong","blurb":"Võng lôi quang Lôi Đạo Tử dùng để vây khốn tiên vệ khôi lỗi trong trận chiến với Vương Lâm.","detail":"Lôi Đạo Tử lấy lôi võng từ túi trữ vật, hóa thành một chiếc võng lôi quang lớn với nhiều hoa văn phù chú, dùng để bao vây tiên vệ khôi lỗi. Khi thiết côn thu lôi không chịu nổi lôi lực của Vương Lâm và sụp đổ, lôi lực phát tiết khiến lôi võng tan rã, tiên vệ thoát ra.","nguon":["@c0656"]},{"id":"thiet-con-khac-phu","name":"Thiết côn khắc phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"hong","blurb":"Cây côn đen dài ba trượng dùng để thu lôi, có phù văn và dây đỏ sậm quấn quanh.","detail":"Trong lúc đối đầu lôi cầu của Vương Lâm, Lôi Đạo Tử lấy ra thiết côn khắc phù, cắm xuống đất và phối hợp pháp quyết thu lôi để dẫn lôi lực vào pháp bảo. Lôi cầu của Vương Lâm quá mạnh khiến thiết côn rạn nứt, nổ tung rồi sụp đổ trước mặt Lôi Đạo Tử.","nguon":["@c0656"]},{"id":"loi-thu-loi-tien-dien","name":"Lôi thú Lôi Tiên Điện","cn":"","category":"khac","categoryLabel":"Tiên thú / lôi thú","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử","Lôi Tiên Điện"],"trangThai":"đang giao chiến","blurb":"Lôi thú do Lôi Đạo Tử triệu ra bằng Lôi chi tiên thú. Nó không có lôi giác, huyết thống không thuần nhưng vẫn lao vào tử đấu với Ngân Giác lôi thú.","detail":"Lôi thú Lôi Tiên Điện được ngưng tụ từ lôi quang trên không trung, hóa ra sau khi Lôi Đạo Tử thi triển Lôi chi tiên thú. Khi đối mặt Ngân Giác lôi thú của Vương Lâm, nó bị huyết thống áp chế nhưng vì tôn nghiêm linh hồn vẫn gầm lên lao vào chém giết.","nguon":["@c0657"]},{"id":"phi-kiem-mau-bac","name":"Phi kiếm màu bạc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / lôi kiếm","phamCap":"Không rõ","soHuu":["Lôi Đạo Tử"],"trangThai":"đang sử dụng","blurb":"Phi kiếm do điện quang của Lôi Đạo Tử ngưng hình. Nó được dùng để đánh về phía tiên vệ khôi lỗi trong trận với Vương Lâm.","detail":"Trong lúc sinh tham niệm muốn đoạt Ngân Giác lôi thú, Lôi Đạo Tử vung tay khiến điện quang hóa thành phi kiếm màu bạc, trực chỉ tiên vệ khôi lỗi. Đây là một phần thế công của hắn trước khi thi triển Lôi tiên kiếp.","nguon":["@c0657"]},{"id":"dai-kiem","name":"Đại kiếm","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Thanh đại kiếm được Vương Lâm lấy ra ở cuối chương. Hắn dùng nó để chuẩn bị đối mặt nguyên lực thần thông của Lôi Đạo Tử.","detail":"Sau khi Lôi Đạo Tử uy hiếp dùng nguyên lực pháp thuật bước thứ hai, Vương Lâm lấy đại kiếm, mũi kiếm nghiêng xuống, không lùi bước. Khi đối phương chạm tới nỗi đau Vương Bình, hắn nâng kiếm trong sát ý đỏ mắt.","nguon":["@c0657"]},{"id":"hai-dao-kim-sac-kiem-khi-tao-thanh-vuong-binh","name":"Hai đạo kim sắc kiếm khí tạo thành Vương Bình","cn":"","category":"khac","categoryLabel":"Kiếm khí","phamCap":"không rõ","soHuu":["Vương Bình","Vương Lâm"],"trangThai":"tan-di","blurb":"Hai đạo kiếm khí là bản chất thân thể và lớp thủ hộ oan hồn của Vương Bình. Chúng duy trì sự tồn tại của hắn trong hơn bảy mươi năm phàm tục.","detail":"Chương xác nhận một đạo kim sắc kiếm khí hóa thành thân thể Vương Bình, một đạo khác thủ hộ oan hồn. Khi Vương Bình từ biệt cha và Thanh Nghi, thân thể hắn hóa về kiếm khí, chỉ còn dải sáng trắng mang tia oán khí cuối cùng.","nguon":["@c0659"]},{"id":"dan-duoc-cuu-vuong-binh-nam-xua","name":"Đan dược cứu Vương Bình năm xưa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Lâm","Vương Bình"],"trangThai":"da-dung","blurb":"Đan dược Vương Lâm từng cho Vương Bình ăn khi nhận đứa trẻ từ Liễu Mi. Do bản chất Vương Bình chỉ là hồn phách và kiếm khí, thân thể không thể hấp thu như người thường.","detail":"Trong hồi tưởng chân tướng, Vương Bình nhớ thời thơ ấu uống thuốc đắng, còn Vương Lâm từng dùng đan dược và lôi hệ thần thông để xử lý oán khí. Đan dược không thể giải quyết tận gốc vì thân thể Vương Bình vốn không phải thân xác sinh trưởng bình thường.","nguon":["@c0659"]},{"id":"bay-thanh-bao-kiem","name":"Bảy thanh bảo kiếm","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bảy thanh phi kiếm Vương Lâm dùng để bố trí Thất Tinh kiếm trận.","detail":"Trong sát cục vây Lôi Đạo Tử, Vương Lâm phóng bảy thanh bảo kiếm ra, tạo thành Thất Tinh kiếm trận xoay quanh đối phương và liên tục công kích lôi mạc phòng ngự.","nguon":["@c0660"]},{"id":"hon-thu-tu","name":"Hồn thứ tư","cn":"","category":"khac","categoryLabel":"Chủ hồn","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chủ hồn trở về Tôn Hồn Phiên, góp phần tăng mạnh uy lực hồn phiên.","detail":"Sau khi hồn thứ tư quay về, Tôn Hồn Phiên tuy chưa đủ mười ức hồn thường nhưng uy lực tăng mạnh vì có nhiều hồn phách đại thần thông, giúp ba chung cực chủ hồn hiện ra trong trận vây Lôi Đạo Tử.","nguon":["@c0660"]},{"id":"ngoc-gian-loi-quang","name":"Ngọc giản lôi quang","cn":"","category":"khac","categoryLabel":"Vật phẩm phòng ngự","phamCap":"","soHuu":["Lôi Đạo Tử"],"trangThai":"da-dung","blurb":"Vật phẩm Lôi Đạo Tử bóp nát để tạo lôi mạc bảo vệ thân thể.","detail":"Khi bị Thất Tinh kiếm trận và nhiều thế công vây ép, Lôi Đạo Tử bóp nát ngọc giản lôi quang. Vật này hóa thành màn lôi bao quanh hắn, tạm thời chống đỡ công kích.","nguon":["@c0660"]},{"id":"ba-chung-cuc-chu-hon","name":"Ba chung cực chủ hồn","cn":"","category":"khac","categoryLabel":"Hồn phách chiến lực","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm","blurb":"Ba chủ hồn của Vương Lâm tham gia uy hiếp nguyên thần Lôi Đạo Tử trong động phủ.","detail":"Ba chung cực chủ hồn phát tiếng hô khóc trong động phủ, phối hợp tiên vệ khôi lỗi, lôi thú, Thất Tinh kiếm trận và cấm chế điện quang để bao vây, tạo áp lực khiến Lôi Đạo Tử khó phản kháng.","nguon":["@c0661"]},{"id":"khoang-thach-kim-loai","name":"Khoáng thạch kim loại","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã luyện hóa","blurb":"Vật liệu kim loại trong lòng tinh cầu bỏ hoang, bị Hoàng Tuyền lực hút ra để luyện khôi lỗi.","detail":"Vương Lâm dùng Hoàng Tuyền lực bao phủ tinh cầu bỏ hoang, hút khoáng thạch kim loại từ lòng đất rồi để chúng hòa tan trong hoàng tuyền, làm nguyên liệu tạo dịch cầu màu vàng.","nguon":["@c0661"]},{"id":"dich-cau-mau-vang","name":"Dịch cầu màu vàng","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu luyện khôi lỗi","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã dùng một phần","blurb":"Ba dịch cầu luyện từ khoáng thạch kim loại, dùng để nâng cấp thân thể khôi lỗi Lôi Đạo Tử.","detail":"Sau khi luyện hóa khoáng thạch kim loại bằng Hoàng Tuyền lực, Vương Lâm thu được ba dịch cầu màu vàng to bằng nắm tay. Hắn đặt một dịch cầu vào mi tâm thân thể Lôi Đạo Tử, khiến thân thể khôi lỗi đạt tới ngân cấp.","nguon":["@c0661"]},{"id":"cai-dinh-lon-cua-tham-lang","name":"Cái đỉnh lớn của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hoặc vật phẩm","phamCap":"không rõ","soHuu":["Tham Lang"],"trangThai":"đang thuộc Tham Lang","blurb":"Cái đỉnh lớn xuất hiện cùng Tham Lang trong lần hắn cố thoát khỏi Vân Hà tinh.","detail":"Khi Tham Lang chật vật lao ra khỏi sương mù Vân Hà tinh, trước mặt hắn có một cái đỉnh lớn cùng lao ra. Công năng và lai lịch của vật này chưa được nói rõ trong chương.","nguon":["@c0661"]},{"id":"tien-ve-thu-hai","name":"Tiên vệ thứ hai","cn":"","category":"phap-bao","categoryLabel":"Khôi lỗi bán thành phẩm","phamCap":"Thân thể ngân cực đỉnh phong","soHuu":["Vương Lâm"],"trangThai":"bán thành phẩm","blurb":"Khôi lỗi được Vương Lâm tế luyện từ Lôi Đạo Tử phối hợp đầu lôi thú nhưng thất bại ở bước cuối. Thành phẩm chỉ còn thân thể ngân cực đỉnh phong, chưa thể chiến đấu tự nhiên.","detail":"Vương Lâm kịp chém đứt liên hệ nguyên thần Lôi Đạo Tử và giữ lại thân thể khôi lỗi. Với thần thức hiện tại, hắn chỉ khiến tiên vệ thứ hai làm vài động tác đơn giản nên chưa thích hợp đưa vào thực chiến.","nguon":["@c0662"]},{"id":"ngoc-gian-khac-loi-thu","name":"Ngọc giản khắc lôi thú","cn":"","category":"phap-bao","categoryLabel":"Ngọc giản","phamCap":"Di vật Lôi Tiên Điện","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản trong túi trữ vật Lôi Đạo Tử, mặt trước khắc lôi thú kim giác và mặt sau có ký hiệu lớn. Bên trong ghi Đỉnh Hóa Thiên Địa cùng Lôi Nguyên Thuật.","detail":"Ngọc giản có lôi quang ngăn thần thức, mang một tia thiên địa lôi uy. Vương Lâm phá được trở ngại này nhờ lôi uy Thái Cổ trong nguyên thần và thu được hai thần thông lôi hệ quan trọng.","nguon":["@c0662"]},{"id":"loi-kiem-khong-ban-the","name":"Lôi kiếm không bản thể","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo lôi hệ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Thanh kiếm hoàn toàn do tia chớp tạo thành, không có bản thể vật chất. Đây là pháp bảo từng được Lôi Đạo Tử dùng để giằng co với tiên vệ.","detail":"Khi kiểm kê di vật Lôi Đạo Tử, Vương Lâm nhận ra lôi kiếm này là vật từng đối kháng song quyền tiên vệ. Sau khi quan sát, hắn cất nó vào túi trữ vật.","nguon":["@c0662"]},{"id":"khoang-thach-bac-chua-loi-dien-luc","name":"Khoáng thạch bạc chứa lôi điện lực","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng thạch","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Hòn đá bạc to bằng nắm tay, chứa lôi điện lực. Khi Vương Lâm chạm vào, lôi đình nhập thể và bị nguyên thần nuốt lấy, để lại một chút nguyên lực thiên địa.","detail":"Khoáng thạch khiến Vương Lâm hứng thú vì có thể liên quan đến việc sinh ra nguyên lực thiên địa qua lôi đình nhập thể. Hắn không hấp thu hết ngay mà tạm thời cất đi.","nguon":["@c0662"]},{"id":"tui-tru-vat-cua-loi-dao-tu","name":"Túi trữ vật của Lôi Đạo Tử","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Túi trữ vật của Lôi Đạo Tử mất lạc ấn thần thức sau khi nguyên thần chủ nhân tiêu tán. Vương Lâm mở túi và kiểm kê bốn vật đáng chú ý.","detail":"Trong túi có ngọc giản khắc lôi thú, lôi kiếm không bản thể, khoáng thạch bạc chứa lôi điện lực và tiên ngọc. Việc túi trở thành vô chủ giúp Vương Lâm thu được Lôi Nguyên Thuật cùng nhiều vật lôi hệ.","nguon":["@c0662"]},{"id":"hai-dao-kiem-khi-lang-thien-hau","name":"Hai đạo kiếm khí Lăng Thiên Hậu","cn":"","category":"phap-bao","categoryLabel":"Kiếm khí","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Hai đạo kiếm khí của Lăng Thiên Hậu được Vương Lâm giữ trong động phủ. Khi hắn chuẩn bị tu luyện, kiếm khí dung nhập vào tiên vệ khôi lỗi để hộ pháp.","detail":"Kiếm khí lơ lửng trong động phủ của Vương Lâm trên tinh cầu bỏ hoang. Chúng được dùng cùng tiên vệ khôi lỗi đứng trước động phủ, bảo vệ Vương Lâm trong lúc nghiên cứu di vật và chuẩn bị nâng tu vi.","nguon":["@c0662"]},{"id":"ngoc-gian-huyet-sac","name":"Ngọc giản huyết sắc","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tống","phamCap":"Không rõ","soHuu":["Tử Tâm"],"trangThai":"đã kích hoạt","blurb":"Ngọc giản huyết sắc là vật Huyết Tổ tặng Tử Tâm để bảo mạng. Nó có thể truyền tống một lần từ bất kỳ nơi nào về Huyết Tinh nhưng cần thời gian mở ra.","detail":"Khi tinh cầu hoang dã sụp đổ và sóng gợn lan tới, Tử Tâm lấy ngọc giản huyết sắc ra để chuẩn bị truyền tống về Huyết Tinh. Hai huyết nô tự bạo nguyên thần nhằm tranh thủ thời gian cho nàng kích hoạt vật này.","nguon":["@c0663"]},{"id":"thiet-kiem-ri-set","name":"Thiết kiếm rỉ sét","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thác Sâm"],"trangThai":"đang ở bên Thác Sâm","blurb":"Thiết kiếm rỉ sét cắm bên cạnh Thác Sâm trên cột đá trong Huyết Hải. Thân kiếm loang lổ rỉ sét và có vết máu nâu khô.","detail":"Trong Cổ Thần Chi Địa, Thác Sâm ngồi trên cột đá lớn nhất giữa Huyết Hải, bên cạnh là một thanh thiết kiếm rỉ sét. Vật này xuất hiện cùng cảnh hắn khắc tên Vương Lâm và tuyên bố sắp thoát khốn.","nguon":["@c0663"]},{"id":"tui-tru-vat-vuong-lam-luu-lai-cho-chu-nhu","name":"Túi trữ vật Vương Lâm lưu lại cho Chu Như","cn":"","category":"khac","categoryLabel":"Vật phẩm phong ấn ký ức","phamCap":"Không rõ","soHuu":["Chu Như"],"trangThai":"đã mở","blurb":"Túi trữ vật cổ xưa do Vương Lâm lưu lại cho Chu Như nhiều năm trước. Bên trong không có tài vật, chỉ có bạch quang nhập vào mi tâm nàng để giải khai ký ức phong ấn.","detail":"Trên đỉnh Chu Tước Sơn, Chu Như mở túi trữ vật đã trải qua mấy trăm năm. Bạch quang từ trong túi bay vào mi tâm, khiến ký ức bị phong ấn trong đầu nàng chậm rãi cởi bỏ và làm nàng hiểu Vương Lâm không muốn mình đi tìm hắn.","nguon":["@c0663"]},{"id":"bach-quang-trong-tui-tru-vat","name":"Bạch quang trong túi trữ vật","cn":"","category":"khac","categoryLabel":"Phong ấn ký ức","phamCap":"Không rõ","soHuu":["Chu Như"],"trangThai":"đã dung nhập mi tâm Chu Như","blurb":"Bạch quang là thứ duy nhất trong túi trữ vật Vương Lâm để lại cho Chu Như. Nó nhập vào mi tâm nàng và giải khai ký ức bị phong ấn.","detail":"Khi Chu Như mở túi trữ vật trên đỉnh Chu Tước Sơn, bạch quang lập tức bay ra, tiến vào mi tâm nàng. Sau đó ký ức bị phong ấn trong đầu Chu Như chậm rãi được cởi bỏ, kéo theo đoạn ký ức liên quan tới Uyển nhi và Vương Lâm.","nguon":["@c0663"]},{"id":"co-than-khi","name":"Cổ Thần Khí","cn":"","category":"khac","categoryLabel":"Vật liên quan Cổ Thần","phamCap":"không rõ","soHuu":[],"trangThai":"chưa rõ","blurb":"Vật mà Vương Lâm cho rằng bản tôn cần để trưởng thành.","detail":"Vương Lâm nghĩ bản tôn đã tới tứ tinh nhưng thiếu Cổ Thần Khí, rồi liên hệ tới Vọng Nguyệt trên Vân Hà tinh vì Vọng Nguyệt là ký sinh thể của Cổ Thần, có thể còn sót lại loại vật này.","nguon":["@c0664"]},{"id":"than-dieu-dau-tinh","name":"Thần điêu đầu tinh","cn":"","category":"khac","categoryLabel":"Dị thú dò tìm","phamCap":"không rõ","soHuu":["Sứ giả Tu Chân Liên Minh"],"trangThai":"được nhắc lại","blurb":"Dị thú từng đi cùng sứ giả Tu Chân Liên Minh và nhạy với Cổ Thần Khí.","detail":"Vương Lâm nhớ tới con thần điêu đầu tinh mà sứ giả Tu Chân Liên Minh từng mang theo ở Thiên Vận Tinh. Nó được nhắc vì có khả năng cảm ứng Cổ Thần Khí.","nguon":["@c0664"]},{"id":"loi-tien-lenh-bai","name":"Lôi Tiên lệnh bài","aliases":["ngọc giản của Lôi Đạo Tử"],"category":"phap-bao","categoryLabel":"Tín vật","phamCap":"Sứ giả Lôi Tiên Điện","soHuu":["Vương Lâm","Lôi Đạo Tử"],"trangThai":"Vương Lâm đang giữ","blurb":"Tín vật của Lôi Đạo Tử được Vương Lâm dùng để chứng minh thân phận Sứ giả Lôi Tiên Điện trước Thiên gia.","detail":"Khi được lấy ra, vật này phát lôi quang và lôi uy, phù hợp ký ức của Thiên Quỳ Tử về lệnh bài sứ giả nên khiến hắn không còn nghi ngờ thân phận của Vương Lâm.","nguon":["@c0665"]},{"id":"thien-nghich-chau","name":"Thiên Nghịch Châu","aliases":["Hạt châu Thiên Nghịch","Thiên Nghịch","Thiên Nghịch châu","Bạch Châu"],"category":"phap-bao","categoryLabel":"Hạt châu","phamCap":"trọng bảo","soHuu":["Vương Lâm"],"trangThai":"chưa nhận chủ hoàn toàn","blurb":"Thiên Nghịch Châu bảo vệ phần ý thức cốt lõi của Vương Lâm trong lúc thân thể hắn bị lôi đình bản nguyên chân thân nhập vào. (+) Pháp bảo trục của Vương Lâm, đang cần viên mãn thuộc tính kim loại. [CAN-SOAT-GOP]","detail":"Mục tiêu chuyến vào Vân Hà Tinh là hấp thu tính kim loại từ xương Vọng Nguyệt để giúp Thiên Nghịch Châu viên mãn và có khả năng nhận chủ.","nguon":["@c0666","@c1798","@c1812"],"tabs":{}},{"id":"kim-viem-quang-mach","name":"Kim Viêm quáng mạch","aliases":["Kim Viêm thạch"],"category":"nguyen-lieu","categoryLabel":"Khoáng mạch","phamCap":"xương Vọng Nguyệt","soHuu":[],"trangThai":"nằm trong thân thể Vọng Nguyệt","blurb":"Khoáng mạch kim tính trong xương Vọng Nguyệt, mục tiêu Vương Lâm muốn hấp thu cho Thiên Nghịch Châu.","detail":"Vương Lâm tìm tới Kim Viêm quáng mạch nhưng tạm dừng hấp thu vì phát hiện tiên lực bất thường, nghi có tu sĩ khác còn ẩn trong thân thể Vọng Nguyệt.","nguon":["@c0666"]},{"id":"son-thach-cua-tham-lang","name":"Sơn thạch của Tham Lang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo sơn thạch","phamCap":"chưa rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm thu được một phần","blurb":"Khối sơn thạch cực lớn từng được Tham Lang dùng ở vùng đất Yêu Linh, nay mắc trong khe xương Vọng Nguyệt.","detail":"Sơn thạch đã bị Kim Viêm quáng mạch đồng hóa nên cực khó lấy nguyên vẹn; Vương Lâm dùng kiếm khí của Lăng Thiên Hậu cắt tránh phần dính với xương rồi thu phần tách được vào túi trữ vật.","nguon":["@c0667"]},{"id":"nguyet-hoa","name":"Nguyệt Hoa","cn":"","category":"nguyen-lieu","categoryLabel":"Trọng bảo trong cơ thể Vọng Nguyệt","phamCap":"cực độc","soHuu":["Vọng Nguyệt"],"trangThai":"nằm trong cơ thể Vọng Nguyệt","blurb":"Vật trong cơ thể Vọng Nguyệt, chứa kịch độc và lực lượng nguy hiểm.","detail":"Theo ký ức Cổ Thần Đồ Ti, Nguyệt Hoa có kịch độc mà chỉ máu Cổ Thần có thể giải; nếu bị uy hiếp hoặc lấy ra có thể khiến Vọng Nguyệt tự bạo, với con khổng lồ này phạm vi ảnh hưởng có thể rất rộng.","nguon":["@c0667"]},{"id":"cu-dinh","name":"Cự Đỉnh","aliases":["Đại đỉnh thần bí của Tham Lang","Cự Đỉnh của Tham Lang"],"category":"phap-bao","categoryLabel":"Đại đỉnh","phamCap":"thần bí","soHuu":["Tham Lang"],"trangThai":"bị xúc tu quấn","blurb":"Đại đỉnh thần bí giúp Tham Lang giữ mạng trong nơi bài tiết của Vọng Nguyệt gần trăm năm.","detail":"Pháp bảo này từng chống lại lực hút nơi bài tiết, nhưng về sau bị xúc tu quấn quanh và thần thông như bị hấp thu mất tác dụng, khiến Tham Lang không thể thoát.","nguon":["@c0668"]},{"id":"xuong-song-cua-vong-nguyet","name":"Xương sống của Vọng Nguyệt","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu hung thú","phamCap":"thân thể Vọng Nguyệt","soHuu":["Vương Lâm"],"trangThai":"đang bị kéo khỏi Vọng Nguyệt","blurb":"Hai nửa xương sống khổng lồ của Vọng Nguyệt được Vương Lâm và Tiên Vệ rút khỏi lòng đất Vân Hà Tinh.","detail":"Mỗi nửa xương kéo dài vô số dặm, lớn như dãy núi và không thể thu vào túi trữ vật, khiến Vương Lâm phải kéo trực tiếp trong lúc Vọng Nguyệt thức tỉnh và xúc tu truy cản.","nguon":["@c0669"]},{"id":"tu-thu-kiem","name":"Tử Thử kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Trong chương 670, nó được Vương Lâm ra lệnh tự bạo đầu tiên trong khe nứt của Vọng Nguyệt.","detail":"Tử Thử kiếm là kiếm thể thuộc Thất Tinh Kiếm Trận. Khi bị Vọng Nguyệt truy sát, Vương Lâm gọi kiếm trận trở về rồi cho Tử Thử kiếm tự bạo trước, tạo lực nổ bên trong cơ thể Vọng Nguyệt để đổi lấy một nhịp thoát thân.","nguon":["@c0670"]},{"id":"hoi-tru-kiem","name":"Hợi Trư kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng các kiếm còn lại tự bạo sau Tử Thử kiếm để tạo lực hủy diệt bên trong cơ thể Vọng Nguyệt.","detail":"Hợi Trư kiếm thuộc Thất Tinh Kiếm Trận. Sau khi Tử Thử kiếm tự bạo, Vương Lâm ra lệnh cho Hợi Trư kiếm cùng các kiếm còn lại và tà hồn đồng loạt tự bạo, khiến Vọng Nguyệt khựng lại trong khoảnh khắc.","nguon":["@c0670"]},{"id":"vi-duong-kiem","name":"Vị Dương kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó được dùng trong lần tự bạo toàn bộ kiếm trận để cản Vọng Nguyệt.","detail":"Vị Dương kiếm là một trong sáu kiếm được Vương Lâm cho tự bạo sau Tử Thử kiếm. Lực tự bạo phối hợp với tà hồn không đủ làm Vọng Nguyệt bị thương nặng, nhưng đủ khiến nó chậm lại đúng lúc.","nguon":["@c0670"]},{"id":"than-hau-kiem","name":"Thân Hầu kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng các kiếm còn lại tự bạo trong khe nứt của Vọng Nguyệt.","detail":"Thân Hầu kiếm thuộc Thất Tinh Kiếm Trận. Trong lúc truy đuổi sinh tử, Vương Lâm hy sinh cả kiếm trận, để Thân Hầu kiếm cùng những kiếm còn lại nổ tung nhằm tranh thủ thời cơ thoát khỏi Vọng Nguyệt.","nguon":["@c0670"]},{"id":"suu-nguu-kiem","name":"Sửu Ngưu kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó bị Vương Lâm cho tự bạo trong cuộc thoát khỏi Vọng Nguyệt.","detail":"Sửu Ngưu kiếm là kiếm thể thuộc Thất Tinh Kiếm Trận. Nó cùng Hợi Trư kiếm, Vị Dương kiếm, Thân Hầu kiếm, Dần Hổ kiếm và Mão Thỏ kiếm tự bạo sau Tử Thử kiếm, tạo một đợt chấn động trong cơ thể Vọng Nguyệt.","nguon":["@c0670"]},{"id":"dan-ho-kiem","name":"Dần Hổ kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó là một phần của lần tự hủy kiếm trận để ngăn Vọng Nguyệt trong thoáng chốc.","detail":"Dần Hổ kiếm thuộc nhóm kiếm của Thất Tinh Kiếm Trận. Vương Lâm không còn cách khác nên ra lệnh cho nó cùng các kiếm còn lại tự bạo, lấy lực hủy diệt đổi lấy một khoảnh khắc để bỏ chạy.","nguon":["@c0670"]},{"id":"mao-tho-kiem","name":"Mão Thỏ kiếm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thành phần Thất Tinh Kiếm Trận","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Một thanh kiếm trong Thất Tinh Kiếm Trận. Nó cùng toàn bộ kiếm trận bị hy sinh trong lúc Vương Lâm thoát khỏi Vọng Nguyệt.","detail":"Mão Thỏ kiếm là một kiếm thể của Thất Tinh Kiếm Trận. Trong chương 670, nó cùng các kiếm khác và tà hồn tự bạo trong khe nứt, khiến Vọng Nguyệt chậm lại trong một nhịp ngắn.","nguon":["@c0670"]},{"id":"ta-hon-tren-that-tinh-kiem-tran","name":"Tà hồn trên Thất Tinh Kiếm Trận","cn":"","category":"khac","categoryLabel":"Hồn thể","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Tà hồn bám trên Thất Tinh Kiếm Trận, cùng kiếm thể tự bạo trong cuộc đào thoát khỏi Vọng Nguyệt.","detail":"Khi Vương Lâm ra lệnh cho Thất Tinh Kiếm Trận tự bạo, các tà hồn trên kiếm trận cũng vỡ nát, hóa thành lực lượng hủy diệt phối hợp với kiếm thể đánh vào cơ thể Vọng Nguyệt để đổi lấy khoảnh khắc trì hoãn.","nguon":["@c0671"]},{"id":"khoi-loi-tien-ve","name":"Khôi lỗi Tiên Vệ","cn":"","aliases":["Tiên Vệ","Con rối tiên vệ"],"category":"phap-bao","categoryLabel":"Con rối","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"hư tổn","blurb":"Con rối của Vương Lâm, tham gia khiêng xương Vọng Nguyệt chạy khỏi Vân Hà Tinh.","detail":"Tiên Vệ cùng Vương Lâm khiêng nửa xương Vọng Nguyệt lao ra tinh không, triển khai tốc độ đến cực hạn. Khi Vọng Nguyệt gầm rống, kim quang trên người Tiên Vệ sụp đổ và linh tính trong mắt trở nên ảm đạm.","nguon":["@c0672"]},{"id":"tien-tuu","name":"Tiên tửu","cn":"","aliases":[],"category":"khac","categoryLabel":"Tiên vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã dùng hết","blurb":"Rượu tiên còn lại hai giọt, được Vương Lâm dùng để bùng phát tiên lực.","detail":"Trong lúc bị đàn Vọng Nguyệt nhỏ truy sát, Vương Lâm uống hết hai giọt tiên tửu còn lại. Tiên lực trong cơ thể hắn bùng nổ, giúp thi triển Định Thân Thuật ở quy mô vượt mức bình thường.","nguon":["@c0672"]},{"id":"binh-phong-son-ha-do","name":"Bình phong Sơn Hà Đồ","cn":"","aliases":["Sơn Hà Đồ","bình phong có dấu ấn Sơn Hà Đồ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tham Lang"],"trangThai":"bị phá vỡ","blurb":"Bình phong mang dấu ấn Sơn Hà Đồ được Tham Lang dùng để chống một chỉ Cổ Thần.","detail":"Khi xúc tu của Vọng Nguyệt đuổi tới, Tham Lang lấy ra bình phong có dấu ấn Sơn Hà Đồ, khiến tinh không như biến mất và khí thế sơn hà hiện ra. Bình phong bị một chỉ Cổ Thần ép nứt rồi phá vỡ, khiến Tham Lang trọng thương.","nguon":["@c0672"]},{"id":"ton-tien-de-quan","name":"Tôn Tiên Đế Quan","cn":"","aliases":["vương miện"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Tham Lang","Vương Lâm"],"trangThai":"Vương Lâm thu được @c0673","blurb":"Vương miện kim quang có năm hạt châu ngũ hành, do Tham Lang dùng để chống Cổ Thần Chỉ. Sau khi Tham Lang bị đánh bay, pháp bảo vẫn nguyên vẹn và bị Vương Lâm thu lấy.","detail":"Tôn Tiên Đế Quan là vương miện Tham Lang lấy ra trong lúc nguy cấp, trên đó có năm hạt châu kim, mộc, thủy, hỏa, thổ và chứa chín nghìn chín trăm chín mươi chín linh hồn đế vương phàm nhân để luyện thành. Nó giúp Tham Lang chịu một chỉ Cổ Thần, nhưng linh hồn bên trong tan hết; vương miện không nứt, rơi vào tinh không rồi bị Vương Lâm dùng thần thức thu lấy.","nguon":["@c0673"]},{"id":"nam-hat-chau-ngu-hanh","name":"Năm hạt châu kim mộc thủy hỏa thổ","cn":"","aliases":["năm hạt châu ngũ hành"],"category":"khac","categoryLabel":"Bộ phận pháp bảo","phamCap":"không rõ","soHuu":["Tôn Tiên Đế Quan"],"trangThai":"gắn trên Tôn Tiên Đế Quan @c0673","blurb":"Năm hạt châu lớn gắn trên Tôn Tiên Đế Quan. Khi Tham Lang đội vương miện, chúng phát ra năm vầng sáng ngũ hành.","detail":"Năm hạt châu đại diện kim, mộc, thủy, hỏa, thổ là bộ phận nổi bật trên Tôn Tiên Đế Quan, cùng kim quang của vương miện bao bọc Tham Lang khi hắn chống Cổ Thần Chỉ.","nguon":["@c0673"]},{"id":"lac-an-cua-thien-van-tu","name":"Lạc ấn của Thiên Vận Tử","cn":"","category":"khac","categoryLabel":"Ấn ký","phamCap":"","soHuu":["Tham Lang","Thiên Vận Tử"],"trangThai":"Còn tồn tại trong cơ thể Tham Lang","blurb":"Ấn ký do Thiên Vận Tử để lại trong cơ thể Tham Lang, là lạc ấn duy nhất còn sót lại sau biến cố một chỉ Cổ Thần.","detail":"Sau khi Tham Lang bị trọng thương và rơi xuống tinh cầu nguyên thủy ở La Thiên Bắc Vực, phần lớn lạc ấn cường giả trong cơ thể hắn đã bị một chỉ Cổ Thần phá tan. Đạo lạc ấn của Thiên Vận Tử là lạc ấn duy nhất còn tồn tại, tiếp tục là dấu vết khống chế gắn với Tham Lang trong giai đoạn hắn chìm xuống lòng đất để khôi phục.","nguon":["@c0674"]},{"id":"de-tu-hon","name":"Đệ Tứ Hồn","cn":"","category":"khac","categoryLabel":"Chủ hồn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại","blurb":"Một chủ hồn được Vương Lâm phái rời khỏi tinh cầu để cảnh giới từ xa. Nó mở rộng phạm vi thần thức phòng hộ trong lúc Thiên Nghịch hấp thu Kim Viên Quáng.","detail":"Vì Thiên Nghịch quá trọng yếu và từng xuất hiện tại La Thiên Tinh Vực, Vương Lâm không chỉ dùng Tôn Hồn Phiên hộ pháp gần người mà còn sai Đệ Tứ Hồn bay ra ngoài tinh cầu ẩn nấp, mượn đó mở rộng thần thức để đề phòng biến động.","nguon":["@c0675"]},{"id":"nui-da-tien-gioi","name":"Núi đá tiên giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / vật liệu tiên giới","phamCap":"Không rõ","soHuu":["Vương Lâm","Tham Lang"],"trangThai":"bị hư hại","blurb":"Bảo vật của Tham Lang bị Vương Lâm đoạt, bên trong còn tiên khí dày đặc dù đã hư hại. Nó giúp Vương Lâm cảm ngộ thần thông rút hồn linh vật.","detail":"Thần thức Tham Lang trong núi đá đã tiêu tán, bản thể cũng bị tổn hại nên Sơn Hồn rút ra không ổn định. Dù vậy, tiên khí trong núi đá vẫn rất mạnh và mở ra cho Vương Lâm hướng cảm ngộ trước loại thần thông rút linh hồn của Đệ Nhị Bộ.","nguon":["@c0675"]},{"id":"son-ha-thien-dao-do","name":"Sơn Hà Thiên Đạo Đồ","aliases":["Thiên Đạo Đồ"],"cn":"","category":"phap-bao","categoryLabel":"Tiên bảo nguyên bản","phamCap":"Tiên giới thượng phẩm tiên bảo xếp thứ năm","soHuu":[],"trangThai":"không rõ","blurb":"Tiên bảo thượng phẩm xếp thứ năm trong mười tiên bảo thượng phẩm của Tiên giới. Bản bình phong trong tay Tham Lang chỉ là bản in lại không hoàn chỉnh.","detail":"Sơn Hà Thiên Đạo Đồ được giới thiệu qua nguồn gốc của bình phong Sơn Hà Đồ. Truyền thuyết nói chỗ lợi hại chân chính của nó nằm ở nét vẽ Sơn Hà bằng máu, thậm chí tên Thiên Đạo Đồ phát sinh từ truyền thuyết máu vẽ tranh là máu của Thiên Đạo.","nguon":["@c0675"]},{"id":"doa-hong-mau-lam-cua-hong-diep","name":"Đóa hồng màu lam của Hồng Điệp","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm","Hồng Điệp"],"trangThai":"đã dung nhập Vương Miện","blurb":"Bông hồng tỏa lam quang và hàn khí kiêu ngạo, có liên hệ với Hồng Điệp. Khi đặt lên Vương Miện, nó tan thành lam quang dung nhập vào pháp bảo.","detail":"Vương Lâm nhớ tới Hồng Điệp và Ngũ Hành Linh Thể giả khi nghiên cứu năm hạt châu ngũ hành trên Vương Miện. Hắn lấy đóa hồng lam ra thử, khiến năm hạt châu phát sáng; đóa hồng tiêu tán thành điểm sáng màu lam nhập vào Vương Miện, để lại linh khí cùng bóng người múa kiếm mơ hồ.","nguon":["@c0675"]},{"id":"kim-vien-quang","name":"Kim Viên Quáng","cn":"","category":"nguyen-lieu","categoryLabel":"Khoáng vật thuộc tính kim","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã bị Thiên Nghịch hấp thu","blurb":"Khoáng vật thuộc tính kim nằm trong xương mặt trăng, tức xương Vọng Nguyệt. Nó bị Thiên Nghịch hấp thu suốt ba tháng để hoàn tất thuộc tính kim.","detail":"Khi Vương Lâm đặt Thiên Nghịch Châu lên dãy núi do xương mặt trăng hóa thành, Kim Viên Quáng bên trong hóa thành từng sợi tơ vàng bị hạt châu hấp thụ rất chậm. Sau ba tháng, khoáng vật này biến mất, giúp thuộc tính kim của Thiên Nghịch viên mãn.","nguon":["@c0675"]},{"id":"ao-giap-mau-den-cua-loi-thu","name":"Áo giáp màu đen của Lôi Thú","cn":"","aliases":[],"category":"khac","categoryLabel":"Giáp","phamCap":"không rõ","soHuu":["Người đàn ông tóc đen cưỡi Lôi Thú"],"trangThai":"đang xuất hiện","blurb":"Bộ giáp màu đen khoác trên Lôi Thú của người đàn ông tóc đen.","detail":"Lôi Thú mà người đàn ông tóc đen cưỡi được bao phủ bởi một lớp giáp đen, khiến hình dáng của nó càng thêm dữ tợn khi bay trong tinh không về phía tầng đá vụn Nam Vực La Thiên.","nguon":["@c0678"]},{"id":"canh-cua-thien-dia","name":"Cánh cửa Thiên Địa","cn":"","category":"khac","categoryLabel":"Dị tượng cửa thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"đã mở khe hở trong Lôi Trì","blurb":"Cánh cửa lớn xuất hiện giữa Lôi Trì sau khi Thiên Nghịch biến hóa. Khe hở của nó khiến tâm thần Vương Lâm bị hút vào không gian Thiên Nghịch.","detail":"Cánh cửa Thiên Địa hiện ra giữa tử quang phủ khắp Lôi Trì; khi khe cửa mở, thân thể Vương Lâm dừng ngoài khe hở còn tâm thần dung nhập vào không gian bên trong. Bên ngoài cửa còn có cánh tay khổng lồ ngưng hóa, nhưng bị lôi điện màu tím trấn áp, tạo cơ hội để Vương Lâm tiếp cận.","nguon":["@c0679"]},{"id":"canh-tay-khong-lo-ben-ngoai-canh-cua","name":"Cánh tay khổng lồ bên ngoài cánh cửa","cn":"","category":"khac","categoryLabel":"Dị tượng thực thể thần bí","phamCap":"Không rõ","soHuu":[],"trangThai":"bị lôi điện màu tím trấn áp","blurb":"Cánh tay lớn ngưng hóa bên ngoài cánh cửa Thiên Địa trong Lôi Trì. Lần này nó bị vô số lôi điện màu tím quấn quanh, khiến Vương Lâm có cơ hội mạo hiểm tiếp cận khe cửa.","detail":"Cánh tay khổng lồ xuất hiện cùng dị biến cánh cửa Thiên Địa, là uy hiếp khiến Vương Lâm phải giữ đường lui. Tuy nhiên lôi điện màu tím từ Lôi Trì lập tức lao tới tấn công và trấn áp cánh tay, làm tình thế khác hẳn lần nguy hiểm trước đó.","nguon":["@c0679"]},{"id":"dao-hon-cua-than-cong-ho","name":"Đạo Hồn của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật bảo chứng tu đạo","phamCap":"Ý cảnh và đạo niệm Dương Thật","soHuu":["Vương Lâm"],"trangThai":"đã dung nhập nguyên thần Vương Lâm","blurb":"Đạo Hồn của Thân Công Hổ là phần hồn chứa ý cảnh và đạo niệm được hắn tự rút ra để xin dựa vào Vương Lâm. Vương Lâm thu nó vào nguyên thần làm bảo chứng cho lời nương tựa ngàn năm.","detail":"Khi Vương Lâm từ chối nhận người theo, Thân Công Hổ bấm quyết rút một luồng sáng màu đen từ Thiên Linh cái, bên trong ẩn chứa ý cảnh và đạo niệm của hắn. Sau khi xác nhận hắn không hối hận, Vương Lâm thu Đạo Hồn, nuốt vào và dung nhập nguyên thần.","nguon":["@c0681"]},{"id":"loi-dinh","name":"Lôi Đỉnh","cn":"","category":"khac","categoryLabel":"Đạo cụ truyền tống","phamCap":"Liên quan Lôi Tiên Giới","soHuu":[],"trangThai":"được dùng để vào Lôi Tiên Giới khi mở ra","blurb":"Lôi Đỉnh là vật được Thân Công Hổ nhắc tới như điều kiện để tiến vào Lôi Tiên Giới khi giới này mở ra. Nó gắn với lần mở Lôi Tiên Giới sau mười năm tại La Thiên.","detail":"Theo Thân Công Hổ, khi Lôi Tiên Giới mở ra, tu sĩ có thể dựa vào Lôi Đỉnh để đi vào. Vật này trở thành thông tin then chốt khiến Vương Lâm chú ý tới chuyến vào Lôi Tiên Giới nhằm tìm cơ hội tu luyện bằng tiên ngọc.","nguon":["@c0681"]},{"id":"van-dinh-chi-tinh","name":"Vấn Đỉnh Chi Tinh","cn":"","category":"khac","categoryLabel":"Vật liên quan cảnh giới","phamCap":"Không rõ","soHuu":[],"trangThai":"chưa có trong tay Vương Lâm","blurb":"Vấn Đỉnh Chi Tinh được nhắc như yếu tố mà tu sĩ Vấn Đỉnh bình thường có, còn Vương Lâm thì chưa sở hữu sau khi mới đạt Vấn Đỉnh.","detail":"Trong chương này, việc Vương Lâm chưa có Vấn Đỉnh Chi Tinh được dùng để giải thích vì sao nguyên lực của hắn yếu hơn tu sĩ Vấn Đỉnh bình thường, đặc biệt sau trận với Lôi Đạo Tử khiến nguyên lực gần chạm ranh giới thấp nhất.","nguon":["@c0682"]},{"id":"kiem-go-mau-tim","name":"Kiếm gỗ màu tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang sử dụng","blurb":"Pháp bảo màu tím của Chiến Không Liệt, dùng để phi hành và phối hợp thi triển thần thông.","detail":"Kiếm gỗ màu tím mang tử quang và hàn khí sắc bén. Khi Chiến Không Liệt vận chuyển thần thông, kiếm khí từ pháp bảo này dung hợp với lôi quang màu tím, tạo nên uy thế có thiên địa nguyên khí.","nguon":["@c0684"]},{"id":"tui-tru-vat-cua-than-cong-ho","name":"Túi trữ vật của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"đang sở hữu","blurb":"Túi trữ vật Thân Công Hổ dùng để lấy đan dược trước trận chiến.","detail":"Sau khi nhận khảo nghiệm từ Vương Lâm, Thân Công Hổ vỗ túi trữ vật lấy ra một lọ đan dược để chuẩn bị cho tình thế giao chiến với Chiến Không Liệt.","nguon":["@c0684"]},{"id":"lo-dan-duoc-cua-than-cong-ho","name":"Lọ đan dược của Thân Công Hổ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"đang sở hữu","blurb":"Lọ đan dược Thân Công Hổ lấy ra trước khi giao chiến với Chiến Không Liệt.","detail":"Được lấy từ túi trữ vật ngay sau khi Vương Lâm tuyên bố xem trận chiến là khảo nghiệm. Công dụng cụ thể chưa được nêu trong chương này.","nguon":["@c0684"]},{"id":"dan-duoc-phat-hong-quang-cua-loi-tien-dien","name":"Đan dược phát hồng quang của Lôi Tiên Điện","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Đan dược Lôi Tiên Điện","soHuu":["Thân Công Hổ"],"trangThai":"da-dung","blurb":"Đan dược do Thân Công Hổ sử dụng trước khi quyết chiến với Chiến Không Liệt. Thuốc giúp hắn áp chế thương thế và tạm đẩy khí tức lên trạng thái mạnh hơn.","detail":"Thân Công Hổ bóp nát dược bình rồi nuốt các viên đan phát hồng quang. Sau khi dùng đan, khí tức toàn thân hắn tăng vọt hung hãn, giúp hắn cưỡng ép giữ trạng thái đỉnh cao để thi triển Dẫn lôi thuật đấu với Chiến Không Liệt.","nguon":["@c0685"]},{"id":"thu-trieu-tap-cua-loi-tien-dien","name":"Thư triệu tập của Lôi Tiên Điện","cn":"","category":"khac","categoryLabel":"Tín lệnh","phamCap":"Tín lệnh Lôi Tiên Điện","soHuu":["Chiến Không Liệt"],"trangThai":"dang-co","blurb":"Thư triệu tập mà Chiến Không Liệt đã nhận từ Lôi Tiên Điện. Nó báo hiệu hắn sẽ trở thành sứ giả của Lôi Tiên Điện cùng Thân Công Hổ.","detail":"Trước khi rời khỏi Lôi Trì, Chiến Không Liệt nói mình đã nhận thư triệu tập của Lôi Tiên Điện, sau này sẽ cùng Thân Công Hổ làm sứ giả trong hệ thống Lôi Tiên Điện.","nguon":["@c0685"]},{"id":"kiem-go-cua-chien-khong-liet","name":"Kiếm gỗ của Chiến Không Liệt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang sử dụng","blurb":"Pháp bảo kiếm gỗ của Chiến Không Liệt, được dùng trong lần giao thủ với Thân Công Hổ tại Lôi Trì. Khi thúc nguyên khí, kiếm lan tử quang và phóng kiếm khí mạnh.","detail":"Kiếm gỗ bay lên từ dưới chân Chiến Không Liệt, được hắn phun nguyên khí lên để kích phát tử quang và kiếm khí nồng đậm. Nó đối kháng với Dẫn lôi thuật của Thân Công Hổ trong một lần va chạm khiến lôi quang tiêu tán, kiếm gỗ lui lại và hai bên đều bị đẩy lùi.","nguon":["@c0686"]},{"id":"ngoc-gian-truyen-am-cua-than-cong-ho","name":"Ngọc giản truyền âm của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm","Thân Công Hổ"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản Thân Công Hổ để lại cho Vương Lâm trước khi rời Lôi Trì. Bên trong có tinh đồ toàn bộ La Thiên Tinh Vực và phần giới thiệu tỉ mỉ nhiều nơi.","detail":"Trước khi bị Vương Lâm đuổi đi, Thân Công Hổ để lại ngọc giản truyền âm. Vật này chứa tinh đồ La Thiên Tinh Vực, chỉ rõ nhiều khu vực và giúp Vương Lâm không lạc đường khi muốn tìm một nơi bí mật để tu luyện, chuẩn bị cho Lôi Tiên Giới.","nguon":["@c0686"]},{"id":"ngoc-gian-oan-khi","name":"Ngọc giản oán khí","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chứa","phamCap":"không rõ","soHuu":["Trương Tân Hải","Vương Lâm"],"trangThai":"đã giao cho Vương Lâm","blurb":"Ngọc giản chứa oán khí phàm nhân toàn Thanh Linh Tinh do Trương Tân Hải thu gom.","detail":"Trương Tân Hải hoàn thành việc thu gom oán khí phàm nhân trên Thanh Linh Tinh và giao toàn bộ cho Vương Lâm bằng ngọc giản; số oán khí này được Vương Lâm hấp thu vào Hoàng Tuyền.","nguon":["@c0689"]},{"id":"dan-duoc-vuong-lam-ban-cho-truong-gia","name":"Đan dược Vương Lâm ban cho Trương gia","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Con trai Trương Tân Hải"],"trangThai":"đã ban","blurb":"Đan dược Vương Lâm giao cho Trương gia để hỗ trợ con trai Trương Tân Hải trùng kích Hóa Thần.","detail":"Vương Lâm ban đan dược cho con trai Trương Tân Hải, nói rằng nếu tư chất không đủ thì có thể nhờ linh khí trong đan dược tăng thêm chút cơ hội Hóa Thần.","nguon":["@c0689"]},{"id":"tien-dich","name":"Tiên dịch","cn":"","aliases":[],"category":"khac","categoryLabel":"Tài nguyên tu luyện","phamCap":"tiên lực","soHuu":["Vương Lâm"],"trangThai":"đã dùng","blurb":"Tiên dịch là tài nguyên Vương Lâm uống sau khi dùng hết tiên ngọc để thúc đẩy tu vi.","detail":"Sau một năm hấp thu tiên khí trong trận pháp tiên ngọc, khi toàn bộ tiên ngọc đã dùng hết, Vương Lâm lập tức uống tiên dịch để lượng tiên lực lớn tiếp tục đẩy tu vi tới Vấn Đỉnh viên mãn.","nguon":["@c0689"]},{"id":"tien-son","name":"Tiên Sơn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Hòn đá biến hóa thành ngọn Tiên Sơn lớn, chứa tiên lực nồng đậm và uy áp.","detail":"Vương Lâm lấy hòn đá trong túi trữ vật hóa thành Tiên Sơn, rút khí tức tang thương từ đó để thi triển Trừu Linh Chi Lai.","nguon":["@c0690"]},{"id":"ngoc-gian-chua-oan-khi","name":"Ngọc giản chứa oán khí","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản chứa oán khí được Vương Lâm mang theo khi rời Thanh Linh Tinh.","detail":"Vật này liên quan tới việc Tuyền Hồn trong Hoàng Tuyền của Vương Lâm có dấu hiệu ngưng kết thức tỉnh.","nguon":["@c0690"]},{"id":"ngoc-gian-cua-than-cong-ho","name":"Ngọc giản của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Ngọc giản tình báo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Ngọc giản ghi thông tin về các tu chân tinh và lượng Lôi Đỉnh các gia tộc thường nhận.","detail":"Vương Lâm dùng nó để chọn Thánh Đàn Tinh, nơi có hai gia tộc thường nhận nhiều Lôi Đỉnh, làm mục tiêu chờ đoạt.","nguon":["@c0690"]},{"id":"son-hon-tan","name":"Sơn Hồn Tán","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Pháp bảo liên quan hồn phách Tiên Sơn.","detail":"Khi lão già Âm Hư thi triển Đệ Tam Nhãn, hồng quang làm hồn phách Tiên Sơn từ Sơn Hồn Tán tan rã một phần, sau đó Vương Lâm thu hồi về Tiên Sơn.","nguon":["@c0691"]},{"id":"ngoc-gian-ghi-ba-than-thong","name":"Ngọc giản ghi ba thần thông","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lão già Trương gia"],"trangThai":"đã giao dịch","blurb":"Ba ngọc giản Vương Lâm dùng để ghi Tịch Diệt Chỉ, Hóa Ma Chỉ và Sát Lục Tiên Quyết.","detail":"Được dùng làm vật trao đổi để lấy ngọc giản Đệ Tam Nhãn từ lão già Âm Hư.","nguon":["@c0691"]},{"id":"ngoc-gian-de-tam-nhan","name":"Ngọc giản Đệ Tam Nhãn","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Ngọc giản ghi thần thông Đệ Tam Nhãn.","detail":"Lão già Âm Hư ghi thuật vào ngọc giản và cố ý để lại vài chỗ sai lầm gây họa ngầm; Vương Lâm nhờ từng quan sát Đệ Tam Nhãn nên nhìn ra manh mối và dự định tu chỉnh.","nguon":["@c0691"]},{"id":"tien-loi-thu-ba","name":"Tiên Lôi thứ ba","cn":"","category":"khac","categoryLabel":"Lôi đình","phamCap":"không rõ","soHuu":[],"trangThai":"đã giáng xuống","blurb":"Đạo Tiên Lôi mạnh hơn hai lần trước, ngưng thành cơn lốc sấm sét khổng lồ.","detail":"Đạo lôi này gom gần như toàn bộ mây sấm trên Thanh Linh Tinh, được nguyên thần Vương Lâm nuốt một nửa, còn phần còn lại bị Lôi Đỉnh hút vào khiến đỉnh nứt vỡ.","nguon":["@c0692"]},{"id":"luu-tinh-loi-dinh","name":"Lưu tinh lôi đình","cn":"","category":"khac","categoryLabel":"Lôi đình hiện tượng","phamCap":"không rõ","soHuu":[],"trangThai":"đã dẫn Vương Lâm vào Lôi Tiên Giới","blurb":"Luồng lôi đình dạng lưu tinh kéo Vương Lâm vào Lôi Tiên Giới.","detail":"Khi xông vào tia chớp đỏ sậm, lôi lực của nó tăng mạnh, khóa thân thể và nguyên thần Vương Lâm rồi nện hắn xuống đại lục phía đông, tạo hố sâu và khiến hắn trọng thương.","nguon":["@c0694"]},{"id":"tien-but-lap-lanh-kim-quang","name":"Tiên bút lấp lánh kim quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Cây tiên bút kim quang Vương Lâm lấy ra khi đi vào thông đạo dưới lòng đất.","detail":"Vương Lâm lấy tiên bút từ túi trữ vật, phối hợp tiên lực và khe yêu dị ở mi tâm để mở đường trong bùn đất bị giam cầm.","nguon":["@c0694"]},{"id":"tien-dan","name":"Tiên đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"tiên đan","soHuu":[],"trangThai":"không rõ","blurb":"Đan dược hiếm trong Lôi Tiên Giới, được xem là một trong những cơ duyên khiến tu sĩ muốn tiến vào nơi này. Mỗi lần giới mở ra, số người tìm được tiên đan rất ít.","detail":"Vương Lâm hồi tưởng thông tin về Lôi Tiên Giới và nhận ra tiên đan là một lợi ích lớn tại nơi này. Loại đan dược này không dễ gặp, phụ thuộc vận số của người tiến vào Lôi Tiên Giới.","nguon":["@c0695"]},{"id":"tien-bao","name":"Tiên bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"tiên bảo","soHuu":[],"trangThai":"không rõ","blurb":"Bảo vật cấp tiên trong Lôi Tiên Giới, thuộc nhóm cơ duyên được tu sĩ La Thiên tinh vực săn tìm. Việc có thể tìm được hay không phụ thuộc vào vận số của từng người.","detail":"Tiên bảo được nêu cùng tiên đan, tiên thuật, thi thể tiên nhân, vũng nguyên lực và nguyên khí như một trong các nguyên nhân khiến vô số tu sĩ muốn tiến vào Lôi Tiên Giới. Chương chưa nêu món tiên bảo cụ thể nào được Vương Lâm thu được ở thời điểm này.","nguon":["@c0695"]},{"id":"thi-the-tien-nhan","name":"Thi thể tiên nhân","cn":"","category":"khac","categoryLabel":"Di hài","phamCap":"tiên nhân","soHuu":[],"trangThai":"được treo thưởng","blurb":"Dị vật cực giá trị trong Lôi Tiên Giới, gần đây có tin phát hiện tám thi thể tiên nhân được bảo tồn nguyên vẹn. Đầu mối chính xác hoặc bản thân thi thể có thể đổi lấy lợi ích lớn từ Lôi Tiên Điện.","detail":"Theo hiểu biết Vương Lâm tổng hợp, thi thể tiên nhân trong Lôi Tiên Giới là mục tiêu tranh đoạt quan trọng. Lôi Tiên Điện treo giá cao cho manh mối chính xác, thậm chí người có thiên tư tốt nhờ đó có thể được một trong mười đại trưởng lão nhận làm đệ tử.","nguon":["@c0695"]},{"id":"vung-nguyen-luc","name":"Vũng nguyên lực","cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"thiên địa nguyên lực nồng đậm","soHuu":[],"trangThai":"không rõ","blurb":"Nơi tích tụ thiên địa nguyên lực cực nồng trong Lôi Tiên Giới. Từng có tu sĩ Vấn Đỉnh kỳ nhờ tu luyện trong vũng nguyên lực mà đột phá khỏi bước đầu tiên tu đạo.","detail":"Vũng nguyên lực là một trong các cơ duyên khiến tu sĩ điên cuồng muốn vào Lôi Tiên Giới. Tin tức về người từ Vấn Đỉnh kỳ vượt qua bước đầu tiên nhờ vũng nguyên lực khiến tài nguyên này trở thành mục tiêu lớn đối với tu sĩ cấp cao.","nguon":["@c0695"]},{"id":"nguyen-khi","name":"Nguyên khí","cn":"","category":"khac","categoryLabel":"Pháp khí/tài nguyên đặc thù","phamCap":"không rõ","soHuu":[],"trangThai":"không rõ","blurb":"Pháp khí hoặc tài nguyên đặc thù trong Lôi Tiên Giới, chứa lực lượng kỳ dị khác tiên lực trong tiên ngọc. Người hấp thu ở cảnh giới khác nhau sẽ chuyển hóa thành tiên lực hoặc nguyên lực.","detail":"Nguyên khí được Vương Lâm nhắc như một lợi ích quan trọng của Lôi Tiên Giới. Nếu tu sĩ bước đầu tiên hấp thu thì sinh tiên lực; nếu tu sĩ bước thứ hai hấp thu thì chuyển thành nguyên lực, vì vậy nó có giá trị lớn với cả hai tầng tu sĩ.","nguon":["@c0695"]},{"id":"manh-vo-mau-xam-trang-co-tien-luc","name":"Mảnh vỡ màu xám trắng có tiên lực","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm thu vào túi trữ vật","blurb":"Mảnh vỡ màu xám trắng có tiên lực là vật to bằng nắm tay, không trọn vẹn, giống một phần của cái bình. Nó phát ra dao động tiên lực và trở thành mục tiêu tranh đoạt của Hứa Phong Hàn.","detail":"Sau khi các sợi tơ nguyên lực trên mặt đất tan nát, Vương Lâm phát hiện vật màu xám trắng nằm trong bùn đất, phát ra dao động tiên lực. Hắn nhận ra vật này giống mảnh vỡ của một cái bình và thu vào túi trữ vật; ngay sau đó Hứa Phong Hàn xuất hiện, uy hiếp hắn giao vật rồi giao chiến.","nguon":["@c0696"]},{"id":"da-nui-cua-tien-gioi","name":"Đá núi của tiên giới","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Đá núi của tiên giới là vật Vương Lâm lấy từ túi trữ vật trong lúc giao chiến. Hắn khiến nó hóa lớn thành tảng đá khổng lồ rồi rút hồn phách tiên thạch bên trong.","detail":"Khi đối mặt màn nước ma khí của Hứa Phong Hàn, Vương Lâm lấy đá núi tiên giới ra, khiến nó hóa thành tảng đá lớn. Từ tảng đá này, hắn rút ra hồn phách tiên thạch, biến thành sương mù tiên khí để xuyên phá màn nước.","nguon":["@c0696"]},{"id":"hon-phach-tien-thach","name":"Hồn phách tiên thạch","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm/năng lượng","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Được rút ra để giao chiến","blurb":"Hồn phách tiên thạch là phần hồn phách được Vương Lâm rút ra từ đá núi tiên giới. Nó hóa thành sương mù mang khí tức tang thương và tiên khí nồng đậm.","detail":"Trong trận đấu với Hứa Phong Hàn, Vương Lâm dùng tay phải nhấc lên, rút hồn phách tiên thạch từ đá núi tiên giới. Hồn phách này hóa thành đám sương tiên khí, xuyên thủng màn nước ma khí rồi được hắn đẩy về phía đối thủ.","nguon":["@c0696"]},{"id":"loi-cau","name":"Lôi cầu","cn":"","category":"khac","categoryLabel":"Vật phẩm lôi lực","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Lôi cầu là khối lôi lực từng bị ma ảnh nuốt nhưng chưa bị hóa giải.","detail":"Trong trận với Hứa Phong Hàn, Vương Lâm dẫn bạo lôi cầu từ bên trong ma ảnh, khiến lôi uy bộc phát và phá nát thân thể ma ảnh màu đen.","nguon":["@c0697"]},{"id":"thanh-truong-thuong","name":"Thanh trường thương","cn":"","category":"phap-bao","categoryLabel":"Pháp khí biến hóa","phamCap":"không rõ","soHuu":["Hứa Phong Hàn"],"trangThai":"hong","blurb":"Thanh trường thương là pháp khí do nước mưa và linh tính biến hóa trong trận giao chiến.","detail":"Thanh trường thương bị sương mù do hồn phách tiên thạch hóa thành áp chế. Khi sương mù quay lại tảng đá, trường thương mất linh tính và trở lại thành nước mưa.","nguon":["@c0697"]},{"id":"manh-vo-phap-bao","name":"Mảnh vỡ pháp bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo tàn phiến","phamCap":"có tiên lực","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh vỡ pháp bảo là các tàn phiến tỏa tiên lực lộ ra dưới bùn đất trong trận chiến.","detail":"Khi đất cát bị chấn động hất tung, các mảnh vỡ pháp bảo gần thông đạo dưới đất lộ ra. Vương Lâm tranh thủ vung tay thu toàn bộ vào túi trữ vật giữa lúc Hứa Phong Hàn còn đang giao chiến.","nguon":["@c0697"]},{"id":"ma-lien","name":"Ma Liên","cn":"","category":"khac","categoryLabel":"Đạo niệm thực thể","phamCap":"không rõ","soHuu":["Hứa Phong Hàn","Vương Lâm"],"trangThai":"tieu-tan","blurb":"Ma Liên là đạo niệm thực thể của Hứa Phong Hàn, đồng thời là không gian cất giữ vật phẩm.","detail":"Ma Liên bị Đạo Hóa Hoàng Tuyền của Vương Lâm luyện hóa nên chưa tiêu tán ngay sau khi Hứa Phong Hàn chết. Bên trong nó có hắc khí ma hồn và bốn viên quang châu chứa vật phẩm; sau khi ma hồn bị nuốt và quang châu bị lấy đi, Ma Liên héo rũ rồi tan mất.","nguon":["@c0699"]},{"id":"manh-vo-phap-bao-dang-binh","name":"Mảnh vỡ pháp bảo dạng bình","cn":"","category":"phap-bao","categoryLabel":"Mảnh pháp bảo","phamCap":"nghi nguyên khí","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Các mảnh vỡ pháp bảo Vương Lâm thu được sau trận với Hứa Phong Hàn, có thể ghép thành hình bình nhưng không đủ mảnh.","detail":"Vương Lâm nhận ra mười mảnh vỡ có tiên lực ba động cổ quái, ghép thử thành hình bình nước nhưng thiếu một phần nên không thể phục nguyên. Hắn suy đoán đây có thể là pháp bảo nguyên khí luyện chế thất bại hoặc đã vỡ nát.","nguon":["@c0699"]},{"id":"hai-dao-tien-loi","name":"Hai đạo tiên lôi","cn":"","category":"khac","categoryLabel":"Lôi lực","phamCap":"tiên lôi","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hai đạo tiên lôi từng bị Vương Lâm nuốt nhưng chưa luyện hóa.","detail":"Sau trận chiến với Hứa Phong Hàn, Vương Lâm luyện hóa hai đạo tiên lôi trong động phủ trên Lôi Sơn để bổ sung nguyên lực đã hao tổn khi dùng con mắt thứ ba và Trảm La Quyết.","nguon":["@c0699"]},{"id":"quang-chau-trong-ma-lien","name":"Quang châu trong Ma Liên","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"không rõ","soHuu":["Hứa Phong Hàn","Vương Lâm"],"trangThai":"da-mo","blurb":"Những viên quang châu nằm trong không gian Ma Liên, mỗi viên chứa một vật phẩm.","detail":"Trong Ma Liên có bốn viên quang châu; một viên tự vỡ, Vương Lâm kịp lấy hai viên và mở ra dược bình khắc chữ Hứa cùng một lá bùa có ký hiệu mực đỏ.","nguon":["@c0699"]},{"id":"duoc-binh-khac-chu-hua","name":"Dược bình khắc chữ Hứa","cn":"","category":"khac","categoryLabel":"Vật chứa đan dược","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Dược bình lấy từ quang châu trong Ma Liên, trên bình khắc chữ Hứa.","detail":"Dược bình vẫn còn phong sáp chưa mở, bên trong có một viên đan dược tỏa tiên khí nồng đậm. Vì được Hứa Phong Hàn đặt trong đạo niệm, Vương Lâm nhận định vật này không tầm thường.","nguon":["@c0699"]},{"id":"dan-duoc-trong-duoc-binh-ho-hua","name":"Đan dược trong dược bình họ Hứa","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Viên đan dược trong dược bình khắc chữ Hứa, tiên khí rất nồng đậm.","detail":"Khi Vương Lâm mở dược bình, tiên khí từ viên đan dược khiến thể xác và tinh thần thoải mái. Dược hiệu cụ thể chưa lộ, nhưng hắn nhận định tuyệt không tầm thường.","nguon":["@c0699"]},{"id":"la-bua-ky-hieu-muc-do","name":"Lá bùa ký hiệu mực đỏ","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lá bùa rơi ra từ quang châu thứ hai trong Ma Liên, trên đó có ký hiệu mực đỏ khó nhận biết.","detail":"Bề ngoài lá bùa giống phù cấp thấp tầm thường, nhưng vì được Hứa Phong Hàn cất trong đạo niệm nên Vương Lâm cho rằng lai lịch và công dụng của nó không đơn giản.","nguon":["@c0699"]},{"id":"lenh-bai-cua-to-phu-dieu-gia","name":"Lệnh bài của tổ phụ Diêu gia","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"không rõ","soHuu":["Diêu Không"],"trangThai":"dang-co","blurb":"Tín vật tổ phụ Diêu gia giao cho Diêu Không để tới Lôi Tiên Điện.","detail":"Sau khi tính ra Diêu Tích Huyết ở Lôi Tiên Giới, tổ phụ Diêu gia bảo Diêu Không cầm lệnh bài tới Lôi Tiên Điện để được tìm cách đưa vào Lôi Tiên Giới.","nguon":["@c0699"]},{"id":"hinh-nhan-moc-linh","name":"Hình nhân mộc linh","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Vật dò trận","phamCap":"không rõ","soHuu":["Người đàn ông trung niên"],"trangThai":"da-dung","blurb":"Hình nhân toàn thân bằng mộc linh, trên người khắc ký tự và dấu ấn. Tu sĩ trung niên dùng nó để dò trận rồi tự bạo phá lớp cấm chế che giấu cửa động.","detail":"Vật này được lấy ra khi tu sĩ trung niên phát hiện trận pháp cấm chế khả nghi. Sau khi bước vào trận, hình nhân tự bạo, làm cấm chế tan vỡ và lộ ra cửa động bên dưới, nhưng cũng khiến chủ nhân rơi vào bẫy thật sự.","nguon":["@c0700"]},{"id":"quat-long-cua-nu-tu","name":"Quạt lông của nữ tu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo công kích","phamCap":"không rõ","soHuu":["Nữ tu mắt phượng"],"trangThai":"hong","blurb":"Pháp bảo dạng quạt lông được nữ tu dùng để phóng lông chim mang sát khí công kích Vương Lâm. Lông chim bị lôi đình của Vương Lâm đánh tan, khiến nữ tu thổ huyết vì phản chấn.","detail":"Nữ tu lấy quạt lông từ túi trữ vật khi quyết định bắt Vương Lâm làm thức ăn cho thú cưng. Đòn công kích bằng lông chim tưởng như sắc bén nhưng không chịu nổi lôi đình từ ngón trỏ Vương Lâm và bị phá hủy ngay trong một lần va chạm.","nguon":["@c0700"]},{"id":"dan-duoc-cua-to-phu-nu-tu","name":"Đan dược của tổ phụ nữ tu","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược cứu thương","phamCap":"không rõ","soHuu":["Tổ phụ Diêu gia","Lý Nguyên"],"trangThai":"da-dung","blurb":"Đan dược từng được tổ phụ của nữ tu ban cho Lý Nguyên. Theo lời nữ tu, nếu không có đan dược này thì Lý Nguyên đã chết vì thương thế từ trăm năm trước.","detail":"Vật này được nhắc lại trong cuộc đối thoại giữa nữ tu và Lý Nguyên, cho thấy gia tộc nữ tu vừa từng cứu mạng vừa nắm mệnh hồn của hắn. Đan dược là một phần nguyên nhân tạo nên ràng buộc giữa Lý Nguyên và gia tộc ấy.","nguon":["@c0700"]},{"id":"thiet-kiem-den-cua-nu-tu-ho-cat","name":"Thiết kiếm đen của nữ tử họ Cát","cn":"","aliases":["Thiết kiếm","Thanh thiết kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo gia truyền","phamCap":"Không rõ","soHuu":["Cát Hồng"],"trangThai":"dang-co","blurb":"Thanh thiết kiếm đen do Cát Hồng kế thừa từ gia tộc, bề ngoài bình thường nhưng chuyên đối phó lôi đình.","detail":"Cát Hồng dùng máu và ký hiệu kích hoạt thanh thiết kiếm, khiến nó tỏa quầng sáng để chở nàng và Lý Nguyên vượt qua sợi xích lôi quang. Khi Lý Nguyên đứng ở mũi kiếm, Vương Lâm cảm thấy người và kiếm hòa hợp một thể, cho thấy thanh kiếm có liên hệ sâu với Lý Nguyên.","nguon":["@c0701"]},{"id":"ngoc-gian-cam-che-cua-ly-nguyen","name":"Ngọc giản cấm chế của Lý Nguyên","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản chứa phương pháp cấm chế ẩn giấu thân hình mà Lý Nguyên giao cho Vương Lâm.","detail":"Theo yêu cầu của Vương Lâm, Lý Nguyên in phương pháp cấm chế vào ngọc giản rồi giao ra. Nội dung bên trong khiến Vương Lâm thấy khác với tiên cấm thuật hắn quen biết và hiện ra mười tám pho tượng lớn trong tâm thần.","nguon":["@c0701"]},{"id":"ban-do-co-cua-ly-nguyen","name":"Bản đồ cổ của Lý Nguyên","cn":"","category":"khac","categoryLabel":"Bản đồ","phamCap":"Không rõ","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Bản đồ cổ ghi vị trí một bí địa có cấm chế trong Lôi Tiên Giới.","detail":"Lý Nguyên nói mình từng có bản đồ cổ ghi lại nơi bí ẩn tồn tại trước khi Lôi Tiên Giới sụp đổ. Hắn đã nghiên cứu lâu và dùng tin tức này để cầu Vương Lâm tha lỗi.","nguon":["@c0701"]},{"id":"quang-cau-hon-phach-cua-nu-tu-ho-cat","name":"Quang cầu hồn phách của nữ tử họ Cát","cn":"","category":"khac","categoryLabel":"Tín vật hồn phách","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một phần hồn phách của Cát Hồng bị Vương Lâm rút ra và ngưng thành quang cầu làm tín vật.","detail":"Vương Lâm không lấy hồn Lý Nguyên mà chụp lấy hồn ảnh của nữ tử họ Cát, rút một quang cầu từ mi tâm hồn ảnh rồi cất vào túi trữ vật để khống chế chuyến đi.","nguon":["@c0701"]},{"id":"thiet-kiem","name":"Thiết kiếm","cn":"","aliases":["Thiết kiếm của Lý Nguyên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Thanh thiết kiếm chở Lý Nguyên và Cát Hồng đi trong hư vô Lôi Tiên Giới. Nó có quầng sáng chống lôi quang rất mạnh nhưng bị ảnh hưởng khi sợi xích lôi đình chấn động dữ dội. (+) Thanh kiếm được Vương Lâm dùng để tập kích Vân Hồn Tử khi đối phương sắp tiến vào vết nứt bảy màu. [CAN-SOAT-GOP]","detail":"Trong hành trình gần hai tháng, thiết kiếm là vật để Lý Nguyên đứng ở mũi kiếm và chở Cát Hồng đi qua hư vô đầy lôi quang. Vương Lâm quan sát nhiều lần, nhận ra lôi quang càng đậm nhưng thanh kiếm vẫn không suy chuyển; về sau khi sợi xích lôi đình chấn động mạnh, quầng sáng quanh kiếm bắt đầu tan rã.","nguon":["@c0702","@c1111"],"tabs":{}},{"id":"la-ban","name":"La bàn","cn":"","aliases":["La bàn của Lý Nguyên"],"category":"khac","categoryLabel":"Vật phẩm cấm chế","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"hong","blurb":"Vật phẩm Lý Nguyên dùng để tính toán cấm chế trước đám sương mù chắn đường. Kim đồng hồ trên la bàn xoay loạn rồi la bàn nổ tung thành tro bụi.","detail":"Khi phát hiện đám sương mù tiên khí phía trước là cấm chế, Lý Nguyên lấy la bàn ra để tính toán. Kim đồng hồ run rẩy xoay liên tục, sau đó vật này nổ tan, giúp làm nổi bật mức độ nguy hiểm và phức tạp của cấm chế thiên cấp trung phẩm.","nguon":["@c0702"]},{"id":"soi-xich-loi-quang","name":"Sợi xích lôi quang","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật lôi đình","phamCap":"không rõ","soHuu":[],"trangThai":"dang-ton-tai","blurb":"Đường nối lôi đình giữa các mảnh vỡ trong Lôi Tiên Giới. Chương này nhiều sợi xích lôi quang chấn động bất thường, báo hiệu nguy cơ sụp đổ mảnh vỡ đại lục.","detail":"Sợi xích lôi quang nối giữa các mảnh vỡ đại lục trong Lôi Tiên Giới vốn theo lời lão tổ nhà Lý Nguyên là chưa từng lay động. Khi nhóm Vương Lâm đi sâu vào hư vô, chấn động truyền tới khiến Vương Lâm suy yếu và khiến Lý Nguyên nhận ra nguy cơ hai mảnh vỡ đại lục có thể sụp đổ; cuối chương, lão già bí ẩn còn cầm một sợi xích lôi quang bước ra từ sương mù cấm chế.","nguon":["@c0702"]},{"id":"loi-quang-thiet-lien","name":"Lôi quang thiết liên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ, có chứa chút Tiên lôi","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"trangThai":"đang được lão già nắm giữ","blurb":"Sợi xích sắt tỏa lôi quang trong tay lão già Lôi tiên giới, ẩn chứa một chút Tiên lôi. Vương Lâm dù có nguyên thần thuộc tính lôi và lôi thể cũng không thể cầm nó thoải mái như lão.","detail":"Lôi quang thiết liên là sợi xích sắt do lão già cầm khi xuất hiện trước nhóm Vương Lâm. Chớp trên xích ẩn chứa Tiên lôi, khiến Vương Lâm nhận ra bản thân dù có lôi nguyên thần và lôi thể vẫn không đủ khả năng nắm giữ như lão; lão còn muốn dùng Lôi thú sừng bạc để kéo thiết liên.","nguon":["@c0703"]},{"id":"qua-cau-sang-ngung-tu-tu-hat-bui","name":"Quả cầu sáng ngưng tụ từ hạt bụi","cn":"","category":"khac","categoryLabel":"Vật phẩm hoặc thủ đoạn","phamCap":"Không rõ","soHuu":["Lão già chủ Lôi tiên giới cầm Lôi quang thiết liên"],"trangThai":"đã chui vào ngực Vương Lâm","blurb":"Quả cầu sáng do lão già ngưng tụ từ vô số hạt bụi rồi thổi vào ngực Vương Lâm. Lão nói đây là cách giúp Vương Lâm tu luyện lôi nguyên thần và lôi thể.","detail":"Sau khi chê Vương Lâm tu luyện lôi nguyên thần và lôi thể như trẻ con chơi đùa, lão già giơ tay chộp không trung, ngưng tụ vô số hạt bụi thành một quả cầu sáng. Lão thổi nhẹ khiến quả cầu bắn thẳng vào ngực Vương Lâm, nhanh đến mức hắn không kịp né tránh.","nguon":["@c0703"]},{"id":"chuy-thu-mau-den","name":"Chủy thủ màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo truyền thừa","phamCap":"không rõ","soHuu":["Cát Hồng","Vương Lâm"],"trangThai":"Vương Lâm thu giữ","blurb":"Chủy thủ truyền thừa của gia tộc Cát Hồng, chứa kịch độc ăn mòn thân thể và âm hồn gây thương tổn nguyên thần.","detail":"Cát Hồng lấy chủy thủ này ra từ túi trữ vật để nhân lúc Vương Lâm đau đớn mà ám toán. Khi bị Vương Lâm mở mắt uy hiếp ngược, nàng hoảng sợ ném chủy thủ xuống đất, để hắn chộp lấy và cất vào túi trữ vật.","nguon":["@c0704"]},{"id":"kiem-khi-cua-lang-thien-hau","name":"Kiếm khí của Lăng Thiên Hậu","cn":"","aliases":[],"category":"khac","categoryLabel":"Kiếm khí","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã sử dụng để uy hiếp Lý Nguyên","blurb":"Đạo kiếm khí do Lăng Thiên Hậu lưu lại trong tay Vương Lâm, được phóng ra tại ngọn núi vô danh. Nó dừng trước mi tâm Lý Nguyên như một thanh bảo kiếm, buộc Lý Nguyên phải nhìn nhận lại thế yếu.","detail":"Sau khi dùng Tiên Vệ khôi lỗi chứng minh ngọn núi không thể khóa mình, Vương Lâm tiếp tục phóng kiếm khí của Lăng Thiên Hậu. Đạo kiếm khí này cực nhanh, áp sát mi tâm Lý Nguyên và trở thành đòn uy hiếp trực tiếp trong cuộc mặc cả về thù lao.","nguon":["@c0705"]},{"id":"phap-bao-truyen-thua-cua-cat-gia","name":"Pháp bảo truyền thừa của Cát gia","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo gia tộc","phamCap":"không rõ","soHuu":["Cát Hồng"],"trangThai":"đang ở trong tay Cát Hồng","blurb":"Pháp bảo gia tộc do lão tổ Cát gia truyền cho Cát Hồng trước khi nàng vào Lôi tiên giới. Trong suy nghĩ của Cát Hồng, việc nhận pháp bảo này gắn với chuộc tội và hiến tế hồn phách.","detail":"Khi nhận ra bí mật giữa Cát gia, Lý Nguyên và ngọn núi vô danh, Cát Hồng hồi tưởng việc lão tổ truyền pháp bảo gia tộc cho mình. Nàng hiểu rằng sự sắp đặt ấy không đơn thuần là bảo hộ, mà liên quan đến việc gia tộc từng có người vào Lôi tiên giới rồi không trở về.","nguon":["@c0705"]},{"id":"ngoc-gian-mai-hoa-thap-tam-cam","name":"Ngọc giản Mai hoa thập tam cấm","cn":"","aliases":[],"category":"khac","categoryLabel":"Ngọc giản","phamCap":"không rõ","soHuu":["Lý Nguyên","Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Ngọc giản Mai hoa thập tam cấm là vật Lý Nguyên giao trước cho Vương Lâm khi tới ngọn núi cấm thuật. Bên trong ghi mười ba hình ảnh lớn và mười ba đóa hoa mai.","detail":"Lý Nguyên lấy ngọc giản từ túi trữ vật, giao cho Vương Lâm để đáp ứng yêu cầu về Mai Hoa thuật. Ngọc giản chứa Mai hoa thập tam cấm, còn các phần khác được Lý Nguyên hẹn giao sau khi vào núi.","nguon":["@c0706"]},{"id":"hoa-truc","name":"Họa trục","cn":"","aliases":["Bức họa","Họa trục của Lý Nguyên"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"Lý Nguyên đang giữ","blurb":"Họa trục là một trong ba vật Cát Hồng giao cho Lý Nguyên để cầu sống. Bức họa vẽ ngọn núi, phi kiếm, người trên chuôi kiếm và bóng người trên mũi kiếm giống Lý Nguyên.","detail":"Sau khi nhận túi trữ vật từ Cát Hồng, Lý Nguyên lấy ra họa trục và tỏ ra đặc biệt trân trọng. Hình ảnh trong họa trục hé lộ mối liên hệ giữa ngọn núi, thanh phi kiếm, chủ nhân trên chuôi kiếm và người đứng trên mũi kiếm.","nguon":["@c0706"]},{"id":"thanh-phi-kiem","name":"Thanh phi kiếm","cn":"","aliases":["Bảo kiếm trong huyễn cảnh","Thanh bảo kiếm tím"],"category":"phap-bao","categoryLabel":"Kiếm","phamCap":"không rõ","soHuu":["Chủ nhân của Lý Nguyên"],"trangThai":"xuất hiện trong họa trục, tượng đá và huyễn cảnh","blurb":"Thanh phi kiếm xuất hiện xuyên suốt qua họa trục, tượng đá và huyễn cảnh. Trong huyễn cảnh, nó là bảo kiếm được vô số tia chớp tím bao quanh, chở chủ nhân trên chuôi kiếm và người hầu trên mũi kiếm.","detail":"Bức họa cho thấy một thanh phi kiếm gắn với ngọn núi, nam tử trên chuôi kiếm và người trên mũi kiếm. Khi Vương Lâm rơi vào huyễn cảnh, thanh kiếm hiện ra giữa lôi điện tím, trở thành trung tâm của cảnh chủ nhân tan rã và người hầu lao theo.","nguon":["@c0706"]},{"id":"tuong-da","name":"Tượng đá","cn":"","aliases":["Tượng đá tiên nhân","Tượng đá của tiên nhân"],"category":"khac","categoryLabel":"Di tích / vật thể","phamCap":"Không rõ","soHuu":["Chủ nhân của Lý Nguyên"],"trangThai":"còn tồn tại","blurb":"Pho tượng trên đỉnh núi chứa thủ ấn nô ấn, gắn với tiên nhân từng khiến tổ tiên Lý gia trở thành đầy tớ.","detail":"Khi Lý Nguyên dùng tiên lực khiến tượng đá vỡ nát, các mảnh đá lập tức tự ngưng tụ trở lại hình dạng ban đầu. Thủ ấn trên tượng có thể hút tâm thần người quan sát và truyền ra âm thanh truyền thừa nô lệ.","nguon":["@c0707"]},{"id":"binh-ngoc-cua-ly-nguyen","name":"Bình ngọc của Lý Nguyên","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"da-dung","blurb":"Bình ngọc được Lý Nguyên dùng trong nghi thức tế luyện tượng đá.","detail":"Khi tượng đá xuất hiện vết nứt, Lý Nguyên lấy bình ngọc ném ra; tia sáng trong bình bay vào hồng hỏa rồi chui vào tượng đá, thúc đẩy khí tức bên trong thức tỉnh mạnh hơn.","nguon":["@c0708"]},{"id":"thach-kiem","name":"Thạch kiếm","cn":"","category":"khac","categoryLabel":"Tượng kiếm","phamCap":"không rõ","soHuu":["Chủ nhân của Lý Nguyên"],"trangThai":"nứt vỡ","blurb":"Thanh kiếm đá gắn với bố cục chủ nhân đứng trên chuôi kiếm và đầy tớ đứng trên mũi kiếm.","detail":"Trong biến cố tượng đá, thạch kiếm cũng xuất hiện vết nứt. Hình ảnh chủ nhân đứng trên chuôi kiếm và đầy tớ đứng trên mũi kiếm là biểu tượng trung tâm trong sự cố Lý Nguyên muốn hồi sinh chủ nhân.","nguon":["@c0709"]},{"id":"ba-loai-phap-khi-cua-cat-gia","name":"Ba loại pháp khí của Cát gia","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"không rõ","soHuu":["Cát gia"],"trangThai":"không rõ","blurb":"Ba pháp khí được Cát gia cố ý giữ và truyền tin, liên quan đến lần luân hồi thứ hai nhằm hồi sinh tiên nhân bị phong ấn.","detail":"Vương Lâm suy luận Cát gia không che giấu mà còn truyền tin về ba loại pháp khí, chờ người Lý gia bước vào lần luân hồi thứ hai. Vai trò cụ thể của từng pháp khí chưa được xác nhận trong chương này.","nguon":["@c0709"]},{"id":"thanh-kiem-khoi-xanh","name":"Thanh kiếm khói xanh","cn":"","category":"phap-bao","categoryLabel":"Kiếm/hiện tượng tiên giới","phamCap":"không rõ","soHuu":[],"trangThai":"tồn tại trong Lôi tiên giới","blurb":"Thanh kiếm do khói xanh hóa thành sau biến cố tượng đá và nô ấn. Tàn hồn từ nô ấn của Lý Nguyên bay lên mũi kiếm rồi biến mất về phía chân trời.","detail":"Từ sau biến cố, trong Lôi tiên giới xuất hiện một thanh kiếm do khói xanh hóa thành, trên mũi kiếm có một thân ảnh đứng mãi như tồn tại vĩnh hằng. Vật này gắn với tàn hồn người đầy tớ, nô ấn trên Lý Nguyên và bí ẩn thực giả của cảnh tượng viễn cổ tiên giới.","nguon":["@c0710"]},{"id":"cam-che-la-ban","name":"Cấm chế la bàn","cn":"","category":"phap-bao","categoryLabel":"Pháp khí cấm chế","phamCap":"chưa chế tạo","soHuu":["Vương Lâm","Lý Nguyên"],"trangThai":"dự kiến chế tạo","blurb":"Cấm chế la bàn là pháp khí Lý Nguyên nhắc tới khi khuyên thu bùn đất tiên cấm. Sau khi rời Lôi tiên giới, bùn đất này có thể dùng để chế tạo la bàn phục vụ cấm chế.","detail":"Khi nhận ra tiên cấm lấy bùn đất làm chính, Lý Nguyên khuyên Vương Lâm thu bùn đất vào túi trữ vật. Hắn cho rằng sau khi rời Lôi tiên giới, loại bùn đất này có thể biến đổi và trở thành vật liệu để chế tạo cấm chế la bàn.","nguon":["@c0710"]},{"id":"bun-dat-cua-cam-che","name":"Bùn đất của cấm chế","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu cấm chế","phamCap":"vật liệu tiên cấm","soHuu":["Vương Lâm","Lý Nguyên"],"trangThai":"được thu giữ","blurb":"Bùn đất tại tiên cấm trên mảnh đại lục hoang vu được Lý Nguyên và Vương Lâm thu vào túi trữ vật. Nó được xem là vật liệu có thể dùng để chế tạo cấm chế la bàn sau khi rời Lôi tiên giới.","detail":"Loại bùn đất này là phần chủ yếu của tiên cấm dùng để che giấu tiên sơn và cung điện. Lý Nguyên nhận ra giá trị của nó trong cấm chế, vì vậy hai người thu lại để dành cho việc luyện chế hoặc nghiên cứu cấm chế sau này.","nguon":["@c0710"]},{"id":"bo-giap-da","name":"Bộ giáp da","cn":"","category":"phap-bao","categoryLabel":"Giáp/vật phẩm","phamCap":"không rõ","soHuu":[],"trangThai":"trên hài cốt","blurb":"Bộ giáp da thô thiển có đường nét được mặc trên một bộ hài cốt dưới tán cây sau cung điện. Vương Lâm chấn động mạnh khi nhìn thấy nó.","detail":"Bộ giáp nằm trên một trong hai bộ hài cốt trắng dưới tán cây phía sau cung điện rách nát. Hình dạng thô thiển nhưng có đường nét đặc biệt, khiến Vương Lâm kinh ngạc đến mức không tin vào mắt mình, cho thấy vật này có lai lịch quan trọng liên quan đến Cổ Thần.","nguon":["@c0710"]},{"id":"son-ha-do","name":"Sơn Hà Đồ","aliases":["bình phong Sơn Hà Đồ"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không nêu","soHuu":["Vương Lâm"],"trangThai":"hư tổn","blurb":"Chí bảo chân chính của Vũ Tiên Giới, do Tu Chân Liên Minh lấy được khi Vũ Giới sụp đổ. Hình dáng cuộn tranh sơn thủy mười vạn trượng, bên trong có một thế giới ẩn chứa hương hỏa, lai lịch khó lường. (+) Pháp bảo dạng bình phong hóa cảnh núi sông, được Vương Lâm dùng để ngăn khe nứt không gian. [CAN-SOAT-GOP]","detail":"Trong không gian trữ vật tiên nhân, Vương Lâm tung Sơn Hà Đồ lên không trung để hóa thành cảnh núi sông, tạm ngăn phần lớn khe nứt không gian cứu Lý Nguyên. Sau khi chống đỡ, pháp bảo bị chọc thủng nhiều lỗ nhỏ và rơi vào trạng thái hư tổn.","nguon":["@c0712","@c1457"],"tabs":{}},{"id":"doan-kiem-mau-den-thung-lung-thu-nhat","name":"Đoản kiếm màu đen thung lũng thứ nhất","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Nguyên"],"trangThai":"Lý Nguyên giữ","blurb":"Thanh đoản kiếm màu đen cắm giữa tám đầu lâu mãnh thú trong thung lũng thứ nhất.","detail":"Vương Lâm nhận ra thanh kiếm không tầm thường nhưng nhường cho Lý Nguyên sau khi phá cấm thung lũng thứ nhất. Hình dạng và khí tức của nó giống tám đoản kiếm ở thung lũng thứ hai, cho thấy thuộc cùng một bộ.","nguon":["@c0713"]},{"id":"tam-dau-lau-manh-thu","name":"Tám đầu lâu mãnh thú","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ","blurb":"Tám đầu lâu bao quanh đoản kiếm ở thung lũng thứ nhất.","detail":"Các đầu lâu tràn sương mù và được Vương Lâm thu lấy. Khi thần thức đảo qua, hắn chấn động trong lòng nhưng không để lộ ra ngoài.","nguon":["@c0713"]},{"id":"tam-doan-kiem-trong-thung-lung-thu-hai","name":"Tám đoản kiếm trong thung lũng thứ hai","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"Trong thung lũng thứ hai","blurb":"Tám thanh đoản kiếm cắm ở trung tâm thung lũng thứ hai.","detail":"Hình dạng và khí tức của tám kiếm giống hệt thanh đoản kiếm màu đen ở thung lũng thứ nhất, tạo thành bố cục bao quanh đầu thú bốn gai xương.","nguon":["@c0713"]},{"id":"dau-thu-bon-gai-xuong","name":"Đầu thú bốn gai xương","cn":"","category":"nguyen-lieu","categoryLabel":"Thú cốt","phamCap":"Không rõ","soHuu":[],"trangThai":"Trong thung lũng thứ hai","blurb":"Đầu thú lớn đặt giữa tám đoản kiếm trong thung lũng thứ hai.","detail":"Đầu thú có bốn gai xương dữ tợn, tỏa khí âm trầm đậm đặc và nằm tại trung tâm bố cục tám kiếm.","nguon":["@c0713"]},{"id":"giap-da-co-than","name":"Giáp da Cổ Thần","cn":"","category":"phap-bao","categoryLabel":"Di vật phòng cụ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ","blurb":"Giáp da nằm trên một bộ xương trước miếu cổ trong thung lũng thứ ba.","detail":"Vương Lâm tìm kiếm vật này trong không gian trữ vật. Khi cầm vào tay, hắn cảm nhận được khí tức bi ai máu tanh và sức mạnh còn sót lại của chủ nhân cũ.","nguon":["@c0714"]},{"id":"ngon-tay-mau-vang","name":"Ngón tay màu vàng","cn":"","category":"khac","categoryLabel":"Di vật trên hài cốt","phamCap":"Không rõ","soHuu":[],"trangThai":"Trên hài cốt trong thung lũng thứ ba","blurb":"Ngón tay phải lóe kim quang của một bộ xương trước miếu cổ.","detail":"Ngón tay kim quang cắm sâu vào đầu bộ xương mặc giáp da Cổ Thần, cho thấy hai bên từng giao chiến kịch liệt.","nguon":["@c0714"]},{"id":"qua-cau-cam-che-dieu-khien-pha-thien-cam","name":"Quả cầu cấm chế điều khiển Phá Thiên cấm","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm cấm chế","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ","blurb":"Quả cầu Lý Nguyên giao cho Vương Lâm để kích nổ các điểm sụp đổ.","detail":"Chỉ cần đưa tiên lực vào, quả cầu có thể điều khiển một ngàn bốn trăm sáu mươi lăm điểm sụp đổ trong trữ vật không gian cùng nổ.","nguon":["@c0715"]},{"id":"xuong-dau-thu","name":"Xương đầu thú","cn":"","aliases":["chín cái xương thú"],"category":"phap-bao","categoryLabel":"Pháp bảo tế luyện","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm giữ","blurb":"Bộ xương thú được Vương Lâm xem là pháp bảo trọng yếu nhất còn sót trong trữ vật không gian.","detail":"Vương Lâm liên hệ xương đầu thú với pháp bảo bị tổn hại mà Tiên nhân vô danh ghi là đang tế luyện, cho rằng đây là thu hoạch then chốt của không gian này.","nguon":["@c0715"]},{"id":"qua-cau-cam-che-giam-dieu-tich-tuyet","name":"Quả cầu cấm chế giam Diêu Tích Tuyết","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm giam cầm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Bị ném sâu vào dãy núi trong trữ vật không gian","blurb":"Quả cầu giam giữ Diêu Tích Tuyết.","detail":"Vương Lâm ném nó sâu vào một dãy núi trong trữ vật không gian, biến Diêu Tích Tuyết thành điểm then chốt trong kế hoạch đối phó Huyết Tổ.","nguon":["@c0715"]},{"id":"tui-tru-vat-cua-dieu-tich-tuyet","name":"Túi trữ vật của Diêu Tích Tuyết","cn":"","category":"khac","categoryLabel":"Vật phẩm chứa đồ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Bị Vương Lâm phong ấn","blurb":"Túi trữ vật của Diêu Tích Tuyết mà Vương Lâm không mở được.","detail":"Vương Lâm dùng cấm chế phong tỏa để khí tức lạc ấn bên trong không tản ra quá xa, đồng thời suy đoán trong đó có Huyết Hồn đan chân chính.","nguon":["@c0715"]},{"id":"tinh-the-truyen-tong-tran","name":"Tinh thể truyền tống trận","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm trận pháp","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Tiên vệ mang theo","blurb":"Truyền tống trận của Lý Nguyên được thu nhỏ thành tinh thể.","detail":"Vương Lâm thu nhỏ trận thành vật như nắm tay, sau đó để Tiên vệ nuốt vào nhằm mang theo khi đi dụ Huyết Tổ.","nguon":["@c0716"]},{"id":"hong-cham","name":"Hồng châm","cn":"","aliases":["Cây châm màu đỏ"],"category":"khac","categoryLabel":"Huyết quang công kích","phamCap":"Không rõ","soHuu":["Diêu Không"],"trangThai":"Dùng truy sát bản thể Vương Lâm","blurb":"Hồng quang ngưng tụ thành cây châm đỏ xuyên đại địa truy sát Vương Lâm.","detail":"Nếu đâm trúng, hồng châm có thể khiến nguyên thần Vương Lâm sụp đổ. Nó là biểu hiện dưới đất của huyết quang truy bản thể do Huyết Tổ phát động.","nguon":["@c0717"]},{"id":"hon-nui-da","name":"Hồn núi đá","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Vật được Vương Lâm lấy ra từ túi trữ vật để đánh vào huyết cầu Huyết Tổ.","detail":"Sau khi Vương Lâm bị đánh văng, Hứa Lập Quốc khống chế Kiếm tiên cuốn Hồn núi đá đuổi theo hắn.","nguon":["@c0719"]},{"id":"giot-mau-huyet-to","name":"Giọt máu Huyết Tổ","cn":"","category":"nguyen-lieu","categoryLabel":"Huyết thân/nguyên lực","phamCap":"Khuy Niết liên quan","soHuu":["Diêu Không","Vương Lâm"],"trangThai":"xâm nhập cơ thể Vương Lâm","blurb":"Giọt máu từ huyết thân Huyết Tổ chứa nguyên lực trời đất khổng lồ.","detail":"Một phần huyết cầu sụp đổ hóa thành giọt máu xông vào cơ thể Vương Lâm, vừa là sát cơ vừa thúc đẩy nguyên thần hắn hướng tới Âm hư.","nguon":["@c0719"]},{"id":"da-vun-tram-truong","name":"Đá vụn trăm trượng","cn":"","category":"khac","categoryLabel":"Vũ khí thô","phamCap":"không rõ","soHuu":["Vương Lâm bản tôn"],"trangThai":"đã dùng","blurb":"Các khối đá lớn trong tinh không được Vương Lâm thu gom làm vũ khí Cổ Thần.","detail":"Bản tôn dùng linh lực dẫn dắt chúng thành dòng sông đá, rồi ném liên tiếp xuống Huyết Tinh để phá màn máu phòng hộ và tàn phá mặt đất.","nguon":["@c0720"]},{"id":"tinh-do-thien-van-tu-de-lai","name":"Tinh đồ Thiên Vận tử để lại","cn":"","category":"khac","categoryLabel":"Tinh đồ","phamCap":"không rõ","soHuu":["Vương Lâm bản tôn"],"trangThai":"đang dùng","blurb":"Tinh đồ do Thiên Vận tử từng để lại, giúp Vương Lâm biết vị trí Huyết Tinh.","detail":"Nhờ từng xem tinh đồ này, bản tôn xác định được Huyết Tinh nằm hẻo lánh ngoài phạm vi Thiên Vận tinh.","nguon":["@c0720"]},{"id":"huyet-dan","name":"Huyết đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"không rõ","soHuu":["Diêu Không"],"trangThai":"đang dùng","blurb":"Đan dược Huyết Tổ dùng để nuôi luyện một số thiếu niên có tư chất thành Huyết vệ.","detail":"Huyết đan gắn với hệ thống khống chế Huyết nô và Huyết vệ trên Huyết Tinh, khiến họ sống chết phụ thuộc biến cố của Huyết Tổ.","nguon":["@c0720","@c0788"]},{"id":"huyet-cac","name":"Huyết các","cn":"","category":"khac","categoryLabel":"Kiến trúc trọng yếu","phamCap":"không rõ","soHuu":["Diêu Không","Vương Lâm bản tôn"],"trangThai":"bị Vương Lâm mang đi","blurb":"Cấm địa kỳ dị trên Huyết Tinh, vốn thuộc Huyết Tổ và ngay cả Tử Tâm cũng không được tùy tiện vào.","detail":"Tử Tâm dùng thủ pháp học lén để mở con đường đỏ trong Huyết các nhưng bị ăn mòn đến chết; sau đó Vương Lâm nhổ cả mảnh đất chứa Huyết các mang đi.","nguon":["@c0720"]},{"id":"manh-luc-dia-loi-tien-gioi","name":"Mảnh lục địa Lôi Tiên Giới","aliases":["Mảnh lục địa trôi trong hư không"],"cn":"","category":"phap-bao","categoryLabel":"Phôi pháp bảo thiên luyện","phamCap":"thiên luyện","soHuu":[],"trangThai":"đang được thiên lôi luyện hóa","blurb":"Mảnh nhỏ tiên giới trong hư không Lôi Tiên Giới, nơi Vương Lâm hôn mê và chịu Thiên Kiếp.","detail":"Dưới thiên lôi, phần rìa mảnh lục địa tan vỡ nhưng bên trong ngày càng vững chắc, dần giống một kiện pháp bảo có uy lực khó tưởng tượng; Huyết Tổ đã nảy lòng tham với vật này.","nguon":["@c0721"]},{"id":"huyet-than-cua-huyet-to","name":"Huyết Thân của Huyết Tổ","cn":"","category":"nguyen-lieu","categoryLabel":"Huyết thân/nguyên lực","phamCap":"Khuy Niết liên quan","soHuu":["Diêu Không","Vương Lâm"],"trangThai":"bi-thu-giu","blurb":"Một nửa Huyết thân của Huyết Tổ nằm sâu trong mảnh lục địa Lôi Tiên Giới và bị Vương Lâm hấp thu nguyên lực.","detail":"Dưới tác động của thiên lôi, Huyết thân cùng lực lượng lão già thần bí dung hợp, triệt tiêu trong cơ thể Vương Lâm, đồng thời đánh tan sấm sét xâm nhập.","nguon":["@c0721","@c0724"]},{"id":"ngon-nui-tien-gioi","name":"Ngọn núi tiên giới","cn":"","category":"khac","categoryLabel":"Địa vật thu giữ","phamCap":"Tiên giới","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọn núi tiên giới được Vương Lâm thu hồi trước khi trực diện Thiên Kiếp.","detail":"Khi bay khỏi mảnh lục địa, Vương Lâm thu ngọn núi tiên giới vào túi trữ vật cùng tiên kiếm, chuẩn bị đón các đạo kiếp lôi đánh xuống.","nguon":["@c0722"]},{"id":"nua-huyet-than","name":"Nửa Huyết Thân","cn":"","category":"khac","categoryLabel":"Dị vật thân thể","phamCap":"Nguồn nguyên khí của Huyết Tổ","soHuu":["Vương Lâm","Huyết Tổ"],"trangThai":"đã tự bạo","blurb":"Nửa Huyết Thân trong cơ thể Vương Lâm trở thành nguồn nguyên khí ngoài dự tính.","detail":"Dưới Thiên Kiếp, nửa Huyết Thân va chạm với khí tức lão già thần bí và kiếp lôi, sinh ra nguyên lực nồng đậm giúp Vương Lâm chống kiếp và tiến lên Âm Hư.","nguon":["@c0722","@c0741"]},{"id":"sam-set-mau-den","name":"Sấm sét màu đen","cn":"","category":"khac","categoryLabel":"Kiếp lôi","phamCap":"Thiên Kiếp","soHuu":[],"trangThai":"tieu-tan","blurb":"Sấm sét màu đen là kiếp lôi đầu tiên đánh thẳng vào Vương Lâm trong chương này.","detail":"Bốn rồi tám đạo sấm sét đen đánh vào thân Vương Lâm, kích phát các lực lượng trong cơ thể; tám đạo sau bị nguyên thần Thái Cổ Lôi Long của hắn nuốt chửng.","nguon":["@c0722"]},{"id":"sam-set-bay-mau","name":"Sấm sét bảy màu","cn":"","category":"khac","categoryLabel":"Kiếp lôi","phamCap":"Thiên Kiếp","soHuu":[],"trangThai":"dang-giang-xuong","blurb":"Sấm sét bảy màu là tầng kiếp lôi khác thường kèm ma âm câu dẫn tâm hồn.","detail":"Vương Lâm lần đầu thấy loại kiếp lôi bảy màu này; nó ngưng tụ trong tầng mây rồi đánh xuống, đi cùng âm thanh kỳ dị khiến hắn thấy nhiều bóng người quen.","nguon":["@c0722"]},{"id":"khi-tuc-lao-gia-than-bi","name":"Khí tức lão già thần bí","cn":"","category":"khac","categoryLabel":"Lực lượng ngoại lai","phamCap":"Thần bí","soHuu":["Vương Lâm"],"trangThai":"tieu-tan","blurb":"Khí tức lão già thần bí trong cơ thể Vương Lâm bị Thiên Kiếp tiêu tán hoàn toàn.","detail":"Khí tức này vốn còn lưu trong thân Vương Lâm và có thể gây ảnh hưởng lớn; khi hắn xông vào tầng mây thôn phệ sấm sét, nó bị lôi lực thanh trừ, tạo điều kiện để thân thể chỉ còn nguyên lực trước khi đột phá Dương Thực.","nguon":["@c0723"]},{"id":"thanh-kiem-do-khoi-xanh-hoa-thanh","name":"Thanh kiếm do khói xanh hóa thành","cn":"","aliases":["Thanh kiếm khói xanh"],"category":"phap-bao","categoryLabel":"Kiếm/hiện tượng tiên giới","phamCap":"Không rõ","soHuu":["Người hầu trong huyễn cảnh"],"trangThai":"đang tồn tại trong Lôi tiên giới","blurb":"Thanh kiếm do làn khói xanh hóa thành sau khi nô ấn rời khỏi Lý Nguyên. Nó mang tàn hồn nô ấn bay đi và để lại hình ảnh một thân ảnh đứng trên mũi kiếm.","detail":"Sau khi nô ấn của Lý Nguyên hiện ra và hóa thành tàn hồn, tàn hồn bay lên mũi kiếm do khói xanh biến thành. Từ đó Lôi tiên giới xuất hiện thanh kiếm khói xanh với một thân ảnh đứng trên mũi kiếm, gắn với chân tướng còn bỏ ngỏ về tiên nhân năm xưa và người đầy tớ.","nguon":["@c0710"]},{"id":"manh-vo-tien-gioi-hoa-dai-an","name":"Mảnh vỡ Tiên giới hóa đại ấn","cn":"","aliases":["Hạt cát","Đại ấn trăm trượng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Luyện từ mảnh vỡ Tiên giới, từng qua thiên kiếp trong thiên địa hỏa lô","soHuu":["Vương Lâm"],"trangThai":"Được Vương Lâm dùng để trấn áp Huyết Tổ","blurb":"Pháp bảo do Vương Lâm luyện từ mảnh vỡ Tiên giới, khi xuất hiện chỉ như hạt cát nhưng có thể hóa thành đại ấn khổng lồ. Trong trận với Huyết Tổ, nó được dùng để ép nguyên thần Huyết Tổ trở lại màn sương đen.","detail":"Vương Lâm phun ra pháp bảo này dưới dạng một hạt cát; hạt cát lập tức tỏa uy nghiêm lớn rồi bành trướng thành đại ấn trăm trượng. Khi Huyết Tổ sắp xé màn sương đen của Tôn Hồn Phiên thoát ra, đại ấn liên tục trấn áp xuống, phối hợp với Tôn Hồn Phiên, Côn Cực Tiên và các chủ hồn khiến nguyên thần Huyết Tổ gần sụp đổ và bị ép vào thế phong ấn.","nguon":["@c0725"]},{"id":"ba-dai-chu-hon","name":"Ba đại chủ hồn","cn":"","aliases":["Ba đại chủ hồn trong Tôn Hồn Phiên"],"category":"khac","categoryLabel":"Hồn trong pháp bảo","phamCap":"Chủ hồn","soHuu":["Vương Lâm"],"trangThai":"Được triệu ra công kích và kiềm chế Huyết Tổ trong Tôn Hồn Phiên","blurb":"Ba chủ hồn được Vương Lâm gọi ra từ Tôn Hồn Phiên để vây công nguyên thần Huyết Tổ. Chúng gồm Kỳ Lân hồn, hồn thứ tư và một chủ hồn hình người/hắc khí.","detail":"Trong lúc phong ấn Huyết Tổ, Vương Lâm gọi ba đại chủ hồn hiện ra từ màn sương đen. Kỳ Lân hồn cắn xé nguyên thần, hồn thứ tư xuyên qua để lấy nguyên thần khí, còn chủ hồn còn lại hóa hắc khí kiềm chế tốc độ Huyết Tổ. Dù bị Huyết Thần Băng phản kích làm tổn hại, ba chủ hồn vẫn góp phần duy trì thế phong ấn cho tới khi đại ấn và Côn Cực Tiên hoàn tất trấn áp.","nguon":["@c0725"]},{"id":"ky-lan-hon","name":"Kỳ Lân hồn","cn":"","aliases":["Chủ hồn Kỳ Lân"],"category":"khac","categoryLabel":"Chủ hồn","phamCap":"Chủ hồn trong Tôn Hồn Phiên","soHuu":["Vương Lâm"],"trangThai":"Bị Huyết Thần Băng làm tiêu tán rồi phải lui lại trong trận phong ấn Huyết Tổ","blurb":"Kỳ Lân hồn là một trong ba đại chủ hồn được Vương Lâm triệu ra từ Tôn Hồn Phiên. Nó hóa thành miệng Kỳ Lân lớn để cắn xé nguyên thần Huyết Tổ.","detail":"Khi Vương Lâm dùng Tôn Hồn Phiên vây Huyết Tổ, Kỳ Lân hồn hiện ra trong màn sương đen và lao vào cắn xé nguyên thần đối thủ. Đòn Huyết Thần Băng của Huyết Tổ khiến Kỳ Lân hồn bị đánh tan, phải lui khỏi thế công, cho thấy nó là chủ hồn mạnh nhưng vẫn bị nguyên thần Huyết Tổ suy yếu phản kích dữ dội.","nguon":["@c0725"]},{"id":"bat-dien-phe-hon-trung","name":"Bát diện Phệ hồn trùng","cn":"","aliases":[],"category":"khac","categoryLabel":"Độc trùng","phamCap":"Độc trùng tra tấn nguyên thần","soHuu":["Thanh niên Diêu gia"],"trangThai":"Ký sinh trong thân thể và nguyên thần Lý Nguyên","blurb":"Độc trùng của thanh niên Diêu gia dùng để tra tấn Lý Nguyên. Nó ký sinh trong thân thể và nguyên thần nạn nhân, vừa hành hạ vừa được dùng làm công cụ tẩm bổ.","detail":"Trong thời gian truy đuổi và tra tấn Lý Nguyên, thanh niên Diêu gia thả Bát diện Phệ hồn trùng vào thân thể và nguyên thần của hắn. Độc trùng khiến Lý Nguyên chịu đau đớn kéo dài, góp phần đẩy hắn tới cảnh gần dầu hết đèn tắt trước khi Vương Lâm phát hiện sự việc.","nguon":["@c0725"]},{"id":"pha-cam-co-kinh","name":"Phá Cấm Cổ Kính","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo của gia tộc truyền thừa tại La Thiên Tinh Vực","soHuu":[],"trangThai":"Được phía truy kích dùng để khắc chế thủ đoạn ẩn thân bằng cấm pháp của Lý Nguyên","blurb":"Pháp bảo liên quan các gia tộc truyền thừa tại La Thiên Tinh Vực, có tác dụng phá hoặc dò cấm pháp. Vì phía truy kích có Phá Cấm Cổ Kính, Lý Nguyên khó ẩn thân bằng cấm chế.","detail":"Lý Nguyên vốn dựa vào truyền thừa cấm chế của Lý gia để trốn chạy, nhưng nhóm truy kích có Phá Cấm Cổ Kính nên việc che giấu bằng cấm pháp trở nên khó khăn. Sự hiện diện của pháp bảo này khiến Phá Diệt Cấm chỉ giúp hắn kéo dài thời gian, không thể thoát hẳn khỏi sự truy sát của nhóm Diêu gia.","nguon":["@c0725"]},{"id":"kiem-tien-ly-nguyen","name":"Kiếm tiên của Lý Nguyên","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Phi kiếm của Lý Nguyên từng bị nữ tử phe truy sát chiếm giữ; sau khi nàng chết, phi kiếm cùng túi trữ vật rơi xuống đất.","detail":"Nữ tử phe truy sát Lý Nguyên đang cầm pháp bảo này khi bị Vương Lâm giết; các thanh phi kiếm văng ra rơi xuống đất cùng túi trữ vật của nàng.","nguon":["@c0726"]},{"id":"tu-mau-dao-kho","name":"Tử Mẫu Đạo Khô","cn":"","category":"phap-bao","categoryLabel":"Tiên gia pháp bảo","phamCap":"Tiên gia pháp bảo","soHuu":["Vương Lâm"],"trangThai":"đã nhận chủ, từng bị hao tổn","blurb":"Bộ Tiên gia pháp bảo gồm thú cốt và phi kiếm, được Vương Lâm luyện hóa trong Lôi chi Tiên giới.","detail":"Tử Mẫu Đạo Khô gồm chín thú cốt và chín thanh phi kiếm, từng bị tổn hại sau trận chiến giữa chủ nhân cũ và Cổ Thần. Vương Lâm dùng nguyên thần Thái Cổ Lôi Long phá cấm chế kiếm khí, lưu thần thức vào thú cốt lớn, nhận chủ và thu nó thành đồ án thú cốt trên mu bàn tay phải; hắn đánh giá đây là một trong các pháp bảo mạnh nhất mình đang có.","nguon":["@c0727"]},{"id":"nguyen-luc-cau","name":"Nguyên lực cầu","cn":"","category":"khac","categoryLabel":"Vật phẩm nguyên lực","phamCap":"không rõ","soHuu":["Vương Lâm","Lý Nguyên"],"trangThai":"đã dùng để tẩm bổ nguyên thần Lý Nguyên","blurb":"Khối nguyên lực được Vương Lâm luyện từ nguyên thần Sửu thúc sau khi sưu hồn.","detail":"Vương Lâm hủy thần thức nguyên thần Sửu thúc rồi nhào nặn thành nguyên lực cầu, đặt vào mi tâm Lý Nguyên để tẩm bổ nguyên thần và tạo cơ hội đột phá Âm Hư.","nguon":["@c0727"]},{"id":"chin-thanh-phi-kiem","name":"Chín thanh phi kiếm","aliases":["Chín thanh tiên kiếm","Kiếm tiên của Lý Nguyên"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi kiếm","phamCap":"không rõ","soHuu":["Lý Nguyên"],"trangThai":"đã trả lại cho Lý Nguyên","blurb":"Chín thanh phi kiếm từng được lấy từ không gian trữ vật của Tiên nhân, là một phần trong bố cục luyện hóa Tử Mẫu Đạo Khô.","detail":"Vương Lâm bày chín thanh phi kiếm cùng chín thú cốt đúng hình thế ban đầu để phá cấm và luyện hóa Tử Mẫu Đạo Khô. Sau khi xong việc, hắn trả lại chín kiếm tiên cho Lý Nguyên.","nguon":["@c0727"]},{"id":"chin-thu-cot","name":"Chín thú cốt","cn":"","category":"phap-bao","categoryLabel":"Bộ phận pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"hợp thành Tử Mẫu Đạo Khô","blurb":"Tám thú cốt nhỏ và một thú cốt lớn tạo thành bộ phận then chốt của Tử Mẫu Đạo Khô.","detail":"Chín thú cốt hút nguyên thần Vương Lâm qua nhiều tầng chuyển hóa, kết hợp với chín phi kiếm và cấm chế kiếm khí để mở ra phương pháp nhận chủ Tử Mẫu Đạo Khô. Sau khi luyện hóa, bộ thú cốt biến thành đồ án trên mu bàn tay phải Vương Lâm.","nguon":["@c0727"]},{"id":"chi-phu","name":"Chỉ phù","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang giữ","blurb":"Vật phẩm bí ẩn xuất hiện lần thứ hai trong tay Vương Lâm tại La Thiên Tinh Vực.","detail":"Vương Lâm tìm được một tờ Chỉ phù trong túi trữ vật Thiếu chủ Diêu gia, đem so với tờ đã có và phát hiện cả hai có dao động nguyên lực rất nhỏ, khiến hắn cảm thấy vật này không tầm thường.","nguon":["@c0727"]},{"id":"thu-cot","name":"Thú cốt","cn":"","aliases":["Bộ xương thú trên mu bàn tay","Thú Cốt","Đồ án thú cốt trên lưng bàn tay"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Pháp bảo từ đồ án trên lưng bàn tay Vương Lâm hiện ra, có u hỏa trong hốc mắt và sát khí mạnh.","detail":"Khi Đường Ngôn Vân thi triển Nguyên long thôn, Thú cốt hiện từ lưng bàn tay Vương Lâm, phóng sát khí cùng u hỏa, hóa đá hắc long nghìn trượng thành thạch điêu màu xám. Sau đó Vương Lâm thu nó trở lại đồ án trên tay, còn quần tu bên ngoài vì chứng kiến uy lực này mà coi phạm vi nghìn trượng như cấm địa tử vong.","nguon":["@c0729","@c0814","@c0844"]},{"id":"bao-vat-phia-duoi-hac-dong","name":"Bảo vật phía dưới hắc động","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Lý Nguyên"],"trangThai":"đã bị đoạt lấy","blurb":"Vật phẩm nằm phía dưới hắc động và được Lý Nguyên đoạt được. Chương này chưa nêu tên thật, phẩm cấp hay công dụng của bảo vật.","detail":"Sau khi từ hắc động xông ra, Lý Nguyên báo với Vương Lâm rằng bảo vật phía dưới đã bị hắn đoạt được. Cùng lúc đó hắn còn phát hiện một thông đạo bí mật chưa rõ dẫn tới nơi nào, nên bảo vật này gắn với khu vực sâu bên dưới hắc động trong Lôi chi Tiên giới.","nguon":["@c0730"]},{"id":"ba-bao-boi-ky-quai-trong-hang-dong","name":"Ba bảo bối kỳ quái trong hang động","cn":"","category":"khac","categoryLabel":"Bảo vật","phamCap":"Không rõ","soHuu":["Lý Nguyên"],"trangThai":"chưa lấy ra","blurb":"Ba bảo bối kỳ quái Lý Nguyên từng phát hiện trong hang động dưới cấm chế.","detail":"Lý Nguyên nói bên trong hang động có ba loại bảo bối kỳ quái đã được hắn phát hiện từ trước. Hắn dự định sau khi đi tiếp sẽ lấy ra để cùng Vương Lâm phân tích, nhưng chương này chưa nêu hình dạng hay công dụng cụ thể.","nguon":["@c0731"]},{"id":"tia-cuc-canh-trong-nguyen-than-vuong-lam","name":"Tia Cực Cảnh trong nguyên thần Vương Lâm","cn":"","category":"khac","categoryLabel":"Bảo mệnh thủ đoạn","phamCap":"Cực Cảnh","soHuu":["Vương Lâm"],"trangThai":"Được giữ trong nguyên thần","blurb":"Một tia Cực Cảnh được Vương Lâm giữ lại thay vì thanh trừ.","detail":"Sau khi tỉnh lại, Vương Lâm nhận ra có thể bức tia chớp đỏ Cực Cảnh ra khỏi cơ thể, nhưng cho rằng thanh trừ như vậy quá đáng tiếc. Hắn dùng nguyên lực bao vây nó trong nguyên thần, dự định để lại làm thủ đoạn bảo mệnh vào thời điểm mấu chốt.","nguon":["@c0733"]},{"id":"trong-bao-tai-cac-manh-vo-dao-dong-tien-luc","name":"Trọng bảo tại các mảnh vỡ dao động tiên lực","cn":"","category":"khac","categoryLabel":"Bảo vật chưa lộ","phamCap":"Chưa rõ","soHuu":[],"trangThai":"Chưa xuất thế","blurb":"Các trọng bảo được đồn sẽ xuất hiện sau khi phong ấn trên những mảnh vỡ dao động tiên lực bị phá.","detail":"Chiến Không Liệt cho biết nhiều mảnh vỡ trong Lôi Tiên Giới phát ra dao động tiên lực nồng đậm, bên ngoài có cấm chế phong ấn bảo vệ. Một khi phong ấn bị phá giải, trọng bảo sẽ xuất hiện, khiến nhiều tu sĩ và gia tộc đổ tới tranh đoạt.","nguon":["@c0733"]},{"id":"tien-thuat-trong-tang-pham-cac","name":"Tiên thuật trong Tàng Phẩm Các","cn":"","category":"khac","categoryLabel":"Tri thức tiên thuật","phamCap":"Tiên thuật","soHuu":[],"trangThai":"Ẩn trong Tàng Phẩm Các","blurb":"Tiên thuật mà Vương Lâm tin chắc có trong Tàng Phẩm Các.","detail":"Từ ký ức lão già Diêu gia, Vương Lâm biết Tàng Phẩm Các là nơi đáng tới và cho rằng bên trong chắc chắn có tiên thuật. Vì vậy hắn tạm gác việc tìm tiên phủ rải rác, cùng Lý Nguyên chuyển hướng tới nơi này.","nguon":["@c0733"]},{"id":"phi-kiem-mau-do-thu-ve","name":"Phi kiếm màu đỏ","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ áo đen thủ vệ Tàng Phẩm Các"],"trangThai":"dang-co","blurb":"Phi kiếm màu đỏ của tu sĩ áo đen lấy từ túi trữ vật, dùng để lao thẳng đến Vương Lâm.","detail":"Tu sĩ áo đen lấy phi kiếm đỏ từ túi trữ vật, dùng để lao thẳng đến Vương Lâm, nhưng bị Định Thân Thuật làm ngừng lại cùng chủ nhân.","nguon":["@c0734"]},{"id":"bao-thap","name":"Bảo tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo dạng vật chứa của Vương Lâm, dùng để cất nữ thi áo trắng. Trong Tàng Phẩm Các, nó được lấy ra để thả nữ thi giúp vượt kiểm tra tư cách.","detail":"Khi người sương mù của Tàng Phẩm Các sắp tan đi sau khi phán Vương Lâm là Bát Phẩm Thượng Tiên, Vương Lâm lấy bảo tháp ra và thả nữ thi áo trắng. Nhờ điều khiển nàng chạm vào người sương mù, kết quả kiểm tra chuyển thành Cửu phẩm tiên quân, cho phép lên tầng chín.","nguon":["@c0735"]},{"id":"tien-ngoc-trong-o-go-tang-chin","name":"Tiên ngọc trong ô gỗ tầng chín","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"trong Tàng Phẩm Các","blurb":"Hơn mười viên tiên ngọc đặt trong các ô gỗ ở tầng chín Tàng Phẩm Các. Chúng tỏa ánh sáng dịu trong gian lầu các nhỏ.","detail":"Khi lên tầng chín, Vương Lâm thấy hơn mười ô vuông bằng gỗ, trong mỗi ô có tiên ngọc phát ra ánh sáng dịu dàng. Chúng nằm cùng không gian với bức họa cây và đồng tử, gắn với cơ duyên tiên thuật tầng chín.","nguon":["@c0735"]},{"id":"buc-hoa-cay-va-dong-tu","name":"Bức họa cây và đồng tử","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"trong Tàng Phẩm Các","blurb":"Bức họa treo trên vách tầng chín Tàng Phẩm Các, vẽ một cái cây, lá khô vàng một bên và đồng tử khoanh chân dưới tán. Trên tranh có câu thơ gợi nhiều thần thông bí ẩn.","detail":"Ở tầng chín, Vương Lâm thấy bức họa trên vách vẽ cây, đồng tử khoanh chân và câu thơ nhắc Hô phong hoán vũ, Tát đậu thành binh, Địa liệt sơn băng, Âm nguyệt hữu tình. Đây là manh mối quan trọng khiến hắn suy xét ý nghĩa các tiên thuật tầng chín.","nguon":["@c0735"]},{"id":"bo-doan-da","name":"Bồ đoàn đá","cn":"","category":"khac","categoryLabel":"Vật phẩm hư ảnh","phamCap":"không rõ","soHuu":[],"trangThai":"hư ảnh","blurb":"Bồ đoàn đá nằm trên mặt đất tầng chín Tàng Phẩm Các, có dấu lõm như từng có người ngồi lâu năm. Khi Vương Lâm chạm vào, tay xuyên qua, cho thấy nó chỉ là hư ảnh.","detail":"Trong căn phòng tầng chín, Vương Lâm kiểm tra bồ đoàn đá và nhận ra vật này không có thực thể. Phát hiện ấy khiến hắn hiểu rằng thu hoạch hữu hình ở tầng chín không dễ đạt được, từ đó chuyển sự chú ý sang bức họa.","nguon":["@c0736"]},{"id":"tang-pham-cac-bao-vat","name":"Tàng Phẩm Các","cn":"","category":"phap-bao","categoryLabel":"Lầu các/bảo vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"bị thu lấy","blurb":"Lầu các chứa tiên thuật tầng chín, được Vương Lâm thu nhỏ và mang đi sau khi rời quang môn.","detail":"Tàng Phẩm Các là lầu các nơi cất giữ tiên thuật tầng thứ chín. Vương Lâm ban đầu tiếc vì tưởng không thể mang đi, sau đó nhớ thủ ấn của đồng tử trong bức tranh, thi triển khiến lầu các thu nhỏ bằng lòng bàn tay và rơi vào tay hắn.","nguon":["@c0737"]},{"id":"ngan-cham-lam-quang-cua-tu-si-ho-tran","name":"Ngân châm lam quang của tu sĩ họ Trần","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ họ Trần"],"trangThai":"bị phá hủy","blurb":"Cụm ngân châm lóe lam quang được tu sĩ họ Trần dùng khi đánh úp Vương Lâm.","detail":"Tu sĩ họ Trần xuất ra cụm ngân châm, mỗi chiếc lóe lam quang, nhằm công kích Vương Lâm từ phía sau. Khi chạm vào Hô Phong, các ngân châm lập tức vỡ vụn.","nguon":["@c0737"]},{"id":"cay-quat-nho-phat-tinh-quang-cua-tu-si-ho-lu","name":"Cây quạt nhỏ phát tinh quang của tu sĩ họ Lữ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo nguyên thần","phamCap":"Không rõ","soHuu":["Tu sĩ họ Lữ"],"trangThai":"bị phá hủy","blurb":"Pháp bảo nguyên thần của tu sĩ họ Lữ, dùng để hóa sáu hỏa long màu tím.","detail":"Tu sĩ họ Lữ phun ra cây quạt nhỏ phát tinh quang, dùng tinh khí nguyên thần khiến nó hóa thành sáu hỏa long vây Vương Lâm. Hô Phong thổi qua làm pháp bảo này tan vỡ.","nguon":["@c0737"]},{"id":"ba-giot-mau-hoa-da","name":"Ba giọt máu hóa đá","cn":"","category":"khac","categoryLabel":"Chiến lợi phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm thu giữ","blurb":"Ba giọt máu hóa đá là ba giọt máu đỏ sậm từ thế công của cánh tay cụt. Chúng bị thú cốt trên tay Vương Lâm hóa đá và được hắn thu vào túi trữ vật.","detail":"Khi Vương Lâm dùng con mắt thứ ba khiến năm vết rách trở về căn nguyên thành năm giọt máu đỏ sậm, hắn tiếp tục dùng Định và thú cốt trên mu bàn tay phải. Ba trong năm giọt máu hóa đá, sau đó được Vương Lâm thu vào túi trữ vật.","nguon":["@c0739"]},{"id":"dinh-bang-dong-cua-chien-khong-liet","name":"Đỉnh bằng đồng của Chiến Không Liệt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang dùng","blurb":"Một chiếc đỉnh bằng đồng mang sát khí mãnh liệt của Chiến Không Liệt. Nó được lấy ra trong trận vây công quái nhân tóc bạc.","detail":"Chiến Không Liệt lấy đỉnh đồng khi dẫn nhóm tu sĩ Âm Hư lao vào vây công. Pháp bảo mang sát khí mạnh, cùng thần thông và pháp bảo của các tu sĩ khác đánh về phía quái nhân tóc bạc.","nguon":["@c0740"]},{"id":"phi-kiem-cua-than-cong-ho","name":"Phi kiếm của Thân Công Hổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"hư hỏng","blurb":"Phi kiếm mang lôi quang nồng đậm của Thân Công Hổ. Nó đánh lên màn sáng đỏ của quái nhân tóc bạc nhưng bị chấn vỡ.","detail":"Thân Công Hổ dùng phi kiếm chứa lôi uy công kích quái nhân tóc bạc trong trận vây công. Phi kiếm va vào màn sáng đỏ, bị phản chấn dữ dội rồi tan vỡ.","nguon":["@c0740"]},{"id":"tia-chop-mau-do","name":"Tia chớp màu đỏ","cn":"","category":"khac","categoryLabel":"Vật chưa rõ","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"không rõ","blurb":"Tia chớp màu đỏ là vật hoặc lực lượng Vương Lâm phóng ra khi bị quái nhân tóc bạc truy kích.","detail":"Trong lúc lui lại, Vương Lâm phóng tia chớp màu đỏ để ứng biến; quái nhân tóc bạc lập tức đổi hướng đuổi theo, chụp lấy và quan sát, cho thấy vật này có thể gây chú ý trong giao thủ.","nguon":["@c0741"]},{"id":"thanh-suong-tien-kiem","name":"Thanh Sương tiên kiếm","cn":"","category":"phap-bao","categoryLabel":"Tiên kiếm","phamCap":"tiên kiếm","soHuu":["Thanh Sương"],"trangThai":"khong-ro","blurb":"Tiên kiếm được Thanh Thủy nhắc tới khi đánh giá các thủ đoạn bên phía Vương Lâm.","detail":"Thanh Sương tiên kiếm được đặt cùng Bạch Phàm tiên thuật và pháp bảo của Tiêu Dao Tử trong lời đánh giá của Thanh Thủy về đối thủ sau khi hắn thoát khỏi pho tượng đen.","nguon":["@c0742"]},{"id":"phap-bao-cua-tieu-dao-tu","name":"Pháp bảo của Tiêu Dao Tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tiêu Dao Tử"],"trangThai":"khong-ro","blurb":"Pháp bảo của Tiêu Dao Tử được Thanh Thủy nhắc tới trong lúc nhận diện các thủ đoạn của Vương Lâm.","detail":"Thanh Thủy tiên quân xem pháp bảo của Tiêu Dao Tử là một trong những bảo vật, thủ đoạn đáng chú ý mà phía Vương Lâm đang sở hữu trong trận giao chiến.","nguon":["@c0742"]},{"id":"truong-thuong-mau-den","name":"Trường thương màu đen","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"","soHuu":["Thanh Thủy"],"trangThai":"hong","blurb":"Vũ khí do pho tượng đen tan biến mà thành trong tay Thanh Thủy tiên quân.","detail":"Sau khi bước ra khỏi pho tượng đen, Thanh Thủy vỗ tượng khiến nó tan biến thành trường thương màu đen. Hắn dùng trường thương dẫn hồng mang đối kháng bạch cầu thiên địa, rồi chủ động làm vỡ thương thành vô số mảnh nhỏ vờn quanh thân.","nguon":["@c0742"]},{"id":"pho-tuong-cua-quai-nhan-toc-bac","name":"Pho tượng của quái nhân tóc bạc","cn":"","category":"khac","categoryLabel":"Vật dẫn biến hóa","phamCap":"không rõ","soHuu":["Quái nhân tóc bạc"],"trangThai":"vỡ hóa thành trường thương @c0743","blurb":"Vật dẫn kỳ dị giúp quái nhân tóc bạc nhiều lần thoát nguy và trẻ hóa sau mỗi lần thoát ra.","detail":"Sau mỗi lần gặp nguy cơ, quái nhân tóc bạc lại hình thành pho tượng; khi phá tượng thoát ra, hình dạng của hắn trẻ hơn, từ lão giả thành trung niên rồi tới thanh niên. Ở chương 743, pho tượng vỡ ra và hóa thành trường thương trong tay hắn.","nguon":["@c0743"]},{"id":"truong-thuong-cua-thanh-nien-ta-khi","name":"Trường thương của thanh niên tà khí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo vũ khí","phamCap":"không rõ","soHuu":["Quái nhân tóc bạc"],"trangThai":"đang dùng @c0743","blurb":"Trường thương do pho tượng vỡ hóa thành, được thanh niên tà khí dùng trong lúc thôn phệ và công kích.","detail":"Khi pho tượng vỡ, nó hóa thành một cây trường thương trong tay thanh niên tà khí. Hắn dùng trường thương ép tu sĩ Âm Hư hiện thân, sau đó còn ném thành luồng sáng đen công kích thân thể Vương Lâm do lão giả điều khiển.","nguon":["@c0743"]},{"id":"tam-binh-phong","name":"Tấm bình phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dùng","blurb":"Tấm bình phong là vật Vương Lâm lấy ra từ túi trữ vật để triển khai Sơn Hà Đồ trong lúc chống lại thanh niên đầy tà khí.","detail":"Khi mảnh vỡ đại ấn phải gánh công kích của quang cầu đỏ, Vương Lâm lấy tấm bình phong ra để mở Sơn Hà Đồ. Cảnh non nước đen trắng từ đó bao phủ bốn phía, dẫn lực núi sông vào đại ấn nhằm triệt tiêu sức công kích.","nguon":["@c0744"]},{"id":"loi-tien-gioi-luyen-hoa-thanh-phap-bao","name":"Lôi Tiên Giới luyện hóa thành pháp bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo đang hình thành","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"dang-hinh-thanh","blurb":"Pháp bảo mà Viêm Lôi Tử muốn luyện từ một nửa Lôi Tiên Giới. Mục tiêu của hắn là dùng vật này mở vách ngăn không gian để tu sĩ La Thiên Tinh Vực tự do tiến vào Liên Minh Tinh Vực.","detail":"Viêm Lôi Tử tuyên bố đã chuẩn bị hàng vạn năm, kích hoạt bốn mươi chín mảnh vỡ đại lục và dùng pháp linh dung nhập từng mảnh để luyện hóa Lôi Tiên Giới. Nếu thành công, pháp bảo này sẽ mở ra vách ngăn không gian, khiến La Thiên Tinh Vực không cần dựa vào La Thiên Thạch khi tiến vào Liên Minh Tinh Vực.","nguon":["@c0745"]},{"id":"phap-linh","name":"Pháp linh","cn":"","category":"khac","categoryLabel":"Linh thể pháp bảo","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"dang-duoc-dung","blurb":"Các nguyên thần được Viêm Lôi Tử đưa vào mảnh vỡ đại lục để làm linh cho pháp bảo đang luyện hóa. Trong chương này gồm nhiều nguyên thần Âm Hư và một nguyên thần Dương Thực xuất hiện từ mảnh kính cũ.","detail":"Pháp linh là yếu tố mà thanh niên đầy tà khí cho rằng cần thiết để luyện hóa Lôi Tiên Giới thành pháp bảo. Viêm Lôi Tử dùng mảnh kính cũ phóng ra nguyên thần, sai chúng dung nhập vào mảnh vỡ đại lục; khi mảnh vỡ có pháp bảo chi linh, linh tính của chúng tăng lên và trở thành bộ phận trong đại trận luyện hóa.","nguon":["@c0745"]},{"id":"bon-muoi-chin-manh-vo-dai-luc","name":"Bốn mươi chín mảnh vỡ đại lục","cn":"","category":"phap-bao","categoryLabel":"Vật dẫn trận","phamCap":"Lôi Tiên Giới luyện hóa","soHuu":["Viêm Lôi Tử"],"trangThai":"đang dùng","blurb":"Bốn mươi chín mảnh vỡ đại lục được Viêm Lôi Tử dùng làm nền của Tiên Giới Đại Trận. Sau khi thu trận, chúng co thành các mảnh nhỏ bằng bàn tay quanh hắn.","detail":"Các mảnh vỡ đại lục là vật dẫn tạo thành trận pháp tuyệt luân, mỗi mảnh được tăng linh tính nhờ nguyên thần quy vị. Khi Viêm Lôi Tử thu hồi đại trận, bốn mươi chín mảnh vỡ thu nhỏ và xoay quanh bản thể, thể hiện chúng đã bị hắn luyện hóa sâu trong Lôi Tiên Giới.","nguon":["@c0746"]},{"id":"phap-bao-loc-xoay-phong-an-cua-thanh-thuy","name":"Pháp bảo lốc xoáy phong ấn của Thanh Thủy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thanh Thủy"],"trangThai":"đã dùng phong ấn","blurb":"Pháp bảo Thanh Thủy dùng để tự phong ấn nguyên thần và thân thể thành chín phần sau khi tự sát.","detail":"Sau khi tỉnh lại từ sát nghiệp và sợ Cực Cảnh khiến mình sống lại, Thanh Thủy dùng pháp bảo lốc xoáy để phong ấn toàn bộ nguyên thần cùng thân thể thành chín phần.","nguon":["@c0747"]},{"id":"tien-gian-cua-thanh-thuy","name":"Tiên ngọc / tiên giản của Thanh Thủy","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Thanh Thủy","Tiên Đế Bạch Phàm","Viêm Lôi Tử"],"trangThai":"đã bị Thanh Thủy nuốt","blurb":"Vật cũ do Bạch Phàm để lại, được Viêm Lôi Tử giao cho Thanh Thủy để giúp nhớ chuyện xưa.","detail":"Viêm Lôi Tử lấy tiên ngọc cũ do Bạch Phàm để lại từ túi trữ vật và giao cho Thanh Thủy. Thanh Thủy nhận lấy, nuốt vào miệng rồi bùng phát huyết quang cùng sát ý dữ tợn.","nguon":["@c0747"]},{"id":"doan-sung-tu-kim","name":"Đoạn sừng tử kim","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Đoạn sừng màu tử kim dài ba tấc do Viêm Lôi Tử trao Vương Lâm làm tín vật.","detail":"Viêm Lôi Tử vỗ túi trữ vật lấy ra đoạn sừng tử kim ném cho Vương Lâm làm tín vật, đặt điều kiện nếu Vương Lâm tự rời Lôi tiên giới và trong một năm tới Lôi Tiên Điện thì có cơ hội cùng đi Liên Minh Tinh Vực. Vương Lâm thu đoạn sừng vào túi trữ vật trước khi rời đi.","nguon":["@c0748"]},{"id":"quyen-truc-tu-chan-lien-minh","name":"Quyển trục Tu Chân Liên Minh","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":[],"trangThai":"dang-co","blurb":"Quyển trục bí ẩn trong Tu Chân Liên Minh mang khí tức viễn cổ tiên vực, được đồn ghi nguyên nhân tiên giới sụp đổ.","detail":"Viêm Lôi Tử nói quyển trục rơi xuống sau khi tiên giới sụp đổ, tỏa khí tức viễn cổ tiên vực, chưa ai mở được, và được đồn ghi lại nguyên nhân bí ẩn chính thức khiến tiên giới sụp đổ, có liên quan tới kinh biến của Thanh Thủy năm xưa.","nguon":["@c0748"]},{"id":"tui-tru-vat-cua-chien-van","name":"Túi trữ vật của Chiến Vân","cn":"","category":"khac","categoryLabel":"Vật phẩm chứa đồ","phamCap":"không rõ","soHuu":["Chiến Vân"],"trangThai":"đang tồn tại","blurb":"Túi trữ vật của Chiến Vân chứa khoảng năm vạn tiên ngọc trong lúc nàng được Vương Lâm cứu khỏi khe nứt không gian.","detail":"Sau khi Vương Lâm đòi tiên ngọc làm giá cứu mạng và cho phép trú lại trên mảnh đại lục, Chiến Vân ném túi trữ vật cho hắn. Vương Lâm xóa thần thức của nàng, kiểm tra bên trong có khoảng năm vạn tiên ngọc rồi thu lấy.","nguon":["@c0749"]},{"id":"day-to-tam-mau-hong","name":"Dây tơ tằm màu hồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phụ trợ","phamCap":"không rõ","soHuu":["Chiến Vân"],"trangThai":"đang tồn tại","blurb":"Dây tơ tằm màu hồng là vật Chiến Vân dùng để tiếp ứng Tây Tử Phượng và hai tu sĩ đi cùng trong Lôi Tiên Giới sụp đổ.","detail":"Khi Vương Lâm không dừng mảnh đại lục cho nhóm Tây Tử Phượng lên, Chiến Vân tự vỗ túi trữ vật, lấy ra dây tơ tằm màu hồng và phóng về phía ba người đang đuổi theo mảnh đại lục hơn trăm trượng.","nguon":["@c0749"]},{"id":"manh-nho-tram-truong","name":"Mảnh nhỏ trăm trượng","cn":"","category":"phap-bao","categoryLabel":"Mảnh nhỏ tiên giới","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh nhỏ trăm trượng là phương tiện Vương Lâm dùng để lao qua Lôi Tiên Giới. Nó trở thành sinh lộ cho nhiều tu sĩ và là mục tiêu bị ba tu sĩ Dương Thực tranh đoạt.","detail":"Mảnh nhỏ chở Vương Lâm, Chiến Vân, Tây Tử Phượng và ngày càng nhiều tu sĩ vượt qua các khe không gian trong Lôi Tiên Giới. Vì từng được thiên kiếp luyện hóa nên nó bền hơn tảng đá ngàn trượng của nhóm Dương Thực, có thể mở ra con đường an toàn tương đối, khiến các tu sĩ phía sau tụ thành đội ngũ đi theo.","nguon":["@c0750","@c0751"]},{"id":"tang-da-ngan-truong","name":"Tảng đá ngàn trượng","cn":"","category":"khac","categoryLabel":"Vật chở tạm","phamCap":"không rõ","soHuu":["Nam tử kim bào","Lão giả bạch y","Văn sĩ áo lam"],"trangThai":"hư hại dần","blurb":"Tảng đá ngàn trượng là vật chở nhóm ba tu sĩ Dương Thực cùng gần trăm tu sĩ trong Lôi Tiên Giới. Do không được thiên kiếp luyện hóa, nó liên tục vỡ vụn khi đi qua khe không gian.","detail":"Nhóm nam tử kim bào, lão giả bạch y và văn sĩ áo lam dùng tảng đá lớn làm phương tiện tương tự mảnh nhỏ của Vương Lâm. Khi nhận ra mảnh nhỏ trăm trượng bền hơn và an toàn hơn, họ sinh lòng tranh đoạt, chặn đường yêu cầu Vương Lâm lưu lại mảnh nhỏ tiên giới.","nguon":["@c0750"]},{"id":"thanh-kiem-hu-ao","name":"Thanh kiếm hư ảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo hoặc thần thông kiếm","phamCap":"không rõ","soHuu":["Văn sĩ áo lam"],"trangThai":"bị phá hủy","blurb":"Thanh kiếm hư ảo được văn sĩ áo lam phóng ra từ Thiên Linh Cái để đánh Vương Lâm. Nó bị hồng mang từ con mắt thứ ba của Vương Lâm bao phủ rồi tan vỡ trong hắc khí.","detail":"Khi văn sĩ áo lam lao tới cứu viện, thanh kiếm hư ảo như thuấn di đâm thẳng về phía Vương Lâm. Vương Lâm mở con mắt thứ ba, phóng hồng mang bao trùm thanh kiếm, khiến kiếm toát ra hắc khí và nhanh chóng tan tành.","nguon":["@c0750"]},{"id":"khoa-mau-vang","name":"Khóa màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm","Sáu sứ giả Lôi Tiên điện"],"trangThai":"Vương Lâm đoạt và luyện hóa","blurb":"Pháp bảo hình khóa màu vàng của sứ giả Lôi Tiên điện, dùng để thi triển Khóa nguyên, phong thần.","detail":"Sứ giả Lôi Tiên điện phun khóa vàng cùng tinh huyết nguyên thần để thi triển Khóa nguyên, phong thần. Sau khi thần thông bị gió đen hóa rồng phá tan, Vương Lâm thu khóa vào tay, nuốt xuống và dùng lôi nguyên thần luyện hóa.","nguon":["@c0753"]},{"id":"ba-la-co-nho","name":"Ba lá cờ nhỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm","Sáu sứ giả Lôi Tiên điện"],"trangThai":"Vương Lâm thu giữ","blurb":"Ba lá tiểu kỳ tạo khí tím bảo hộ thân thể và nguyên thần của sứ giả Lôi Tiên điện.","detail":"Một sứ giả Lôi Tiên điện lấy ba lá cờ nhỏ từ túi trữ vật, tạo dòng xoáy khí tím bao phủ bảo vệ. Vương Lâm dùng khí nguyên thần hóa cấm chế phong ấn ba lá cờ rồi thu vào túi trữ vật.","nguon":["@c0753"]},{"id":"nhan-qua-con-cuc-tien","name":"Nhân Quả Côn Cực Tiên","cn":"","aliases":["Côn Cực Tiên","Côn Cực tiên"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Pháp bảo được Vương Lâm gọi ra để trấn áp nguyên thần sứ giả Lôi Tiên điện.","detail":"Khi nguyên thần sứ giả Lôi Tiên điện định cầu xin sau khi thân thể bị phá, Vương Lâm gọi Côn Cực tiên ra, khiến nguyên thần kêu thảm rồi bị hắn chộp lấy.","nguon":["@c0753"]},{"id":"truong-kiem-ao-anh-co-tua-kiem","name":"Trường kiếm ảo ảnh có tua kiếm","cn":"","aliases":["Bóng kiếm ảo ảnh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Bóng người trên mũi kiếm ảo ảnh"],"trangThai":"không rõ","blurb":"Bóng kiếm xuất hiện trong Lôi Tiên Giới đã bị băng phong, có tua kiếm và không bị lớp băng ảnh hưởng. Trên mũi kiếm có một bóng người ảo ảnh đứng rồi cùng kiếm quang biến mất.","detail":"Khi Lôi Tiên Giới gần như hóa thành khối băng đen, một bóng kiếm lướt qua bên trong mà không chịu ảnh hưởng từ lớp băng. Trên mũi kiếm có thân ảnh như ảo ảnh, bình tĩnh nhìn phía trước mỉm cười; sau đó kiếm quang lóe lên và cả bóng người lẫn bóng kiếm biến mất.","nguon":["@c0754"]},{"id":"huyen-am-dinh","name":"Huyền Âm đỉnh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":[],"trangThai":"hong","blurb":"Vật được lão nhân Tiên Di tộc chủ động nhắc tới khi tiếp đón Vương Lâm. Lão hỏi Vương Lâm lần này tới đây có phải vì Huyền Âm đỉnh hay không, cho thấy nó có liên hệ quan trọng với nơi ở của Tiên Di tộc.","detail":"Sau khi nhận ra Tử Mẫu Đạo Khô trên tay phải Vương Lâm và suy đoán hắn là người thân cận bên cạnh Tiêu Dao tiên vương, lão nhân Tiên Di tộc hỏi chuyến tới đây có phải vì Huyền Âm đỉnh hay không. Công dụng, cấp bậc và tình trạng của Huyền Âm đỉnh chưa được làm rõ trong chương này.","nguon":["@c0755","@c0766"]},{"id":"phap-khi-hinh-voi-am-dai","name":"Pháp khí hình vòi ấm dài","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Nam tử áo vải Tiên Di tộc"],"trangThai":"dang-co","blurb":"Pháp khí kỳ quái do nam tử áo vải Tiên Di tộc cầm khi xuất hiện trên đại lục lơ lửng. Hình dáng giống vòi ấm rất dài, kích thước lớn hơn nhiều và cao hơn nửa người.","detail":"Vật này xuất hiện trong tay nam tử áo vải Tiên Di tộc khi Vương Lâm vừa tới vùng đại lục lơ lửng. Chương này chỉ mô tả hình dạng kỳ quái giống vòi ấm dài, chưa nêu công dụng hay phẩm cấp.","nguon":["@c0755"]},{"id":"linh-tien-qua","name":"Linh Tiên quả","cn":"","category":"nguyen-lieu","categoryLabel":"Linh quả","phamCap":"Không rõ","soHuu":["Tiên Di tộc"],"trangThai":"da-chin","blurb":"Linh quả trong khu vực Tiên Di tộc, được lão nhân tóc bạc nói là đã chín từ lâu. Lão định sai người mang tới cho Vương Lâm nếm thử khi mời hắn vào đại lục.","detail":"Linh Tiên quả được nhắc tới sau khi lão nhân Tiên Di tộc nhận định Vương Lâm là người thân cận của Tiêu Dao tiên vương. Việc quả đã chín từ lâu cho thấy trong đại lục lơ lửng có tài nguyên đặc thù được Tiên Di tộc gìn giữ.","nguon":["@c0755"]},{"id":"manh-dat-nho-tien-gioi","name":"Mảnh đất nhỏ tiên giới","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Mang tiên lực","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật phẩm do Vương Lâm phun ra từ một hạt cát, hóa thành mảnh đất trăm trượng mang tiên lực mạnh.","detail":"Trong trận với Tháp Sơn, Vương Lâm lần đầu đưa mảnh đất nhỏ nơi tiên giới xuất hiện trên thế gian. Nó cứng rắn đến mức quyền lực của Tháp Sơn không thể lay chuyển, còn cú nện xuống của nó khiến toàn đại lục rung chuyển, nứt ra và phun sương đen sinh ra Vụ thú.","nguon":["@c0757"]},{"id":"linh-giap-do-tien-ban-thuong","name":"Linh giáp do tiên ban thưởng","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Áo giáp","phamCap":"Tiên ban thưởng","soHuu":["Tháp Sơn"],"trangThai":"dang-co","blurb":"Bộ giáp đen do ký hiệu trên thân Tháp Sơn tụ lại, được lão nhân tộc Tiên Tuyển nhận ra là linh giáp do tiên ban thưởng.","detail":"Khi Tháp Sơn quyết chiến với Vương Lâm, các ký hiệu quanh thân hắn co rút về mi tâm rồi nhanh chóng tạo thành một bộ giáp màu đen. Bộ giáp tỏa khí lạnh, sau lưng hiện bóng ma như Ma Thần, và khiến Vương Lâm liên tưởng tới áo giáp Tán Ma ở mảnh đất yêu linh nhưng ma khí bị áp chế nhiều hơn.","nguon":["@c0757"]},{"id":"kiem-tien","name":"Kiếm tiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm sử dụng","blurb":"Đại tam linh của Huyền La, thanh kiếm nhỏ luyện từ 99.999 khối Toái Tinh Thần và hồn phách tiên nhân, cực hung ác khiến cả Cổ Tộc và Tiên Tộc kinh khiếp. (+) Pháp bảo dạng kiếm được Vương Lâm lấy từ túi trữ vật trong trận với vụ thú hình người. [CAN-SOAT-GOP]","detail":"Vương Lâm dùng kiếm tiên để thi triển Trảm La quyết, chém mạnh vào vụ thú hình người một mắt, khiến quái vật lộ vẻ hoảng sợ và bị chia cắt trong giao chiến.","nguon":["@c0758","@c1696"],"tabs":{}},{"id":"bo-xuong-thu","name":"Bộ xương thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo/vật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm sử dụng","blurb":"Vật hiện ra từ hình xương trên tay Vương Lâm, được dùng để khắc chế vụ thú hình người.","detail":"Bộ xương thú biến ảo ra ngoài từ hình xương trên tay Vương Lâm; hai mắt bắn tia sáng đen, sát khí khiến sương mù của vụ thú hình người có dấu hiệu hóa đá, tạo điều kiện để Vương Lâm đánh nát nó hoàn toàn.","nguon":["@c0758"]},{"id":"xa-than-xa-thu-ba","name":"Xạ Thần xa thứ ba","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được tế luyện","blurb":"Xạ Thần xa thứ ba là chiếc cuối cùng và mạnh nhất trong các Xạ Thần xa của Vương Lâm. Bảo vật này được chế ra để sát thương tiên thần, nhưng còn thiếu ba tài liệu để hoàn chỉnh. (+) Một chiếc Xạ Thần Xa của Vương Lâm, đã lâu không dùng và được lấy ra khi lực tự bạo chặn đường. [CAN-SOAT-GOP]","detail":"Xạ Thần xa thứ ba dài khoảng mười lăm trượng, rộng khoảng bốn trượng, toàn thân đầy gai nhọn và tỏa uy áp mạnh. Di ngôn Viên mỗ cho biết nó có uy lực vượt dự đoán, nhưng còn thiếu Huyền Huyền Sí, Minh Văn mộc và Tiên Điệp hồn; muốn nhận chủ phải dung hợp bảy ký hiệu phong ấn, luyện thành bổn mạng pháp bảo. Ở chương này Vương Lâm bắt đầu tế luyện, kích phát ánh sáng đen từ các gai nhọn để ngưng thành bảy ký hiệu rồi dùng nguyên thần Thái Cổ Lôi Long nuốt ký hiệu đầu tiên.","nguon":["@c0760","@c0896"]},{"id":"dau-lau-toc-tien-di","name":"Đầu lâu tộc Tiên Di","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Những đầu lâu tộc Tiên Di mà Vương Lâm thu được khi rời Chu Tước tinh, mỗi cái đều có ký hiệu phức tạp.","detail":"Sau khi nhận ra ký hiệu bản mệnh do thực vật ở mi tâm lão nhân tộc Tiên Tuyển hóa thành, Vương Lâm lấy ra mấy cái đầu lâu tộc Tiên Di từng thu được. Hắn cầm một cái lên quan sát các ký hiệu phức tạp trên đó, đồng thời suy nghĩ về nơi bị phong ấn và khả năng dùng nơi này làm chỗ ẩn thân.","nguon":["@c0760"]},{"id":"buom-ngu-sac","name":"Bướm ngũ sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Hình thái sau khi hồn thú của Xạ Thần Xa bị thu phục","blurb":"Hình thái thu nhỏ của hồn thú Xạ Thần Xa sau khi bị Vương Lâm dùng bảy đạo Băng quyết ép khuất phục.","detail":"Sau khi Xạ Thần Xa được giải phong, hồn thú cao trăm trượng liên tục bị Vương Lâm đánh vỡ bằng bảy đạo Băng quyết. Khi sợ hãi khuất phục, nó thu nhỏ thành kén rồi nở ra thành một con bướm ngũ sắc tỏa phấn nhiều màu, trở thành hình thái pháp bảo sau thu phục của Xạ Thần Xa.","nguon":["@c0761"]},{"id":"phong-tien-an","name":"Phong Tiên Ấn","cn":"","aliases":["Toái phiến đại ấn","Mảnh vỡ đại ấn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh vỡ đại ấn được Vương Lâm dùng trong trận với nam nhân áo xanh. Nó chắn trước Tháp Sơn và va chạm trực tiếp với trường thương tiên khí.","detail":"Khi nam nhân áo xanh uy hiếp Tháp Sơn, Vương Lâm phun ra mảnh vỡ đại ấn để ngăn đòn. Pháp bảo này sau đó được điều khiển va chạm với trường thương màu trắng do tiên khí của đối phương ngưng tụ.","nguon":["@c0762","@c0822"]},{"id":"co-than-bi-giap","name":"Cổ Thần Bì Giáp","cn":"","aliases":["Cổ Thần bì giáp","Du Cổ Thần bì giáp"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Giáp hộ nguyên thần","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Cổ Thần Bì Giáp là bì giáp thô ráp có ám ký phù văn và lạc ấn sâu, rất có thể từng thuộc về Tiêu Dao Tử. Sau khi Vương Lâm hủy tàn dư thần thức bên trong, bì giáp tự dung nhập vào nguyên thần hắn và tăng mạnh phòng ngự nguyên thần. (+) Giáp trên nguyên thần Vương Lâm, phát thanh quang chống lại lực lượng quỷ dị từ tượng đá màu đen. [CAN-SOAT-GOP]","detail":"Bì giáp mang khí tức tang thương nồng đậm, bên trong còn sót một tia thần thức độc lập có khả năng sau nhiều năm tự thức tỉnh thành khí linh. Vương Lâm dùng tinh khí nguyên thần luyện hóa, bức vân vụ màu lam ra ngoài, lấy Trảm La quyết chém đứt liên hệ giữa vân vụ và bì giáp rồi dùng Tôn Hồn Phiên thôn phệ. Khi thần thức hắn tràn vào, bì giáp và Vương Lâm cùng sinh cảm giác quen thuộc thân thiết, sau đó tự dung nhập vào trước ngực, bao bọc nguyên thần dạng Thái Cổ Lôi Long và khiến phòng ngự nguyên thần đạt trình độ cực kỳ đáng sợ.","nguon":["@c0763","@c0785","@c0941"]},{"id":"kim-toa","name":"Kim Tỏa","cn":"","aliases":["Khóa vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo cấp Âm Dương hư thực","soHuu":["Vương Lâm"],"trangThai":"bị phá hủy","blurb":"Kim Tỏa là pháp bảo Vương Lâm cướp từ sứ giả Lôi Tiên Điện, có khả năng phong ấn thần thông của người khác. Trong chương này hắn phá hủy pháp bảo để lấy giọt chất lỏng màu vàng bên trong.","detail":"Sau khi lấy Kim Tỏa ra, Vương Lâm hủy lạc ấn thần thức của chủ cũ rồi dùng nguyên lực bóp nát nó. Hắn đánh giá pháp bảo này tuy không tồi và có năng lực phong ấn thần thông, nhưng kém xa Tử Mẫu Đạo khô; thứ hắn thật sự giữ lại là giọt chất lỏng vàng tạo nên năng lực đặc biệt bên trong. Giá trị của Kim Tỏa được nhấn mạnh qua việc nếu xuất hiện trên Chu Tước Tinh bảy tám trăm năm trước, nó đủ khiến nhiều người điên cuồng tranh đoạt.","nguon":["@c0763"]},{"id":"giot-chat-long-mau-vang","name":"Giọt chất lỏng màu vàng","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Tinh túy pháp bảo","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Giọt chất lỏng màu vàng là tinh túy nằm trong Kim Tỏa. Vương Lâm phá hủy cả pháp bảo để thu lấy vật này.","detail":"Giọt chất lỏng vàng là phần trọng yếu khiến Kim Tỏa có khả năng phong ấn thần thông của người khác. Công dụng cụ thể của nó chưa được triển khai trong chương này, nhưng hành động hủy bảo lấy vật cho thấy Vương Lâm coi trọng nó hơn bản thân Kim Tỏa nguyên vẹn.","nguon":["@c0763"]},{"id":"phap-bao-chua-chat-long-mau-vang","name":"Pháp bảo chứa chất lỏng màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên bảo","soHuu":[],"trangThai":"bi-huy","blurb":"Tiên bảo bị Vương Lâm bóp nát để lấy giọt chất lỏng màu vàng bên trong.","detail":"Pháp bảo này từng được sứ giả Lôi Tiên Điện nhìn trúng, cho thấy cấp bậc ít nhất là tiên bảo. Vương Lâm cố ý bóp nát nó để truy xét căn nguyên thần thông, từ giọt chất lỏng bên trong rút ra phù văn phong ấn.","nguon":["@c0764"]},{"id":"ba-tieu-ky-mau-tim","name":"Ba tiểu kỳ màu tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đã luyện hóa","blurb":"Ba tiểu kỳ màu tím từng dùng để phong ấn nguyên thần sứ giả Lôi Tiên Điện. Sau khi Vương Lâm luyện hóa, chúng tạo thành lốc xoáy sương tím có lực phòng hộ quanh thân.","detail":"Vương Lâm giải phong nguyên thần bị giữ trong ba tiểu kỳ, xóa dấu thần thức cũ rồi đặt dấu của mình vào. Khi vận nguyên lực, tiểu kỳ tạo ra lốc xoáy sương mù màu tím bao phủ quanh thân, được hắn đánh giá là pháp bảo phòng hộ khá hữu dụng.","nguon":["@c0765"]},{"id":"quan-tai-pha-le","name":"Quan tài pha lê","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Quan tài pha lê nằm ở trung tâm trận pháp đỏ sậm trong hư vô tối đen, bên trong có thi thể nam nhân tuấn mỹ như ngủ say.","detail":"Chiếc quan tài bằng pha lê nằm ở trung tâm trận pháp màu đỏ sậm như máu giữa hư vô tối đen. Hắc khí tràn vào trong. Bên trong là thi thể một nam nhân tuấn mỹ trạc hơn hai mươi tuổi, nằm phảng phất như đang ngủ say. Bí ẩn mới hé lộ cuối chương.","nguon":["@c0766"]},{"id":"dau-lau-tien-di-toc-to-tien","name":"Đầu lâu tổ tiên Tiên Di tộc","aliases":["Đầu lâu tộc Tiên Di"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Hơn mười đầu lâu có phù văn trên mi tâm, được Vương Lâm dùng phụ trợ phù lực khi luyện Tháp Sơn thành tiên vệ.","detail":"Hơn mười chiếc đầu lâu tổ tiên Tiên Di tộc, mi tâm có phù văn, được Vương Lâm lấy được từ Chu Tước Tinh. Trong quá trình luyện hóa Tháp Sơn, hắn dùng chúng làm vật phụ trợ phù lực; sau khi dung nhập, chúng ngưng tụ thành một đạo phù văn trên mi tâm Tháp Sơn.","nguon":["@c0766"]},{"id":"ha-do-binh-phong","name":"Hà Đồ Bình Phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo dạng bình phong được Vương Lâm lấy ra để chống vụ tự bạo của phân thân Dương Thực. Nó biến cảnh quanh thân thành tranh thủy mạc, hóa giải một phần lực nổ.","detail":"Trong vụ tự bạo đầu tiên, Vương Lâm lấy Hà Đồ Bình Phong ra vung lên, khiến phạm vi xung quanh như hóa thành tranh thủy mạc để chống lại lực hủy diệt. Chương nhấn mạnh vật này không phải Sơn Hà Đồ chân chính, nhưng vẫn phối hợp với tam diện tiểu kỳ và Cổ Thần Bì Giáp giúp Vương Lâm sống sót.","nguon":["@c0767"]},{"id":"ti-thien-quan","name":"Tị Thiên Quan","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên vực chi bảo viễn cổ","soHuu":["Tiêu Dao Tử"],"trangThai":"chưa rõ phương pháp sử dụng","blurb":"Quan tài pháp bảo của Tiêu Dao Tử, vốn dùng để đặt hồn con phàm tục nhằm ngưng tụ thân thể và chờ thức tỉnh. Long Đạo Tử mở quan tài rồi chui vào để phục hồi thân thể và tu vi, nhưng khi rời quan tài lại bị tiêu tán.","detail":"Tị Thiên Quan được Tiêu Dao Tử gọi là tiên vực chi bảo từ viễn cổ, dùng để chứa hồn con phàm tục của ông nhằm ngưng tụ thân thể và chờ ngày thức tỉnh. Trong chương này, Long Đạo Tử bị ép tới tuyệt cảnh nên đâm đầu mở quan tài, khiến thân thể thanh niên bên trong vừa tiếp xúc bên ngoài liền tiêu tán. Sau đó Long Đạo Tử chui vào quan tài, được hắc khí và sức mạnh trong quan tài nhanh chóng ngưng tụ lại thân thể, tu vi tăng vọt từ mức giữa Dương Thực và Khuy Niết lên thiên tiên rồi tiên vương. Tuy nhiên khi hắn nhảy ra ngoài, thân thể lại tiêu tán giống thanh niên trong quan tài, cho thấy pháp bảo này có cơ chế hoặc cái giá nghiêm trọng khi rời khỏi phạm vi quan tài.","nguon":["@c0768","@c0831","@c1702"],"aliases":["Tị Thiên Quan"],"tabs":{}},{"id":"bach-vu-chi-phien","name":"Bạch vũ chi phiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Long Đạo Tử"],"trangThai":"Được Long Đạo Tử dùng trong giao chiến với Vương Lâm","blurb":"Quạt trắng do Long Đạo Tử biến bạch quang từ mi tâm thành, dùng để vỗ ra cuồng phong và cuồng lôi gió lốc. Đòn này bị nguyên thần Thái Cổ Lôi Long của Vương Lâm ứng đối.","detail":"Bạch vũ chi phiến là pháp bảo hoặc vật biến hóa từ bạch quang nơi mi tâm Long Đạo Tử trong trận chiến với Vương Lâm. Khi được vỗ ra, nó tạo cuồng phong và cuồng lôi gió lốc tấn công, buộc Vương Lâm vận dụng nguyên thần Thái Cổ Lôi Long ở mi tâm để nuốt lấy luồng cuồng lôi ấy trước khi tiếp tục dùng Phong Tiên Ấn áp chế đối thủ.","nguon":["@c0768"]},{"id":"lam-dan","name":"Lam đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Chưa rõ","soHuu":["Long Đạo Tử"],"trangThai":"Được dùng để chống đỡ Hô Phong","blurb":"Viên đan màu lam do Long Đạo Tử phun ra để chống Hô Phong. Lam quang và lực xoáy từ viên đan giúp hấp thu, ngăn cản hắc phong uy hiếp thương thế cũ của hắn.","detail":"Lam đan là viên đan màu lam được Long Đạo Tử dùng khi Vương Lâm thi triển Hô Phong. Do Long Đạo Tử từng bị Bạch Phàm dùng Hô Phong đánh tan thân thể, hắn cực kỳ kiêng kỵ thuật này và phun viên đan ra để phát lam quang, tạo lực xoáy chống đỡ, hấp thu hắc phong nhằm ngăn Hô Phong dẫn phát thương thế cũ còn lưu trong nguyên thần.","nguon":["@c0768"]},{"id":"lung-trao","name":"Lung Tráo","cn":"","category":"khac","categoryLabel":"Vật chứa người","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm sử dụng","blurb":"Vật được Vương Lâm dùng để chứa nữ quyến và hài đồng Tiên Tuyển tộc khi vượt sương mù La Thiên Tây Vực.","detail":"Trong hành trình dẫn Tiên Tuyển tộc thoát khỏi sương mù, Vương Lâm đưa nữ quyến và hài đồng vào Lung Tráo để tăng tốc độ đội ngũ, giúp cả đoàn tiếp tục xông ra tinh không La Thiên.","nguon":["@c0769"]},{"id":"thien-khung-lenh","name":"Thiên Khung Lệnh","cn":"","aliases":["Thương Khung Lệnh"],"category":"khac","categoryLabel":"Lệnh truy sát","phamCap":"không rõ","soHuu":["Diêu gia"],"trangThai":"được Diêu gia phát ra","blurb":"Lệnh truy sát của Diêu gia, lần thứ tư phát ra chỉ ghi tên Hứa Mộc.","detail":"Diêu gia phát Thiên Khung Lệnh khiến toàn La Thiên chấn động. Trên lệnh chỉ có tên Hứa Mộc, thể hiện ý truy sát không chết không thôi và kéo mạng lưới gia tộc liên hệ của Diêu gia vào cuộc tìm kiếm.","nguon":["@c0769"]},{"id":"la-thien-lenh","name":"La Thiên lệnh","cn":"","category":"khac","categoryLabel":"Lệnh triệu tập","phamCap":"không rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"được Lôi Tiên Điện phát ra","blurb":"Lệnh do Lôi Tiên Điện tuyên bố để kêu gọi các gia tộc tu chân La Thiên chuẩn bị tiến vào Liên Minh Tinh Vực.","detail":"La Thiên lệnh được phát trong thời gian Vương Lâm biến mất hơn nửa năm, mở đầu cho đợt triệu tập quy mô lớn nhằm chuẩn bị chiến tranh giữa La Thiên Tinh Vực và Liên Minh Tinh Vực.","nguon":["@c0769"]},{"id":"thang-tien-tri","name":"Thăng Tiên Trì","cn":"","category":"khac","categoryLabel":"Tiên trì","phamCap":"không rõ","soHuu":["Gia tộc tu chân viễn cổ thần bí"],"trangThai":"xuất hiện trong nghi thức Phong Tiên","blurb":"Tiên trì được nêu như phần thưởng tối hậu cho 108 người được Phong Tiên.","detail":"Theo đạo thư triệu tập của gia tộc viễn cổ thần bí, 108 người được Phong Tiên có thể nhập Thăng Tiên Trì, hóa thể nguyên thành tiên nguyên và thành tựu thực tiên, khiến sĩ khí La Thiên dâng cao.","nguon":["@c0769","@c0826"]},{"id":"ngoc-gian-ban-do-cua-than-cong-ho","name":"Ngọc giản bản đồ của Thân Công Hổ","cn":"","category":"khac","categoryLabel":"Vật phẩm bản đồ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm sử dụng","blurb":"Ngọc giản bản đồ La Thiên do Thân Công Hổ từng giao cho Vương Lâm. Trong chương này, nó giúp Vương Lâm đối chiếu vị trí Huyền Trần Tinh và ghi phương vị Thanh Linh Tinh cho Tiên Tuyển Tộc.","detail":"Khi trở lại La Thiên Tinh Vực, Vương Lâm lấy ngọc giản bản đồ ra để xác định mình đang ở vùng nào. Sau khi biết Huyền Trần Tinh thuộc La Thiên Tây Vực, hắn đưa vị trí Thanh Linh Tinh vào bản đồ rồi giao cho lão nhân tiên tổ Tiên Tuyển Tộc dẫn tộc nhân đi trước.","nguon":["@c0770"]},{"id":"tui-tru-vat-cua-ba-tu-si-truy-sat","name":"Túi trữ vật của ba tu sĩ truy sát","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã thu lấy","blurb":"Ba túi trữ vật thu từ nhóm tu sĩ truy sát Vương Lâm. Bên trong có pháp bảo, bảo vật và hai ngọc giản liên hệ Diêu gia.","detail":"Sau khi trung niên văn sĩ và hai lão nhân Âm Hư bị xử lý, túi trữ vật của họ rơi vào tay Vương Lâm. Các pháp bảo và bảo vật bên trong bị bóp nát thành dịch thể để dung nhập vào thân thể Tháp Sơn, còn hai ngọc giản trở thành đầu mối xác nhận liên hệ với Diêu gia.","nguon":["@c0771"]},{"id":"ngoc-gian-lien-he-dieu-gia","name":"Ngọc giản liên hệ Diêu gia","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"Không rõ","soHuu":["Trung niên văn sĩ","Hai lão nhân Âm Hư"],"trangThai":"rơi vào tay Vương Lâm","blurb":"Hai ngọc giản trong túi trữ vật của ba tu sĩ truy sát. Chúng cho thấy những người này có liên hệ với Diêu gia trong cuộc truy sát Hứa Mộc.","detail":"Vương Lâm tìm được hai ngọc giản liên hệ Diêu gia trong túi trữ vật của ba tu sĩ. Kết hợp với ký ức sưu thần, chúng giúp hắn biết quy mô lệnh truy sát và mạng lưới đang truy tìm mình tại La Thiên Tinh Vực.","nguon":["@c0771"]},{"id":"chuong-mau-bac","name":"Chuông màu bạc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Lão nhân Dương Thực đỉnh"],"trangThai":"đang sử dụng","blurb":"Chuông màu bạc là pháp bảo của lão nhân Dương Thực đỉnh. Khi lay động, nó tạo tiếng động và sóng gợn lớn để quấy nhiễu sức mạnh thiên địa.","detail":"Lão nhân Dương Thực đỉnh dùng chuông màu bạc sau khi nhận ra lối di chuyển của Vương Lâm không phải thuấn di hay Đại Na Di. Tiếng chuông hóa thành sóng gợn lan ra, nhằm phá khả năng dung nhập thiên địa của Vương Lâm.","nguon":["@c0772"]},{"id":"cham-den","name":"Châm đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo vũ khí","phamCap":"không rõ","soHuu":["Tu sĩ Dương Thực dùng châm đen"],"trangThai":"bị hóa đá","blurb":"Châm đen là vũ khí được một tu sĩ Dương Thực phóng ra thành vô số mũi như mưa tên. Chúng bị Tử Mẫu Đạo Khô của Vương Lâm hóa đá trong trận chiến.","detail":"Trong lúc các tu sĩ cố quấy nhiễu thiên địa, tu sĩ Dương Thực phóng vô số châm đen về phía Vương Lâm. Vương Lâm dùng Tử Mẫu Đạo Khô hóa đá số châm này rồi giết người điều khiển cùng hai tu sĩ khác.","nguon":["@c0772"]},{"id":"ngoc-gian","name":"Ngọc giản","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"không rõ","soHuu":["Văn sĩ trung niên của Huyền Trần Tinh"],"trangThai":"đã dùng","blurb":"Ngọc giản được nhắc lại như vật phẩm văn sĩ trung niên Huyền Trần Tinh bóp nát để gọi Diêu Trường Không. Việc này dẫn tới sự xuất hiện của tộc nhân Diêu gia trong kiếm quang.","detail":"Chương này nhắc lại nguyên nhân Diêu Trường Không xuất hiện: văn sĩ trung niên của Huyền Trần Tinh trước đó đã bóp nát ngọc giản, khiến thanh niên Diêu Trường Không được gọi tới chiến trường.","nguon":["@c0772"]},{"id":"de-tien-phu","name":"Đế tiên phù","cn":"","category":"phap-bao","categoryLabel":"Thần phù","phamCap":"Không rõ; do tổ tiên Diêu gia ban cho","soHuu":["Diêu Trường Không"],"trangThai":"Một mảnh còn sót từng dán vào mi tâm Vương Lâm rồi tiêu tán khi đạo cảnh của Diêu Trường Không bị phá","blurb":"Thần phù Diêu Trường Không dùng để sát phạt Vương Lâm, mang lực phù văn giống Tiên Di Tộc nhưng mạnh hơn nhiều. Sau khi bị phù tương tự của Vương Lâm triệt bớt uy lực, phần còn lại vẫn phong ấn nguyên lực của Vương Lâm trong thời gian ngắn.","detail":"Đế tiên phù là thần phù do tổ tiên ban cho Diêu Trường Không. Khi kích phát, nó tạo ra lực phù văn phong ấn khiến nguyên lực trong người Vương Lâm bị khóa, làm hắn gần như rơi vào trạng thái phàm nhân giữa lúc sinh tử. Vương Lâm dùng một tờ phù tương tự và máu để va chạm triệt bớt uy lực, nhưng mảnh phù còn sót vẫn dán vào mi tâm hắn; về sau khi Vương Lâm dùng đạo niệm Nhân Quả phá đạo cảnh vinh quang của Diêu Trường Không, phù văn phong ấn mới tiêu tán.","nguon":["@c0773"]},{"id":"kim-dan-tien-nhan","name":"Kim đan tiên nhân","cn":"","category":"khac","categoryLabel":"Vật phẩm phòng hộ","phamCap":"Không rõ; do lão tổ ban cho","soHuu":["Diêu Trường Không"],"trangThai":"Đã được dùng để hấp thu sát cục hợp kích của Vương Lâm và Tháp Sơn","blurb":"Hạt châu giống kim đan do lão tổ ban cho Diêu Trường Không, có năng lực hấp thu công kích cực mạnh. Nó giúp Diêu Trường Không tránh bị thương trong sát cục do Vương Lâm bố trí.","detail":"Kim đan tiên nhân xuất hiện khi Diêu Trường Không bị Phong Ấn, Trảm La quyết, quyền của Tháp Sơn và Phong Tiên Ấn đồng thời công kích. Viên kim đan hấp thu toàn bộ đợt công kích này, khiến Diêu Trường Không tuy chật vật nhưng không chịu thương tổn, đồng thời phản lực còn làm hữu quyền của Tháp Sơn bị phá nặng lan tới nửa thân.","nguon":["@c0773"]},{"id":"dai-kiem-ba-truong-cua-dieu-truong-khong","name":"Đại kiếm ba trượng của Diêu Trường Không","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"Không rõ","soHuu":["Diêu Trường Không"],"trangThai":"Từng được dùng làm pháp bảo phi hành và phân liệt thành mười chín tiểu kiếm tạo kiếm trận","blurb":"Thanh đại kiếm dài ba trượng mà Diêu Trường Không đứng lên khi hiện thân. Trong giao chiến, nó phân thành mười chín tiểu kiếm xoay tròn tạo lốc xoáy kiếm khí.","detail":"Đại kiếm ba trượng là pháp bảo gắn với màn xuất hiện của Diêu Trường Không trong tinh không. Hắn đứng trên kiếm để đối mặt Vương Lâm, sau đó đại kiếm phân liệt thành mười chín tiểu kiếm hình thành kiếm trận, tạo lốc xoáy kiếm khí chống lại thế công gồm Phong Tiên Ấn và Trảm La quyết.","nguon":["@c0773"]},{"id":"linh-bai-dieu-gia","name":"Linh bài Diêu gia","cn":"","category":"khac","categoryLabel":"Bài vị hồn mệnh","phamCap":"Không rõ","soHuu":["Diêu gia"],"trangThai":"Một linh bài nứt đôi sau khi Diêu Trường Không chết; Huyết Thần Tử thu bạch khí từ đó","blurb":"Bài vị đặt trong từ đường Diêu gia, có liên hệ với sinh tử tộc nhân. Khi Diêu Trường Không chết, một linh bài nứt đôi và tỏa bạch khí bị Huyết Thần Tử thu lấy.","detail":"Linh bài Diêu gia được đặt trong từ đường trên tinh cầu đỏ như máu của Diêu gia. Chương này cho thấy sau cái chết của Diêu Trường Không, một linh bài nứt đôi; Huyết Thần Tử ngồi trong từ đường quan sát việc này, thu lấy bạch khí từ linh bài và không tỏ ra phẫn nộ, mà muốn tiếp tục xem Vương Lâm giết được bao nhiêu người Diêu gia.","nguon":["@c0773"]},{"id":"tieu-kinh-cua-dieu-bang-van","name":"Tiểu kính của Diêu Băng Vân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Diêu Băng Vân"],"trangThai":"hong","blurb":"Tiểu kính của Diêu Băng Vân là pháp bảo truy tung, có thể hiện ra hình ảnh Vương Lâm sau khi nàng mất dấu trong thiên địa. Khi nàng định ấn vào mặt kính, sát khí từ Vương Lâm làm kính vỡ vụn.","detail":"Diêu Băng Vân dùng tiểu kính bên ngoài tinh cầu hoang phế để thôi diễn và nhìn thấy Vương Lâm vừa bay lên. Pháp bảo này bị phá ngay khi sát khí của Vương Lâm từ hình ảnh trong kính lao ra, khiến mặt kính vỡ vụn.","nguon":["@c0774"]},{"id":"nguyen-than-am-hu","name":"Nguyên thần Âm Hư","cn":"","category":"khac","categoryLabel":"Tài nguyên tu luyện","phamCap":"Âm Hư","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Nguyên thần Âm Hư là hồn phách/tài nguyên Vương Lâm rút ra trong lúc chữa thương. Hắn liên tiếp nuốt bốn nguyên thần để bổ sung nguyên lực.","detail":"Khi ẩn trong thung lũng trên tinh cầu hoang phế, Vương Lâm thả Tôn Hồn Phiên thành sương đen bảo hộ và rút nguyên thần Âm Hư từ trong đó để nuốt. Bốn nguyên thần giúp hắn khôi phục nguyên lực trước khi giao thủ với Diêu Băng Vân.","nguon":["@c0774"]},{"id":"nguyen-dan-mau-lam","name":"Nguyên đan màu lam","cn":"","aliases":["Viên đan màu lam"],"category":"khac","categoryLabel":"Vật phẩm hộ thân","phamCap":"Không rõ","soHuu":["Diêu Băng Vân"],"trangThai":"đang dùng","blurb":"Nguyên đan màu lam của Diêu Băng Vân, được gọi ra để nghênh âm phong từ hắc long của Vương Lâm.","detail":"Khi Diêu Băng Vân đối mặt âm phong từ Hô Phong thuật, nguyên đan này lóe sáng trước hai tay nàng và hóa giải âm phong. Sau va chạm, màu sắc của nó nhạt đi như mất vẻ sống động.","nguon":["@c0775"]},{"id":"nguyen-than-huyet-to","name":"Nguyên thần Huyết Tổ","cn":"","category":"khac","categoryLabel":"Nguyên thần bị phong ấn","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tự bạo","blurb":"Nguyên thần Huyết Tổ bị Vương Lâm dùng làm sát chiêu trong Cửu Tuyệt Tổn Thần Trận.","detail":"Vương Lâm lưu lạc ấn lên nguyên thần Huyết Tổ, giữ trong màn sương đen của Tôn Hồn Phiên rồi kích nổ giữa đội truy sát. Vụ tự bạo tạo sóng gợn trong phạm vi vạn trượng, giết nhiều tu sĩ truy sát và tộc nhân Diêu gia.","nguon":["@c0776"]},{"id":"nguyen-than-van-dinh","name":"Nguyên thần Vấn Đỉnh","cn":"","category":"khac","categoryLabel":"Vật liệu trận","phamCap":"Vấn Đỉnh","soHuu":["Vương Lâm"],"trangThai":"đã dùng","blurb":"Nguyên thần Vấn Đỉnh được Vương Lâm dùng làm vật liệu bổ sung cho Cửu Tuyệt Tổn Thần Trận.","detail":"Khi nguyên thần Âm Hư trong Tôn Hồn Phiên không còn nhiều, Vương Lâm dùng nguyên thần Vấn Đỉnh thay thế, bóp nát và đánh lạc ấn để dung nhập vào bố trí trận pháp.","nguon":["@c0776"]},{"id":"thanh-xuong-cua-vong-nguyet","name":"Thanh xương của Vọng Nguyệt","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu trong cơ thể hung thú","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"từng lấy một phần","blurb":"Thanh xương trong cơ thể Vọng Nguyệt từng được Vương Lâm tìm lấy năm xưa.","detail":"Vương Lâm từng định lấy toàn bộ thanh xương của Vọng Nguyệt nhưng phải bỏ lại một nửa. Khi trở lại cơ thể Vọng Nguyệt trong cuộc truy sát, hắn theo dấu vết cũ tiến tới khu vực xương cốt này.","nguon":["@c0777"]},{"id":"phi-kiem-cua-dieu-van-hai","name":"Phi kiếm của Diêu Vân Hải","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo di chuyển","phamCap":"Không rõ","soHuu":["Diêu Vân Hải"],"trangThai":"không rõ","blurb":"Phi kiếm Diêu Vân Hải dùng để tiến vào màn sương đen của tinh cầu Vọng Nguyệt.","detail":"Diêu Vân Hải chân đạp phi kiếm, hóa thành trường hồng tiến vào màn sương đen bao quanh tinh cầu Vọng Nguyệt trong cuộc truy sát Hứa Mộc.","nguon":["@c0778"]},{"id":"kien-bao-boi-cua-huyet-than-tu","name":"Kiện bảo bối của Huyết Thần Tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Huyết Thần Tử"],"trangThai":"đã dùng để đổi lấy huyết tẩy @c0781","blurb":"Một kiện bảo bối chưa nêu tên của Huyết Thần Tử, chỉ còn một lần tác dụng.","detail":"Huyết Thần Tử không tiếc dùng kiện bảo bối chỉ còn một lần tác dụng này để đổi lấy một lần huyết tẩy cho tộc nhân, nhằm khiến họ thích ứng với cuộc chiến cùng Liên Minh Tinh Vực.","nguon":["@c0781"]},{"id":"dai-dinh-cua-tham-lang","name":"Đại đỉnh của Tham Lang Đại Trác","cn":"","category":"phap-bao","categoryLabel":"pháp bảo / vật phẩm","phamCap":"khong-ro","soHuu":["Tham Lang"],"trangThai":"trong cơ thể Vọng Nguyệt","blurb":"Đại đỉnh gắn với Tham Lang Đại Trác, đang là mục tiêu khiến Vương Lâm động tâm trong cơ thể Vọng Nguyệt.","detail":"Dù bị Vọng Nguyệt nhỏ truy kích, Vương Lâm vẫn tiếp tục tìm vị trí đại đỉnh này, cho thấy nó là bảo vật quan trọng trong mạch sự kiện bên trong cơ thể Vọng Nguyệt.","nguon":["@c0782"]},{"id":"dai-dinh","name":"Đại đỉnh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Về lại tay Vương Lâm","blurb":"Đại đỉnh là pháp bảo từng bị Tham Lang chiếm, nay được Vương Lâm xóa lạc ấn cũ và thu về tay.","detail":"Tham Lang từng dùng phù văn ấn lên đại đỉnh để liên kết một phần thần thông, nhưng phương pháp này chỉ cho phép khống chế hạn chế. Trong chương này, Vương Lâm dùng thần thức đánh sụp lạc ấn của Tham Lang trên phù văn, lưu lạc ấn của mình lên đó và tạm thời thu đại đỉnh thành vật của mình. Do vẫn khống chế theo đường phù văn của Tham Lang, liên hệ giữa Vương Lâm và đại đỉnh còn mơ hồ, chưa phát huy hết uy lực; thần thông đã biểu hiện là Di hình.","nguon":["@c0785"]},{"id":"con-thuyen-lon-cua-ngu-thai-dao-nhan","name":"Con thuyền lớn của Ngũ Thải đạo nhân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"Không rõ","soHuu":["Ngũ Thải đạo nhân"],"trangThai":"dang-co","blurb":"Con thuyền khổng lồ đưa Ngũ Thải đạo nhân tới khu vực Vọng Nguyệt, trên thuyền có nhiều thiếu nữ áo năm màu nhảy múa.","detail":"Ngũ Thải đạo nhân xuất hiện từ con thuyền lớn giữa tinh không. Vật này đóng vai trò pháp bảo hoặc phương tiện phi hành, thể hiện phong cách âm nhu quỷ dị của ông ta khi tới tham dự cuộc bắt Vọng Nguyệt.","nguon":["@c0787"]},{"id":"manh-vo-tien-gioi-cua-viem-loi-tu","name":"Mảnh vỡ Tiên giới của Viêm Lôi tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phong ấn","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"đang sử dụng @c0789","blurb":"Vô số mảnh địa lục Tiên giới do Viêm Lôi Tử điều khiển để bao vây và phong ấn Vọng Nguyệt.","detail":"Trong trận bắt Vọng Nguyệt, Viêm Lôi Tử phóng lớn các mảnh vỡ Tiên giới, khiến chúng xoay quanh chiến trường thành lốc xoáy và tạo khí tức như Lôi chi Tiên giới tái hiện, dùng để ép phong ấn con thú.","nguon":["@c0789"]},{"id":"ngan-kiem-cua-liet-van-tu","name":"Ngân kiếm của Liệt Vân Tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Liệt Vân tử"],"trangThai":"đang sử dụng @c0789","blurb":"Thanh kiếm nhỏ màu bạc dùng làm vật dẫn cho Tâm động Tiên thuật của Liệt Vân Tử.","detail":"Ngân kiếm phát ánh sáng mạnh và có thể kéo dài vô hạn khi Liệt Vân Tử thi triển Tâm động Tiên thuật, xuyên qua thân thể Vọng Nguyệt trong trận vây công.","nguon":["@c0789"]},{"id":"huyet-dan-cua-bon-dong-tu","name":"Huyết đan của bốn đồng tử","cn":"","category":"phap-bao","categoryLabel":"Vật phẩm phong tỏa","phamCap":"Không rõ","soHuu":["Phong thần tứ tử"],"trangThai":"hư hại @c0789","blurb":"Huyết đan trên Thiên Linh Cái của bốn đồng tử, dùng để phong tỏa đường thoát của Vọng Nguyệt.","detail":"Bốn đồng tử dùng Huyết đan phối hợp tạo phong tỏa quanh Vọng Nguyệt. Khi Cổ Thần chỉ gần như thực chất đánh tới, Huyết đan xuất hiện vết rạn, phun sương đỏ rồi có viên vỡ vụn.","nguon":["@c0789"]},{"id":"vat-yeu-di-ban-mang-cua-huyet-than-tu","name":"Vật yêu dị bản mạng của Huyết Thần tử","cn":"","category":"khac","categoryLabel":"Vật hộ mệnh","phamCap":"Không rõ","soHuu":["Huyết Thần Tử"],"trangThai":"đang có @c0789","blurb":"Vật yêu dị tương liên bản mạng hiện ra đỡ lực Cổ Thần, giúp Huyết Thần Tử tránh chết trong gang tấc.","detail":"Khi Huyết Thần Tử bị lực toái tinh của Cổ Thần đánh trọng thương nguyên thần, vật yêu dị bản mạng hiện ra trước người hắn để ngăn cản. Nhờ vậy hắn thoát chết nhưng vẫn phải huyết độn bỏ chạy.","nguon":["@c0789"]},{"id":"chuong-lon-hu-ao-cua-cong-ton","name":"Chuông lớn hư ảo của Công Tôn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo thần thông","phamCap":"Không rõ","soHuu":["Người đàn ông trung niên họ Công Tôn"],"trangThai":"đang sử dụng @c0789","blurb":"Chiếc chuông lớn hư ảo do người họ Công Tôn phun ra khi hóa hắc ưng khổng lồ.","detail":"Chuông lớn bao phủ hắc ưng, phát tiếng chuông mang lực lượng khiến tinh không sụp đổ dữ dội hơn. Sau va chạm với Cổ Thần chỉ, chuông bị cuốn lộn nhào theo thần thông sụp đổ.","nguon":["@c0789"]},{"id":"nghich-thien-chau","name":"Nghịch Thiên châu","cn":"","aliases":["Hạt châu Thiên Nghịch"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nghịch Thiên châu nằm trong mi tâm Vương Lâm và chậm rãi xoay chuyển khi hắn cảm ngộ đạo của Diêu Băng Vân. Hạt châu hấp thu trong quá trình đôi cá âm dương nhập vào cơ thể nàng.","detail":"Khi Vương Lâm đưa đôi cá âm dương vào cơ thể Diêu Băng Vân để cảm ngộ đạo, Nghịch Thiên châu trong mi tâm hắn chậm rãi xoay chuyển và hấp thu. Chi tiết này gắn pháp bảo với quá trình kiểm chứng Nhân Quả của hắn.","nguon":["@c0795"]},{"id":"phap-bao-can-linh-hon","name":"Pháp bảo cần linh hồn","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Diêu Gia"],"trangThai":"khong-ro","blurb":"Pháp bảo chưa nêu tên của Diêu Gia cần linh hồn làm thành phần then chốt. Băng Vân và Mộng Vân bị lão tổ Diêu Gia nói rằng từ khi sinh ra đã được định sẵn làm linh hồn cho pháp bảo này.","detail":"Trong đạo niệm Diêu Băng Vân, lão tổ Diêu Gia tuyên bố hai cô bé là tộc nhân Diêu Gia nên số mệnh không thể trốn tránh: từ khi sinh ra đã được định sẵn làm linh hồn cho pháp bảo. Đây là nguyên nhân trực tiếp tạo thành bi kịch của hai tỷ muội.","nguon":["@c0795"]},{"id":"co-dang","name":"Cổ Đăng","cn":"","aliases":["Cổ đăng Diêu Gia"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Diêu Gia","Huyết Thần Tử"],"trangThai":"đang do Huyết Thần Tử giữ","blurb":"Bảo vật trọng yếu của Diêu Gia, mang ngọn lửa xanh lạnh tồn tại từ tiên giới. Pháp bảo này cần khí hồn duy trì và là nguyên nhân khiến Mộng Vân bị nuốt vào làm khí hồn mới.","detail":"Trong từ đường Diêu Gia, lão tổ mở khe hư vô triệu cổ đăng ra. Ngọn lửa xanh trên đèn không tỏa nhiệt mà lạnh lẽo, từng có dấu hiệu tàn lụi nên lão tổ rút một phần khí hồn dung nhập vào tộc nhân ưu tú, tạo nên số phận của Diêu Băng Vân và Mộng Vân; sau khi Mộng Vân bị Cổ Yêu nuốt, nàng bị đưa vào trong ngọn đèn.","nguon":["@c0796"]},{"id":"ngon-lua-xanh-tren-co-dang","name":"Ngọn lửa xanh trên cổ đăng","cn":"","aliases":[],"category":"khac","categoryLabel":"Dị hỏa / khí hồn","phamCap":"không rõ","soHuu":["Diêu Gia","Huyết Thần Tử"],"trangThai":"đang tồn tại trên Cổ Đăng","blurb":"Ngọn lửa xanh lạnh trên Cổ Đăng, không tỏa nhiệt mà mang khí tức lạnh lẽo. Nó hóa thành hình thái Cổ Yêu và nuốt Mộng Vân vào trong pháp bảo.","detail":"Lão tổ Diêu Gia nói ngọn lửa này đã tồn tại từ tiên giới đến nay, năm trăm năm trước xuất hiện dấu hiệu tàn lụi do khí hồn tiêu tán. Trong ảo cảnh, ngọn lửa hóa thành vật yêu dị hai sừng, được Vương Lâm nhận ra là Cổ Yêu, rồi nuốt Mộng Vân khiến ánh lửa trở nên sáng rực.","nguon":["@c0796"]},{"id":"tinh-hon-ben-trong-phap-bao","name":"Tinh hồn bên trong pháp bảo","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh hồn pháp bảo","phamCap":"không rõ","soHuu":["Diêu Gia"],"trangThai":"bị rút một phần để dung nhập vào tộc nhân","blurb":"Tinh hồn liên quan đến pháp bảo Diêu Gia, bị lão tổ rút một phần trong thời gian dài. Việc dung nhập tinh hồn này dẫn đến sự ra đời của Diêu Băng Vân và Mộng Vân với vận mệnh khí hồn.","detail":"Theo lời Diêu Vân và lão tổ Diêu Gia, mẫu thân của hai tỷ muội chỉ là công cụ để tinh hồn trong pháp bảo dung nhập vào hài tử mới sinh. Lão tổ mất ba trăm năm rút một phần khí hồn rồi dung nhập vào tộc nhân ưu tú, khiến Băng Vân và Mộng Vân sinh ra để trở thành linh hồn mới của pháp bảo.","nguon":["@c0796"]},{"id":"truong-chi-phu-cuoi-cung","name":"Trương Chỉ Phù cuối cùng","cn":"","category":"khac","categoryLabel":"phù","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã dùng để hỏi manh mối","blurb":"Trương Chỉ Phù cuối cùng là lá phù Vương Lâm lấy ra khi tìm Tiên Tuyển Tộc trên Thanh Linh Tinh. Nó khiến tộc nhân cảm thấy quen thuộc nhưng không gợi ra được manh mối cụ thể.","detail":"Sau khi rời Hoành Vân, Vương Lâm chưa lập tức rời Thanh Linh Tinh mà tìm Tiên Tuyển Tộc, lấy Trương Chỉ Phù cuối cùng ra hỏi. Người của Tiên Tuyển Tộc chỉ có cảm giác rất quen thuộc với lá phù, nhưng không nhớ ra bất kỳ đầu mối nào.","nguon":["@c0798"]},{"id":"kinh-dong-cua-dieu-van","name":"Kính đồng của Diêu Vân","cn":"","aliases":["gương đồng","cổ kính"],"category":"phap-bao","categoryLabel":"pháp bảo","phamCap":"không rõ","soHuu":["Diêu Vân"],"trangThai":"đang được Diêu Vân sử dụng","blurb":"Kính đồng của Diêu Vân là pháp bảo dùng để truy tung và phong thu Vương Lâm. Nó có điểm đỏ chỉ hướng, rồi biến tinh không vạn trượng thành vùng như mặt kính để thu mục tiêu vào trong.","detail":"Diêu Vân cưỡi hồng vân truy tới nhờ kính đồng có điểm đỏ chỉ phương hướng. Khi đối mặt Vương Lâm, hắn dùng pháp bảo này phong tỏa hư vô, khiến Vương Lâm không thể dung nhập thiên địa, sau đó khiến tinh không chu vi vạn trượng hóa thành mặt kính vỡ vụn và dung nhập vào bên trong kính đồng.","nguon":["@c0798"]},{"id":"an-ky-yeu-di","name":"Ấn ký yêu dị / yêu văn trên mi tâm Diêu Vân","cn":"","aliases":["yêu văn trên mi tâm Diêu Vân"],"category":"khac","categoryLabel":"Ấn ký ký sinh","phamCap":"không rõ","soHuu":["Diêu Vân","Cổ Yêu"],"trangThai":"đang ở trên mi tâm Diêu Vân","blurb":"Ấn ký ký sinh liên quan trực tiếp tới Cổ Yêu trong thân thể Diêu Vân. Sau khi Cổ Yêu bị trọng thương, Huyết Thần Tử ép ấn ký này trở lại mi tâm Diêu Vân.","detail":"Cổ Yêu bị Phong Tiên Ấn, Cổ Thần đại đỉnh và thiên lôi đánh trọng thương rồi hóa thành ấn ký muốn chui về mi tâm Diêu Vân. Diêu Vân cố kháng cự nhưng Huyết Thần Tử từ huyết vụ thò tay chụp lấy ấn ký, ấn vào mi tâm hắn, khiến yêu văn trên mi tâm đậm lên và phản kháng trong mắt Diêu Vân tiêu tan.","nguon":["@c0799"]},{"id":"vat-trong-co-the-vong-nguyet","name":"Vật trong cơ thể Vọng Nguyệt","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm chưa nêu tên","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Vật phẩm chưa nêu tên mà Vương Lâm lấy được trong cơ thể Vọng Nguyệt. Huyết Thần Tử đích thân hiện thân đòi món này.","detail":"Sau khi trấn áp Diêu Vân, Huyết Thần Tử nhìn Vương Lâm và dùng Ngôn Xuất Pháp Tùy yêu cầu hắn giao vật lấy được trong cơ thể Vọng Nguyệt. Phản ứng của Huyết Thần Tử cho thấy món này là mục tiêu quan trọng của lão và Diêu gia.","nguon":["@c0799"]},{"id":"huyet-yen","name":"Huyết Yến","cn":"","aliases":[],"category":"khac","categoryLabel":"Pháp thuật hóa hình","phamCap":"không rõ","soHuu":["Huyết Thần Tử"],"trangThai":"đang truy kích Vương Lâm","blurb":"Huyết yến là vật năm đó của Huyết Thần Tử nhưng đã bị con bướm nhiều màu cướp đi. Trong chương này nó xuất hiện đi cùng con bướm nhiều màu. (+) Hồng quang hóa thành chim yến máu do Huyết Thần Tử phóng ra. Đây là đòn truy kích nhắm thẳng vào Vương Lâm cuối chương. [CAN-SOAT-GOP]","detail":"Huyết Thần Tử nói nếu Vương Lâm tránh được tiên thuật của lão thì là may mắn, sau đó tay phải lóe hồng quang. Hồng quang hóa thành một con Huyết Yến lao thẳng về phía Vương Lâm, mở đầu đòn truy sát tiếp theo.","nguon":["@c0799","@c0897"]},{"id":"yeu-hoa-bat-diet","name":"Yêu Hỏa bất diệt","cn":"","category":"khac","categoryLabel":"Yêu hỏa","phamCap":"Lực lượng gắn với Cổ Yêu","soHuu":["Cổ Yêu"],"trangThai":"tồn tại","blurb":"Yêu Hỏa bất diệt là lực lượng gắn với Cổ Yêu, được thân ảnh bước thứ ba dùng để răn đe. Nếu Cổ Yêu gây sát kiếp ảnh hưởng việc của Liên Minh, người này tuyên bố sẽ hủy Yêu Hỏa của nó.","detail":"Khi can thiệp chiến cuộc, thân ảnh tinh quang không phủ nhận việc Cổ Yêu mượn Diêu gia khôi phục Yêu thể, nhưng cấm Cổ Yêu khiến La Thiên sinh sát kiếp. Lời cảnh cáo nhắm thẳng vào Yêu Hỏa bất diệt, cho thấy đây là điểm trọng yếu với Cổ Yêu.","nguon":["@c0804"]},{"id":"giot-mua-bong-tuyet","name":"Giọt mưa bông tuyết","cn":"","category":"khac","categoryLabel":"Vật phòng thân","phamCap":"Chứa ba lượt Hoán Vũ","soHuu":["Vương Lâm"],"trangThai":"đang giữ","blurb":"Giọt mưa bông tuyết là vật phòng thân Thanh Thủy trao cho Vương Lâm. Bên trong chứa ba lượt tiên thuật Hoán Vũ.","detail":"Sau khi an bài con đường tiên trì cho Vương Lâm, Thanh Thủy ngưng hóa một giọt nước trong suốt giống giọt mưa bông tuyết và giao cho hắn. Vật này có thể dùng ba lượt Hoán Vũ để phòng thân trong các biến cố sau.","nguon":["@c0804"]},{"id":"tam-cam-la-ban","name":"Tâm cấm la bàn","cn":"","aliases":["la bàn Tâm Cấm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cấm khí của đại Phá Diệt tâm cấm","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"La bàn cần có của truyền nhân Phá Diệt Cấm, được Vương Lâm dùng để phá thủy khí cấm trong Tiên phủ. (+) La bàn bát giác do Vương Lâm luyện thành sau khi nhận truyền thừa Phá Diệt tâm cấm. [CAN-SOAT-GOP]","detail":"Vật này được cô đọng từ nước đen truyền thừa trong từ đường Lý gia, dung nhập tảng đất lấy ở Lôi Tiên giới và chịu nguyên thần của Vương Lâm rèn luyện. Lý Nguyên xác nhận mỗi người nhận đại Phá Diệt tâm cấm đều cần có tâm cấm la bàn của riêng mình.","nguon":["@c0805","@c0943"]},{"id":"tang-dat-lay-o-loi-tien-gioi","name":"Tảng đất lấy ở Lôi Tiên giới","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Vật liệu luyện cấm khí","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Vật liệu Vương Lâm từng thu được ở Lôi Tiên giới theo chỉ điểm của Lý Nguyên.","detail":"Trong quá trình luyện tâm cấm la bàn, Vương Lâm dung nhập tảng đất này vào quả cầu nước đen để giúp cô đọng thành la bàn bát giác của đại Phá Diệt tâm cấm.","nguon":["@c0805"]},{"id":"ngoc-gian-ghi-loi-nguyen-quyet","name":"Ngọc giản ghi Lôi Nguyên Quyết","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm truyền công","phamCap":"Ngọc giản công pháp","soHuu":["Lý Nguyên"],"trangThai":"dang-co","blurb":"Ngọc giản do Vương Lâm trao cho Lý Nguyên trước khi rời Phá Diệt Tinh.","detail":"Bên trong ghi Lôi Nguyên Quyết, công pháp có thể giúp Lý Nguyên tăng xác suất đột phá Âm Hư. Lý Nguyên nhận vật này sau khi quyết định bế quan tiềm tu.","nguon":["@c0805"]},{"id":"lenh-bai-tu-cach-nam-vuc-la-thien","name":"Lệnh bài tư cách Nam vực La Thiên","cn":"","category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Tín vật xác nhận tư cách tham gia tranh đoạt phong hào Nam vực La Thiên.","detail":"Người muốn tham gia cuộc tranh đoạt phong hào Nam vực La Thiên cần có lệnh bài tư cách; nếu không có sẽ không được tham chiến, và nếu đến muộn sau khi khu vực bị phong tỏa thì cũng không được vào.","nguon":["@c0806"]},{"id":"truong-kiem-mau-do-cua-duong-ngon-phong","name":"Trường kiếm màu đỏ của Đường Ngôn Phong","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Đường Ngôn Phong"],"trangThai":"hong","blurb":"Trường kiếm màu đỏ là vũ khí Đường Ngôn Phong dùng để công kích Vương Lâm. Nó bị Trảm La Quyết đánh vỡ thành nhiều mảnh.","detail":"Đường Ngôn Phong lao vào Vương Lâm với trường kiếm đỏ phát ra kiếm khí kinh người. Vương Lâm áp sát và thi triển Trảm La Quyết, trực tiếp chém vỡ thanh kiếm rồi tiếp tục phá thần thông hoa sen đỏ của đối phương.","nguon":["@c0807"]},{"id":"buc-tranh-phong-an-nu-tu-huong-gia","name":"Bức tranh phong ấn nữ tử Hướng gia","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"không rõ","blurb":"Bức tranh phong ấn nữ tử Hướng gia được Vương Lâm nhớ lại khi xác lập lý do phải thắng trong cuộc tranh đoạt. Lời của nữ tử trong tranh là một nguyên nhân khiến hắn tới La Thiên Tinh Vực.","detail":"Trong hồi ức trước khi bước vào cuộc tranh đoạt Nam Vực La Thiên, Vương Lâm nhớ tới lời của nữ tử Hướng gia bị phong ấn trong tranh. Mối liên hệ này gắn trực tiếp với mục tiêu hồi sinh Lý Mộ Uyển và nhu cầu dương danh để Hướng gia coi trọng yêu cầu của hắn.","nguon":["@c0807"]},{"id":"chin-thanh-dao","name":"Chín thanh đao","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"không rõ","soHuu":["Nam Cung Hàn"],"trangThai":"đang hiện hữu","blurb":"Chín thanh đao cắm trên tảng đá trước người tu sĩ áo đen được sứ giả Lôi Tiên Điện chú ý. Chúng gắn với khí thế của người áo đen trong vòng dự phong danh hiệu.","detail":"Trong lúc sứ giả áo tím tìm người khiêu chiến Hứa Mộc, người áo đen khoảng bốn mươi tuổi trước mặt có chín thanh đao cắm trên tảng đá được nhắc tới như một nhân vật đáng chú ý. Bộ đao này là dấu hiệu nhận diện rõ nhất của hắn trong cuộc phong danh hiệu.","nguon":["@c0808"]},{"id":"chu-chien-di-vat-cua-to-tien-chien-gia","name":"Chữ Chiến di vật của tổ tiên Chiến gia","cn":"","category":"khac","categoryLabel":"Di vật","phamCap":"không rõ","soHuu":["Chiến gia","Chiến Không Liệt"],"trangThai":"đang lưu giữ","blurb":"Di vật tổ tiên Chiến gia để lại, nơi Chiến Không Liệt từng tĩnh tọa suy nghĩ suốt trăm năm. Nó góp phần giúp hắn hình thành chiến ý bất khuất.","detail":"Sau khi cảm ngộ sấm sét ở Thiên Lôi Tinh, Chiến Không Liệt trở về gia tộc và tĩnh tọa dưới chữ Chiến của tổ tiên suốt trăm năm. Trải nghiệm ấy kết hợp với cảm ngộ thiên lôi, tạo thành ý cảnh chiến ý bất khuất của hắn.","nguon":["@c0808"]},{"id":"dao-niem-cua-chien-khong-liet","name":"Đạo niệm của Chiến Không Liệt","cn":"","category":"khac","categoryLabel":"Đạo niệm","phamCap":"không rõ","soHuu":["Chiến Không Liệt"],"trangThai":"đang giữ","blurb":"Đạo niệm mà Chiến Không Liệt đem ra đặt cược trong trận khiêu chiến Hứa Mộc. Nếu tâm phục, hắn sẽ dâng đạo niệm và tôn Hứa Mộc làm Tôn Chủ.","detail":"Khi bước vào quầng sáng khiêu chiến, Chiến Không Liệt tuyên bố nếu Hứa Mộc khiến hắn tâm phục thì hắn sẽ dâng đạo niệm, tôn Hứa Mộc làm Tôn Chủ và hết sức phụng mệnh. Đạo niệm này là biểu tượng cho sự quy phục đạo tâm của hắn.","nguon":["@c0808"]},{"id":"chin-thanh-dao-cua-nam-cung-han","name":"Chín thanh đao của Nam Cung Hàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"chưa rõ","soHuu":["Nam Cung Hàn"],"trangThai":"đang dùng","blurb":"Bộ chín thanh đao cắm trước người Nam Cung Hàn, dùng làm vật dẫn Cửu Khúc Thiên Đao.","detail":"Chín thanh đao tạo đao khí khóa đường rút của Vương Lâm; bốn thanh sau đó xoay thành cơn lốc để phát động Thiên Đao trảm diệt.","nguon":["@c0809"]},{"id":"buc-hoa-tang-chin-tang-pham-cac","name":"Bức họa tầng chín Tàng Phẩm Các","cn":"","category":"khac","categoryLabel":"Di tích truyền thừa","phamCap":"chưa rõ","soHuu":[],"trangThai":"tồn tại trong Tàng Phẩm Các","blurb":"Bức họa gắn với Tiên Đế Bạch Phàm và cảm ngộ Hô Phong của Vương Lâm.","detail":"Ký ức về bức họa khiến Vương Lâm cảm giác hóa thành đồng tử, tận mắt thấy Tiên Đế Bạch Phàm nâng tay gọi hắc long hủy diệt sinh linh.","nguon":["@c0809"]},{"id":"thien-dao-cua-nam-cung-han","name":"Thiên Đao","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"chưa rõ","soHuu":["Nam Cung Hàn"],"trangThai":"tan vỡ trong giao chiến","blurb":"Bộ Thiên Đao của Nam Cung Hàn dùng trong Thiên Đao Đồ Ma.","detail":"Bốn đao đầu hợp lực giết một hắc long, năm đao sau hóa ngân quang chém xuống Vương Lâm rồi đều tan vỡ sau khi đối kháng hắc long phun âm phong lẫn mưa.","nguon":["@c0810"]},{"id":"chin-thanh-dao-hu-ao","name":"Chín thanh đao hư ảo","cn":"","category":"phap-bao","categoryLabel":"Đao ảnh","phamCap":"chưa rõ","soHuu":["Nam Cung Hàn"],"trangThai":"biến hóa trong đao trận","blurb":"Chín đao ảnh hiện quanh Nam Cung Hàn trong trận cận chiến với Vương Lâm.","detail":"Hai thanh bị chỉ pháp của Vương Lâm phá trước, sau đó lại biến hóa ra trong Cửu Khúc Đao Trận để xoay quanh thân Nam Cung Hàn phòng ngự.","nguon":["@c0810"]},{"id":"do-hinh-thu-cot","name":"Đồ hình Thú Cốt","cn":"","category":"khac","categoryLabel":"Ấn ký","phamCap":"chưa rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Đồ hình trên tay phải Vương Lâm, phát huy tác dụng áp chế thương thế trong chiến đấu.","detail":"Khi đao khí của Nam Cung Hàn đang phá hoại trong cơ thể, đồ hình Thú Cốt hiện ra u quang và khí xám, giúp Vương Lâm áp chế thương thế để tiếp tục truy kích.","nguon":["@c0810"]},{"id":"hon-da-mau-den-mo-tran","name":"Hòn đá màu đen","cn":"","category":"khac","categoryLabel":"Vật mở trận","phamCap":"chưa rõ","soHuu":["Lão già áo tím"],"trangThai":"đã dùng","blurb":"Vật phẩm được lão già áo tím dùng để mở truyền tống trận đặc biệt về Lôi Tiên Điện.","detail":"Sau khi bị bóp nát, hòn đá khiến tinh quang lóe lên và trận pháp hư ảo xuất hiện giữa tinh không, đưa nhóm Nam Vực rời Địa Viêm Tinh.","nguon":["@c0811"]},{"id":"lenh-bai-tranh-doat-danh-hieu","name":"Lệnh bài tranh đoạt danh hiệu","cn":"","category":"khac","categoryLabel":"Lệnh bài","phamCap":"chưa rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"sẽ phát sau ba ngày","blurb":"Lệnh bài Lôi Tiên Điện sẽ đưa cho các tu sĩ tham dự tranh đoạt danh hiệu.","detail":"Người tiếp dẫn thông báo sau ba ngày sẽ có người của Lôi Tiên Điện đưa lệnh bài và sắp xếp chỗ nghỉ cho các tu sĩ tham gia tranh đoạt một trăm lẻ tám danh hiệu.","nguon":["@c0812"]},{"id":"cac-dai-dien-tu-loi-tien-gioi","name":"Các đại điện từ Lôi Tiên Giới","cn":"","category":"khac","categoryLabel":"Kiến trúc mang về","phamCap":"chưa rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"tồn tại tại Lôi Tiên Điện","blurb":"Một nghìn ba trăm bảy mươi hai tòa đại điện của Lôi Tiên Điện, do các đời Điện Chủ mang về từ Lôi Tiên Giới.","detail":"Các đại điện tỏa tiên lực nồng đậm, tạo thành quy mô khổng lồ của Lôi Tiên Điện mà người tiếp dẫn giới thiệu với Vương Lâm trên đường vào nội điện.","nguon":["@c0812"]},{"id":"phong-tien-thach","name":"Phong Tiên Thạch","cn":"","category":"khac","categoryLabel":"di vật/tiên vật","phamCap":"liên hệ Viễn Cổ Tiên Vực","soHuu":["Viêm Lôi Tử","Lôi Tiên Điện"],"trangThai":"xuất hiện trong nghi thức Phong Tiên","blurb":"Phong Tiên Thạch là di vật trọng yếu được Viêm Lôi Tử công bố trong trận tranh đoạt phong tiên.","detail":"Người lọt vào ba mươi sáu Thiên Cang có cơ hội lưu danh trên Phong Tiên Thạch. Các lão quái liên hệ vật này với truyền thuyết Viễn Cổ Tiên Vực, vì người được lưu danh có thể được đưa vào hoặc được tiếp nhận khi tiên vực mở lại; khối trong tay Viêm Lôi Tử do một vị tiền bối từng thu được Nguyệt Thú giao cho hắn.","nguon":["@c0813","@c0826"]},{"id":"tin-vat-nam-xua-cua-viem-loi-tu","name":"Tín vật năm xưa của Viêm Lôi Tử","cn":"","category":"khac","categoryLabel":"tín vật","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đã giao","blurb":"Tín vật Viêm Lôi Tử từng trao cho Vương Lâm, được nhắc lại như một vật có thể hữu dụng về sau.","detail":"Khi triệu kiến Vương Lâm, Viêm Lôi Tử nhắc việc năm xưa đã đưa tín vật cho hắn, coi đó là vận may đã hứa và nói về sau có thể rất hữu dụng.","nguon":["@c0813"]},{"id":"lenh-bai-cua-tran-san-giao-cho-vuong-lam","name":"Lệnh bài của Trần San giao cho Vương Lâm","cn":"","category":"khac","categoryLabel":"lệnh bài","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có","blurb":"Lệnh bài to bằng bàn tay do Trần San giao cho Vương Lâm sau khi hắn rời Lôi Tiên Điện.","detail":"Lệnh bài giống ngọc giản, chứa bản đồ Lôi Tiên Điện, địa điểm nơi ở và một truyền tống trận chưa mở liên quan tranh phong tiên; Trần San cũng nói có thể dùng nó để truyền âm khi cần trợ giúp.","nguon":["@c0813"]},{"id":"bo-doan-bach-ngoc","name":"Bồ đoàn bạch ngọc","cn":"","category":"khac","categoryLabel":"vật phẩm/đài tọa","phamCap":"không rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"đang dùng","blurb":"Mười bồ đoàn bạch ngọc tản tiên khí đặt bên ngoài Lôi Trì cho các đại tu dự khán.","detail":"Các bồ đoàn được bố trí quanh chiến trường Lôi Trì, dành cho Viêm Lôi Tử, Thanh Thủy và các lão tổ, lão quái đủ tư cách ngồi xem tranh phong tiên.","nguon":["@c0813"]},{"id":"nguyet-thu","name":"Nguyệt Thú","cn":"","category":"khac","categoryLabel":"thú/vật liên quan tiền bối bí ẩn","phamCap":"không rõ","soHuu":["vị tiền bối bí ẩn"],"trangThai":"được nhắc tới","blurb":"Nguyệt Thú được Viêm Lôi Tử nhắc trong chuyện nguồn gốc Phong Tiên Thạch.","detail":"Viêm Lôi Tử nói có một vị tiền bối sau khi thu được Nguyệt Thú đã một mình tìm tới và đưa cho hắn một khối Phong Tiên Thạch to bằng bàn tay.","nguon":["@c0813"]},{"id":"dai-kiem-mau-vang","name":"Đại kiếm màu vàng","cn":"","category":"khac","categoryLabel":"Vũ khí thần thông","phamCap":"Do thần thông hóa ra","soHuu":["La Tố"],"trangThai":"hóa hiện @c0814","blurb":"Đại kiếm màu vàng là vũ khí do người khổng lồ kim giáp của La Tố cầm khi khảo nghiệm được tăng cường. Nó được dùng để chém xuống Vương Lâm trên quảng trường.","detail":"Sau khi La Tố phá cấm chế và tăng sức ép với Vương Lâm, người khổng lồ kim giáp cao trăm trượng hiện ra cầm đại kiếm màu vàng. Đây là vũ khí được thần thông hóa ra trong khảo nghiệm, phối hợp với thế công của người khổng lồ kim giáp.","nguon":["@c0814"]},{"id":"bi-giap-cua-co-than","name":"Bì giáp của Cổ Thần","cn":"","category":"khac","categoryLabel":"Vật phòng hộ nguyên thần","phamCap":"Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"đang tồn tại trong nguyên thần Vương Lâm","blurb":"Lớp bảo hộ trong nguyên thần Vương Lâm, khắc chế thần thức thuật của La Tố.","detail":"Khi châm thần thức và thanh xà của La Tố xuyên vào cơ thể Vương Lâm, chúng đều va phải bì giáp của Cổ Thần rồi tan vỡ hoặc hóa khí, khiến sở trường công kích nguyên thần của La Tố không thể gây trọng thương như dự liệu.","nguon":["@c0815"]},{"id":"chiec-trong-nho-cua-la-to","name":"Chiếc trống nhỏ của La Tố","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["La Tố"],"trangThai":"đã tự hủy","blurb":"Pháp bảo La Tố ném ra để chống hắc long Hô Phong của Vương Lâm.","detail":"Khi hắc long Hô Phong áp sát, La Tố ném chiếc trống nhỏ ra rồi quát Cổ băng, khiến trống vỡ và sinh lực công kích triệt tiêu một hắc long.","nguon":["@c0815"]},{"id":"phap-bao-bao-ve-nguyen-than-cua-hua-moc","name":"Pháp bảo bảo vệ nguyên thần của Hứa Mộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"chua-xac-nhan","blurb":"Đây là pháp bảo mà Viêm Lôi Tử suy đoán Hứa Mộc có trên người để bảo vệ nguyên thần. Chương chưa xác nhận trực tiếp sự tồn tại hay lai lịch của vật này.","detail":"Viêm Lôi Tử cho rằng Hứa Mộc có thể sở hữu một pháp bảo rất mạnh bảo vệ nguyên thần, thậm chí có khả năng do Thanh Thủy tặng. Nhận định này xuất phát từ suy đoán trong lòng ông khi đánh giá năng lực của Hứa Mộc.","nguon":["@c0816"]},{"id":"ngoc-gian-mau-xanh-cua-tay-tu-phuong","name":"Ngọc giản màu xanh của Tây Tử Phượng","cn":"","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Tây Tử Phượng","Vương Lâm"],"trangThai":"da-trao","blurb":"Ngọc giản màu xanh là vật Tây Tử Phượng trao cho Vương Lâm trước khi Địa Chi Quan bắt đầu. Hành động này thể hiện sự lo lắng của nàng trước thử thách Lôi Trì.","detail":"Tây Tử Phượng lấy ngọc giản màu xanh từ túi trữ vật, bay đến trước mặt Vương Lâm rồi đặt vào tay hắn. Chương chưa giải thích nội dung cụ thể của ngọc giản, nhưng đặt nó ngay trước khảo nghiệm Lôi Trì.","nguon":["@c0816"]},{"id":"trong-lon-mau-den","name":"Trống lớn màu đen","cn":"","category":"phap-bao","categoryLabel":"Pháp khí khảo nghiệm","phamCap":"Không rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"Được hai sứ giả Lôi Tiên Điện gọi ra trong cửa thứ hai của khảo nghiệm tại Lôi Trì","blurb":"Trống lớn màu đen do hai sứ giả Lôi Tiên Điện biến ảo ra, dùng tiếng trống làm mốc thời gian cho cửa thứ hai. Mỗi tiếng trống khiến lôi uy trong Lôi Trì tăng mạnh hơn.","detail":"Trong khảo nghiệm cửa thứ hai tại Lôi Trì, sau khi Viêm Lôi Tử tuyên bố lấy tiếng trống để tính thời gian, hai sứ giả Lôi Tiên Điện gọi ra một chiếc trống lớn màu đen. Tiếng trống vang lên làm lôi quang trong Lôi Trì dâng cao, lôi uy liên tục tăng, thúc đẩy lôi điện ngưng tụ thành Lôi Linh và đào thải nhiều tu sĩ không chịu nổi áp lực.","nguon":["@c0817"]},{"id":"ba-manh-ngoc-gian-mau-xanh","name":"Ba mảnh ngọc giản màu xanh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phòng hộ","phamCap":"không rõ","soHuu":["Nam tử áo xanh"],"trangThai":"hong","blurb":"Ba mảnh ngọc giản màu xanh được nam tử áo xanh dùng để hấp thu lôi quang trong lôi trì. Chúng bị Lôi Linh đánh vỡ khi công kích hắn.","detail":"Nam tử áo xanh lấy ba mảnh ngọc giản màu xanh ra trước người để hấp thu lôi quang và chống đỡ áp lực trong lôi trì. Khi Lôi Linh lao tới, ba ngọc giản va chạm với lôi lực rồi vỡ vụn thành vô số mảnh, khiến chủ nhân phun máu và phải rút lui.","nguon":["@c0818"]},{"id":"chien-tu-thiep","name":"Chiến Tự Thiếp","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thập đại pháp bảo La Thiên Tinh Vực","soHuu":["Liệt Vân Tử"],"trangThai":"dang-co","blurb":"Chiến tự thiếp là nguồn cung cấp phần lớn lực bổn nguyên trong con mắt thứ ba của Vương Lâm. Lực này được dùng để mở lại Thiên Nghịch ở chương 918. (+) Chí bảo của Chiến gia, một trong thập đại pháp bảo của La Thiên Tinh Vực. [CAN-SOAT-GOP]","detail":"Cuộn tranh cổ mở ra chỉ có một chữ Chiến mang sát khí kinh người khiến người nhìn như vào chiến trường Tu La, bên trong chứa bổn nguyên lực cực mỏng. Tổ tiên Chiến gia nhờ được chí bảo này mà đổi sang họ Chiến.","nguon":["@c0820","@c0918"]},{"id":"tam-khuc-go-viem-loi-tu","name":"Tám khúc gỗ của Viêm Lôi Tử","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"dang-co","blurb":"Vật phẩm nghi thức Viêm Lôi Tử dùng để đưa tu sĩ vào Nhất Đường Thiên.","detail":"Viêm Lôi Tử lấy tám khúc gỗ từ túi trữ vật, phóng to thành khoảng mười trượng, tỏa ánh sáng nhiều màu chiếu xuống một trăm mười hai tu sĩ để đưa họ vào Nhất Đường Thiên.","nguon":["@c0821"]},{"id":"kien-thien-minh","name":"Kiến Thiên Minh","category":"khac","categoryLabel":"Linh thú","phamCap":"Không rõ","soHuu":["Đồng tử đầu to"],"trangThai":"đang xuất hiện","blurb":"Linh trùng màu tím do đồng tử đầu to nuôi dưỡng.","detail":"Đồng tử đầu to ném ánh sáng tím hóa thành con kiến màu tím dài mấy trượng, vượt qua và kẹp lấy Thân Công Hổ bằng hai gọng kìm.","nguon":["@c0822"]},{"id":"kim-phu","name":"Kim phù","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật phẩm Vương Lâm dùng chiếm phân thần tu sĩ tự tuyệt.","detail":"Được Vương Lâm dùng để chiếm lấy một chút phân thần của các tu sĩ tự tuyệt trong chiến trường.","nguon":["@c0824"]},{"id":"da-truyen-am-cua-loi-tien-dien","name":"Đá truyền âm của Lôi Tiên điện","cn":"","category":"khac","categoryLabel":"Vật phẩm truyền tin","phamCap":"chưa rõ","soHuu":["Lôi Tiên điện"],"trangThai":"đang dùng","blurb":"Vật phẩm truyền tin được Lôi Tiên điện bố trí khắp tinh vực La Thiên. Nó vừa phát hình ảnh nghi lễ Phong Tiên, vừa phục vụ tổng động viên quyết chiến với Liên Minh.","detail":"Trong nghi lễ Phong Tiên, đá truyền âm của Lôi Tiên điện truyền âm thanh và hình ảnh ra các tinh cầu tu chân, để các gia tộc và đội quân bốn hướng cùng quan sát. Mục đích của nó không chỉ là truyền hình ảnh Phong Tiên mà còn là tổng động viên cho cuộc quyết chiến với Liên Minh.","nguon":["@c0825"]},{"id":"tam-lua-mau-vang","name":"Tấm lụa màu vàng","cn":"","category":"khac","categoryLabel":"Vật nghi lễ","phamCap":"chưa rõ","soHuu":["Viêm Lôi Tử","Lôi Tiên điện"],"trangThai":"đang dùng","blurb":"Tấm lụa vàng do tiên hạc ngậm đưa tới cho Viêm Lôi Tử trong nghi lễ Phong Tiên. Vật này tỏa tiên khí đậm và được dùng khi tuyên phong.","detail":"Khi nghi lễ Phong Tiên diễn ra, tiên hạc mang tấm lụa màu vàng tới cho Viêm Lôi Tử. Tấm lụa tỏa tiên khí rất đậm, gắn trực tiếp với phần tuyên bố cơ cấu chính, phó Lôi Tiên, Thiên Cương tiên và Địa Sát tiên.","nguon":["@c0825"]},{"id":"thien-ho-ky","name":"Thiên Hổ kỳ","cn":"","category":"tien-bao","categoryLabel":"Tiên bảo / linh kỳ","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm","blurb":"Thiên Hổ kỳ là tiên bảo Viêm Lôi Tử ban cho Hứa Mộc khi phong Chính phẩm Lôi tiên. Lá cờ hình hổ cho phép điều khiển ba nghìn tu sĩ La Thiên, hình thành một phương quân lực.","detail":"Trong nghi thức Phong Tiên, Viêm Lôi Tử dùng tiên bút ghi danh Hứa Mộc lên tấm lụa vàng, kim quang hóa thành hổ rồi thu nhỏ thành Thiên Hổ kỳ. Vật này là tín vật của Chính phẩm Lôi tiên, gắn Vương Lâm với quyền chỉ huy ba nghìn tu sĩ của La Thiên tinh vực.","nguon":["@c0826"]},{"id":"linh-ky","name":"Linh kỳ","cn":"","category":"khac","categoryLabel":"Vật phẩm phong tiên","phamCap":"không rõ","soHuu":["Một trăm lẻ tám vị tiên"],"trangThai":"được ban trong nghi thức Phong Tiên","blurb":"Linh kỳ là vật phẩm được ban cho các tiên giả trong nghi thức Phong Tiên. Mỗi người trong một trăm lẻ tám vị tiên nhận linh kỳ để trở thành tiên giả trấn giữ một nơi.","detail":"Sau khi Hứa Mộc và Hứa Đình được phân phong, Viêm Lôi Tử lần lượt phong một trăm lẻ tám vị tiên. Mỗi người nhận một linh kỳ, qua đó có thân phận tiên giả và phụ trách một nơi trong hệ thống Phong Tiên của La Thiên.","nguon":["@c0826"]},{"id":"truyen-am-thach","name":"Truyền Âm thạch","cn":"","category":"khac","categoryLabel":"Vật truyền cảnh","phamCap":"không rõ","soHuu":["Tu sĩ La Thiên"],"trangThai":"được dùng để theo dõi Phong Tiên","blurb":"Truyền Âm thạch là vật để tu sĩ toàn La Thiên chứng kiến cảnh Phong Tiên. Qua nó, mọi người theo dõi Hứa Mộc được phong Lôi tiên và việc hắn khắc tên lên Phong Tiên thạch.","detail":"Trong chương, hình ảnh Vương Lâm lan khắp La Thiên, khiến các tu sĩ ở nhiều tinh cầu và địa điểm khác nhau cùng chứng kiến nghi thức. Truyền Âm thạch được dùng như vật truyền cảnh để người trong tinh vực theo dõi Phong Tiên và đặc biệt chú ý việc Hứa Mộc có khắc tên lên Phong Tiên thạch hay không.","nguon":["@c0826"]},{"id":"qua-cau-phong-an-nguyen-anh","name":"Quả cầu phong ấn Nguyên Anh","cn":"","category":"khac","categoryLabel":"Vật phong ấn","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang chứa Nguyên Anh Lý Mộ Uyển","blurb":"Quả cầu phong ấn Nguyên Anh là vật Vương Lâm lấy ra khi đưa yêu cầu cứu Lý Mộ Uyển. Quả cầu ánh sáng dịu mở ra như đóa hoa, để lộ Nguyên Anh đang ngủ say bên trong.","detail":"Khi Hướng Vân Đông yêu cầu xem Nguyên Anh, Vương Lâm lấy quả cầu phong ấn từ túi trữ vật. Quả cầu mở ra, bộc lộ Nguyên Anh Lý Mộ Uyển yếu ớt nhưng thánh khiết, được Vương Lâm bảo vệ bằng cấm thuật để chờ cơ hội ngưng tụ thân thể và thức tỉnh.","nguon":["@c0826"]},{"id":"qua-cau-cam-che-chua-nguyen-anh-ly-mo-uyen","name":"Quả cầu cấm chế chứa Nguyên Anh Lý Mộ Uyển","cn":"","category":"khac","categoryLabel":"Cấm chế/vật chứa","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang được Vương Lâm giữ","blurb":"Vật chứa do Vương Lâm thu phong ấn quanh Nguyên Anh Lý Mộ Uyển lại thành quả cầu.","detail":"Sau khi nghe chẩn đoán của Hướng Vân Đông và quyết định thử Thất Tịch Thuật, Vương Lâm thu phong ấn quanh Nguyên Anh Lý Mộ Uyển thành một quả cầu cấm chế. Quả cầu này được hắn cầm trong tay khi nói lời đồng ý hy sinh sinh cơ.","nguon":["@c0827"]},{"id":"manh-dai-luc-nho-tien-gioi","name":"Mảnh đại lục nhỏ tiên giới","cn":"","category":"nguyen-lieu","categoryLabel":"Mảnh vỡ tiên giới","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"được dùng mở thông đạo","blurb":"Mảnh đại lục nhỏ được Viêm Lôi Tử phóng ra để tạo dòng xoáy mở thông đạo tới Liên Minh.","detail":"Viêm Lôi Tử phóng ra một mảnh đại lục nhỏ từ ánh sáng đen trên đỉnh đầu. Hơn mười mảnh đại lục nhỏ ngưng tụ trên bầu trời Lôi Tiên điện, xoay tròn tạo uy áp và dòng xoáy cực mạnh để phá mở không gian.","nguon":["@c0827"]},{"id":"la-co-nho-cua-than-cong-lao-to","name":"Lá cờ nhỏ của Thân Công lão tổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thân Công lão tổ"],"trangThai":"dang-co","blurb":"Pháp bảo được Thân Công lão tổ gọi ra khi hỗ trợ phá bức tường không gian. Lá cờ hóa thành vệt sáng mờ bay vào dòng xoáy.","detail":"Trong nhóm lão quái La Thiên ra tay sau Mạnh Vân Tử, Thân Công lão tổ vỗ trán gọi ra một lá cờ nhỏ. Pháp bảo này hóa thành vệt sáng mờ nhập vào dòng xoáy, góp lực phá mở không gian.","nguon":["@c0828"]},{"id":"muoi-manh-dai-luc-nho","name":"Mười mảnh đại lục nhỏ","cn":"","category":"khac","categoryLabel":"Địa khối phong ấn","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"da-dung","blurb":"Mười mảnh đại lục nhỏ được Viêm Lôi Tử dùng làm nền cho nghi thức mở khe không gian. Chúng chứa linh hồn đại lục bị phong ấn và cuối cùng bị hy sinh để chống khe khép lại.","detail":"Trong nghi thức Khai Thiên Tích địa, mười mảnh đại lục nhỏ hóa thành những bóng người là linh hồn đại lục bị Viêm Lôi Tử phong ấn, rồi nhập vào dòng xoáy để tạo lực phá vách không gian. Khi khe hở sắp khép lại, Viêm Lôi Tử dùng các mảnh đại lục chống vào khe; chúng liên tiếp vỡ nát nhưng giúp kéo khe dài ra, trước khi bị cánh tay khổng lồ từ trong khe bóp nát.","nguon":["@c0828"]},{"id":"lenh-ky-cua-mot-tram-le-tam-vi-tien","name":"Lệnh kỳ của một trăm lẻ tám vị tiên","cn":"","category":"khac","categoryLabel":"Vật phẩm quân lệnh","phamCap":"Không rõ","soHuu":["Chính, phó Lôi Tiên và một trăm lẻ tám vị tiên"],"trangThai":"dang-co","blurb":"Lệnh kỳ được chính, phó Lôi Tiên cùng một trăm lẻ tám vị tiên cầm khi tiến vào tinh vực Liên Minh. Nó gắn với mệnh lệnh tổng tiến công của Viêm Lôi Tử.","detail":"Sau khi đường sang tinh vực Liên Minh mở ra, chính, phó Lôi Tiên cùng một trăm lẻ tám vị tiên cầm lệnh kỳ xông qua khe không gian theo lệnh Viêm Lôi Tử. Vật phẩm này biểu thị quân lệnh và đội ngũ tinh nhuệ của Lôi Tiên Điện trong chiến dịch đầu tiên.","nguon":["@c0828"]},{"id":"da-truyen-tong","name":"Đá truyền tống","cn":"","category":"khac","categoryLabel":"Vật phẩm trận pháp","phamCap":"Không rõ","soHuu":["Các gia tộc tu chân La Thiên"],"trangThai":"da-dung","blurb":"Đá truyền tống trên các tinh cầu tu chân La Thiên vỡ nát để kích hoạt truyền tống đại trận. Chúng đưa tu sĩ các gia tộc tới cạnh khe không gian tiến vào Liên Minh.","detail":"Theo lệnh Viêm Lôi Tử, đá truyền tống trên các tinh cầu tu chân trong toàn tinh vực La Thiên đồng loạt vỡ nát. Sự vỡ nát này hình thành truyền tống đại trận khổng lồ, đưa tu sĩ các gia tộc tới chiến trường cạnh khe hở không gian.","nguon":["@c0828"]},{"id":"ngoc-gian-mau-do-huong-van-dong","name":"Ngọc giản màu đỏ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hướng Vân Đông"],"trangThai":"dang-co","blurb":"Ngọc giản Hướng Vân Đông dùng để dò tìm vị trí Đông Lâm tinh vốn di chuyển không cố định.","detail":"Hướng Vân Đông lấy ra từ túi trữ vật để dò tìm vị trí Đông Lâm tinh vốn di chuyển không cố định trong khu vực phía Đông La Thiên.","nguon":["@c0829"]},{"id":"hoan-vu-tinh","name":"Hoán Vũ Tinh","cn":"","category":"khac","categoryLabel":"Vật phẩm hỗ trợ tiên thuật","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật hỗ trợ tiên thuật có thể kết hợp với tiên nguyên lực để thi triển, giúp Vương Lâm tự bảo vệ tại Liên Minh Tinh Vực.","detail":"Thanh Thủy nhắc cùng tiên nguyên lực, nói hai vật khác nhau nhưng có thể kết hợp để thi triển tiên thuật, giúp Vương Lâm tự bảo vệ trong Liên Minh Tinh Vực nếu không rơi vào chiến đấu của tu sĩ đại thần thông.","nguon":["@c0831"]},{"id":"tien-nguyen-luc-thanh-thuy","name":"Tiên nguyên lực của Thanh Thủy","cn":"","category":"khac","categoryLabel":"Năng lượng / lễ vật","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một đạo tiên nguyên lực Thanh Thủy để lại trong cơ thể Vương Lâm, hóa thành hạt tiên khí trong nguyên thần.","detail":"Thanh Thủy để lại một đạo tiên nguyên lực trong cơ thể Vương Lâm, được vận chuyển thành một hạt tiên khí rơi vào nguyên thần, dùng làm nguồn lực có hạn để thi triển tiên thuật, xem như lễ vật nhỏ.","nguon":["@c0831"]},{"id":"chia-khoa-dong-phu-ngam-trong-yeu-linh-chi-dia","name":"Chìa khoá động phủ ngầm trong Yêu Linh chi địa","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Vương Lâm đang giữ","blurb":"Chìa khoá động phủ ngầm trong Yêu Linh chi địa là vật phẩm Vương Lâm vẫn cất giữ cẩn thận. Nó liên quan đến việc tiến vào động phủ ngầm tại Yêu Linh chi địa.","detail":"Khi trở lại Liên Minh Tinh Vực, Vương Lâm vẫn giữ chìa khóa để tiến vào động phủ ngầm trong Yêu Linh chi địa. Vật này được cất trong túi trữ vật của hắn và được nhắc như một manh mối còn tiếp tục có giá trị.","nguon":["@c0833"]},{"id":"thap-son-khoi-loi-ho-ve","name":"Tháp Sơn","cn":"","category":"khac","categoryLabel":"Khôi lỗi hộ vệ","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang theo Vương Lâm","blurb":"Khôi lỗi hộ vệ đi cùng Vương Lâm. Khi Vương Lâm rời tinh cầu hoang dã trở về Chu Tước Tinh, Tháp Sơn dung nhập vào thân thể hắn.","detail":"Tháp Sơn hiện diện bên cạnh Vương Lâm trong đoạn hắn khôi phục sức sống trên tinh cầu hoang dã. Trước khi Vương Lâm hướng về Chu Tước Tinh, Tháp Sơn nhoáng lên rồi nhập vào thân thể hắn, tiếp tục vai trò hộ vệ đi theo.","nguon":["@c0835"]},{"id":"co-than-dinh","name":"Cổ Thần Đỉnh","cn":"","aliases":["Cổ Thần đại đỉnh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"đang hiện dùng qua hư ảnh","blurb":"Bảo vật Cổ Thần được Vương Lâm dùng trong động phủ thứ năm để dịch chuyển cự ly ngắn. Nó giúp hắn kéo giãn khoảng cách với gió xoáy nhưng không thể thoát hoàn toàn khỏi nguy cơ. (+) Đại đỉnh của Cổ Thần được Vương Lâm gọi ra dưới dạng hư ảnh. Trong chương này, nó là trung tâm để hắn thi triển Hoán vị, đổi vị trí với Đồng tử đầu to. [CAN-SOAT-GOP]","detail":"Khi Đồng tử đầu to sắp thoát khỏi tầng cương phong, bên ngoài thân thể Vương Lâm hiện ra hư ảnh Cổ Thần Đỉnh. Dựa vào đại đỉnh này, hắn thi triển Hoán vị khiến vị trí của mình và Đồng tử đầu to đảo ngược, phá hỏng kế hoạch bỏ chạy tố cáo thân phận Hứa Mộc.","nguon":["@c0836","@c0953"],"tabs":{}},{"id":"kim-phu-dung-nhap-nguyen-than-tu-si","name":"Kim phù dung nhập nguyên thần tu sĩ","cn":"","category":"khac","categoryLabel":"Phù văn phong ấn","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"được Phong Tiên Ấn phóng xuất","blurb":"Một số kim phù trong Phong Tiên Ấn có nguyên thần tu sĩ dung nhập, uy lực phong ấn vượt xa phù văn thường. Chúng góp phần phong bế toàn thân đồng tử đầu to trong trận chiến.","detail":"Khi Vương Lâm phun Phong Tiên Ấn, hơn mười vạn kim phù hóa thành lốc xoáy vàng. Trong đó có những phù văn đã dung nhập nguyên thần tu sĩ, khiến sức phong ấn đối với đồng tử đầu to mạnh hơn rất nhiều.","nguon":["@c0837"]},{"id":"tien-dau-tien-nguyen","name":"Tiên đậu tiên nguyên","cn":"","category":"khac","categoryLabel":"Vật lưu tiên nguyên","phamCap":"tiên gia","soHuu":["Vương Lâm"],"trangThai":"còn trong cơ thể Vương Lâm","blurb":"Tiên đậu do Thanh Thuỷ lưu lại trong cơ thể Vương Lâm, chứa tiên nguyên có thể xoay chuyển khi hắn thi triển tiên thuật. Một tia tiên nguyên từ đó giúp Định Thân thuật và Hoàng Ấn Quyết phát huy uy lực đặc biệt.","detail":"Trong lúc Vương Lâm thi triển Định Thân thuật, Tiên đậu tiên nguyên trong cơ thể xoay chuyển và đưa tiên nguyên vào thiên địa, khiến phép định thân mạnh hơn trước. Khi gieo Hoàng Ấn Quyết, tiên nguyên này tiếp tục là then chốt để hoàn thành phong ấn nô dịch.","nguon":["@c0837"]},{"id":"ngoc-gian-cua-tien-de-thanh-lan","name":"Ngọc giản của Tiên Đế Thanh Lân","cn":"","category":"khac","categoryLabel":"Ngọc giản truyền pháp","phamCap":"tiên gia","soHuu":["Vương Lâm"],"trangThai":"đã được Vương Lâm lĩnh hội một phần","blurb":"Ngọc giản chứa phương pháp luyện chế Tiên vệ và một số pháp thuật thao khống phong ấn. Đây là nguồn giúp Vương Lâm hiểu và thi triển ấn quyết nô dịch đồng tử đầu to.","detail":"Vương Lâm nhớ tới nội dung trong ngọc giản của Tiên Đế Thanh Lân khi suy xét việc dùng tiên nguyên thi triển phong ấn. Ngọc giản này chứa phương pháp luyện Tiên vệ, các pháp thuật thao khống phong ấn và từng thoáng đề cập tới Nô Ấn của Lý Nguyên.","nguon":["@c0837"]},{"id":"linh-loai","name":"Linh Loại","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Vật/hạt giống linh khí","phamCap":"không rõ","soHuu":["Vương Lâm","Lão già Anh Biến"],"trangThai":"đã được để lại cho mười người ở Triệu quốc","blurb":"Linh Loại là vật Vương Lâm từng để lại cho mười người ở Triệu quốc khi còn ở cảnh giới Hóa Thần. Đến chương này, lão già Anh Biến của Huyền Đạo Tông được nhận ra là một trong số những người ấy.","detail":"Năm xưa tại Triệu quốc, Vương Lâm từng để lại mười viên Linh Loại cho mười người. Khi trở lại nhà tổ ở Chu Tước Tinh, hắn phát hiện trên người lão già Anh Biến của Huyền Đạo Tông có hơi thở mỏng manh cùng loại với mình, từ đó nhận ra lão là một trong mười người từng nhận Linh Loại.","nguon":["@c0839"]},{"id":"ky-hieu-mau-den-do-oan-khi-bien-thanh","name":"Ký hiệu màu đen do oán khí biến thành","cn":"","category":"khac","categoryLabel":"Dấu vết","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang dẫn đường","blurb":"Ký hiệu màu đen sinh ra sau khi hắc xà oán linh bị Vương Lâm nghiền nát. Nó được ném ra để tự bay dẫn đường tới nguồn liên quan.","detail":"Hắc xà oán linh trong thân hoàng tử bị một chỉ của Vương Lâm đánh tan, hóa thành khí đen rồi ngưng thành ký hiệu màu đen. Vương Lâm không giữ nó như pháp bảo mà dùng nó làm dấu vết lần theo nơi có liên hệ với oán khí.","nguon":["@c0841"]},{"id":"phuong-linh-ho-than","name":"Phượng linh hộ thân","cn":"","category":"phap-bao","categoryLabel":"Hộ thân","phamCap":"Không rõ","soHuu":["Nữ tử y phục rực rỡ"],"trangThai":"hong","blurb":"Phượng linh bảo hộ nữ tử Phượng Loan tinh trong trận chiến với Vương Lâm tại hoàng cung Vương gia.","detail":"Nữ tử y phục rực rỡ có phượng linh hộ thân, giúp nàng chống đỡ nhiều lần lôi ý của Vương Lâm. Phòng hộ này cuối cùng bị Vương Lâm liên tục điểm chỉ phá tan trước khi thân thể nàng nổ tung.","nguon":["@c0842"]},{"id":"cay-mau-xanh-tim","name":"Cây màu xanh tím","cn":"","category":"khac","categoryLabel":"Vật ký sinh","phamCap":"Không rõ","soHuu":["Lưu Thanh Vân","Thi Âm Tông"],"trangThai":"bị phá hủy","blurb":"Cây màu xanh tím là vật ký sinh cắm rễ trong thân Lôi Cát để hút sức sống nhưng không phá hủy Thiên Phú Thần Thông của Cự Ma Tộc. Bên trong nó chứa thần thức của Lưu Thanh Vân, phó điện chủ Oán Điện.","detail":"Cây màu xanh tím bám trong thân thể Lôi Cát, được Thi Âm Tông dùng để hao tổn sức sống và chuẩn bị thân thể Cự Ma Tộc cho đoạt xá. Khi bị Vương Lâm kéo khỏi Lôi Cát, nó biến thành quái vật hơn mười trượng có hoa, gai, xúc tu và thần thức. Sau khi bị Phong Tiên Ấn, lôi lực và Thú Cốt công kích, cây tan rã, để khí xanh tím nhập vào bóng hắc bào và khiến Lưu Thanh Vân hiện thân.","nguon":["@c0844"]},{"id":"loi-tri-phap-luc","name":"Lôi Trì","cn":"","aliases":[],"category":"khac","categoryLabel":"Khu vực pháp lực","phamCap":"Không rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"bị phá rồi được phục hồi khu vực khảo nghiệm","blurb":"Lôi Trì là khu vực pháp lực của Địa Chi Quan vừa bị Vương Lâm phá hủy sau khi nuốt Lôi Linh. Viêm Lôi Tử xem tổn thất này là chấp nhận được để đổi lấy một tiểu bối cao thủ cho La Thiên.","detail":"Trong chương này Lôi Trì được nhắc lại như tổn thất của Lôi Tiên Điện sau Địa Chi Quan. Viêm Lôi Tử không trách Vương Lâm, còn dùng việc mất một Lôi Trì và một phân thân Lôi Linh để nhấn mạnh giá trị của Hứa Mộc đối với La Thiên Tinh Vực.","nguon":["@c0820"]},{"id":"phan-than-loi-linh","name":"Phân thân Lôi Linh","cn":"","aliases":[],"category":"khac","categoryLabel":"Linh thể khảo nghiệm","phamCap":"Không rõ","soHuu":["Lôi Tiên Điện"],"trangThai":"bị Vương Lâm nuốt","blurb":"Phân thân Lôi Linh là linh thể khảo nghiệm ở Địa Chi Quan. Nó bị Vương Lâm nuốt, rồi được Viêm Lôi Tử nhắc như một phần tổn thất nhỏ của Lôi Tiên Điện.","detail":"Sau khi Vương Lâm rời khỏi Lôi Trì, Viêm Lôi Tử nhắc tới phân thân Lôi Linh cùng Lôi Trì như cái giá phải trả. Ông cho rằng đổi những tổn thất ấy lấy một tiểu bối cao thủ cho La Thiên Tinh Vực là đáng giá.","nguon":["@c0820"]},{"id":"bon-nguyen-luc-trong-chien-tu-thiep","name":"Bổn nguyên lực trong Chiến Tự Thiếp","cn":"","category":"khac","categoryLabel":"Năng lượng","phamCap":"Bổn nguyên lực","soHuu":["Chiến Tự Thiếp","Hứa Đình","Vương Lâm"],"trangThai":"xuất hiện","blurb":"Tia bổn nguyên lực ẩn trong Chiến Tự Thiếp xuất hiện khi tu sĩ khảo nghiệm chữ Chiến. Một phần rất ít lưu lại trong Hứa Đình, còn tia vào Vương Lâm thì bị con mắt thứ ba hút lấy.","detail":"Trong khảo nghiệm Thiên Chi Quan, bổn nguyên lực từ Chiến Tự Thiếp có thể lưu lại trong người khảo nghiệm. Hứa Đình nhận được một phần rất ít, khiến Vương Lâm nhận ra giá trị lớn khi đối phương tiến tới đỉnh bước thứ hai; với Vương Lâm, tia bổn nguyên lực lao vào mi tâm, thúc đẩy con mắt thứ ba tiến hóa nhưng cũng tạo nguy cơ cắn trả.","nguon":["@c0821"]},{"id":"tui-tru-vat-cua-tay-tu-phuong","name":"Túi trữ vật của Tây Tử Phượng","category":"khac","categoryLabel":"Vật phẩm","phamCap":"không rõ","soHuu":["Tây Tử Phượng"],"trangThai":"đang có","blurb":"Túi trữ vật của Tây Tử Phượng, nơi nàng cất ngọc giản màu xanh.","detail":"Trước khi Vương Lâm vào Lôi Trì, Tây Tử Phượng sờ túi trữ vật rồi lấy ra ngọc giản màu xanh để trao cho hắn. Vật phẩm thể hiện sự chuẩn bị và lo lắng của nàng trong Địa Chi Quan.","nguon":["@c0816"]},{"id":"tui-tru-vat-cua-tu-si-la-thien-bi-giet","name":"Túi trữ vật của tu sĩ La Thiên bị giết","cn":"","category":"khac","categoryLabel":"Vật phẩm trữ vật","phamCap":"không rõ","soHuu":["Tu sĩ Liên Minh giả yếu thế"],"trangThai":"bị đoạt @c0829","blurb":"Túi trữ vật của tu sĩ La Thiên bị phản sát tại chiến trường khe nứt. Sau khi giết đối thủ, tu sĩ Liên Minh cầm túi trữ vật này rồi tiếp tục bỏ chạy.","detail":"Vật phẩm xuất hiện trong cảnh tu sĩ Liên Minh giả yếu thế phản sát kẻ truy kích. Nó cho thấy chiến trường hai tinh vực không chỉ là rút lui và truy sát mà còn đầy hành vi giết người đoạt bảo.","nguon":["@c0829"]},{"id":"con-mat-thu-ba-cua-vuong-lam","name":"Con mắt thứ ba của Vương Lâm","cn":"","category":"khac","categoryLabel":"Đặc dị trên thân","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang có @c0829","blurb":"Con mắt thứ ba trên thân Vương Lâm chứa lực lượng bản nguyên. Khi tổ tiên Hướng gia dùng thần thức quét qua, lực lượng này tràn ngập toàn thân khiến hắn không bị nhìn thấu hoàn toàn.","detail":"Trong cấm địa phía Tây Đông Lâm tinh, thần thức tổ tiên Hướng gia tập trung vào Vương Lâm khiến hắn hoảng sợ. Tuy vậy, lực lượng bản nguyên từ con mắt thứ ba bao phủ toàn thân, ngăn đối phương nhìn thấu toàn bộ bí mật của hắn.","nguon":["@c0829"]},{"id":"quan-tai-khong-lo","name":"Quan tài khổng lồ","cn":"","category":"khac","categoryLabel":"Vật phong ấn","phamCap":"không rõ","soHuu":["Thi Âm Tông"],"trangThai":"vỡ @c0844","blurb":"Quan tài vài trăm trượng trôi trong hang động sâu nhất của tổng bộ Thi Âm Tông, dùng để giam giữ Lôi Cát.","detail":"Quan tài khổng lồ phủ đầy cấm chế và chứa thân thể Cự Ma Tộc của Lôi Cát. Vương Lâm điểm tay phá cấm, khiến quan tài vỡ tan và giải phóng người khổng lồ bị phong bên trong.","nguon":["@c0844"]},{"id":"dau-an-hinh-chiec-bua","name":"Dấu ấn hình chiếc búa","cn":"","category":"khac","categoryLabel":"Dấu ấn","phamCap":"không rõ","soHuu":["Lôi Cát"],"trangThai":"tồn tại @c0844","blurb":"Dấu ấn lờ mờ trên mi tâm Lôi Cát, hiện ra khi thân thể khổng lồ của hắn được lộ khỏi quan tài.","detail":"Khi quan tài vỡ, trên mi tâm Lôi Cát có dấu ấn hình chiếc búa thi thoảng lóe sáng. Dấu ấn gắn với thân thể người khổng lồ Cự Ma Tộc của hắn.","nguon":["@c0844"]},{"id":"phap-bao-thu-nguyen-than","name":"Pháp bảo thu nguyên thần","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thân Công Hổ"],"trangThai":"dang-co","blurb":"Pháp bảo của Thân Công Hổ dùng để thu nguyên thần đối thủ bị giết, nhưng không thể sử dụng do không mở được túi trữ vật trong chiến trường.","detail":"Thân Công Hổ nhớ tới pháp bảo này trong lúc bị kiến Thiên Minh áp đảo, tiếc vì không thể mở túi trữ vật trong chiến trường nên không lấy ra được.","nguon":["@c0823"]},{"id":"tam-cay-cot-go","name":"Tám cây cột gỗ","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Tám cây cột gỗ trên bầu trời phía trên tảng đá rộng ngàn trượng tại Lôi Tiên điện, chấn động dữ dội khi thiên lôi trong chiến trường bị Vương Lâm dẫn động.","detail":"Khi nguyên thần Thái Cổ Lôi Long gầm vang, tám cây cột gỗ lập tức chấn động, lưới sét ngưng tụ trên chúng cũng bất ổn. Viêm Lôi Tử phải đứng dậy đánh thủ ấn liên tục để ổn định chúng, cho thấy đây là bộ phận then chốt trong trận thế kiểm soát lôi điện của Lôi Tiên điện.","nguon":["@c0823"]},{"id":"viem-linh-hoa-thi","name":"Viêm Linh Hỏa Thi","cn":"","category":"khac","categoryLabel":"Kỳ thi dị thể","phamCap":"Hạng 12 bảng kỳ thi dị thể Thi Âm Tông","soHuu":["Lưu Thanh Vân"],"trangThai":"da-dung","blurb":"Kỳ thi dị thể hạng 12 của Thi Âm Tông, toàn thân đỏ sẫm xuất hiện kèm lửa tràn ngập trời đất. Nếu đoạt xá thành công sẽ miễn dịch mọi hỏa hệ thần thông và nắm giữ Thiên Địa Chi Hỏa.","detail":"Toàn thân đỏ sẫm, xuất hiện kèm lửa tràn ngập trời đất. Nếu đoạt xá thành công sẽ miễn dịch mọi hỏa hệ thần thông và nắm giữ Thiên Địa Chi Hỏa. Bị Lưu Thanh Vân hy sinh cho tự bạo trong phạm vi nhỏ để ám toán Vương Lâm, uy lực kinh hoàng nhưng bị Cổ Thần Cự Đỉnh chắn hoàn toàn.","nguon":["@c0845"]},{"id":"nguyen-than-khuy-niet-tu-si","name":"Nguyên thần Khuy Niết tu sĩ","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nguyên thần đối thủ cũ của Lưu Thanh Vân, thần trí đã tiêu tan chỉ còn thể xác nguyên thần, vốn định luyện thành khôi lỗi. Bị dâng cho Vương Lâm.","detail":"Nguyên thần của một tu sĩ Khuy Niết đối thủ cũ của Lưu Thanh Vân, thần trí đã tiêu tan chỉ còn thể xác nguyên thần. Lưu Thanh Vân vốn định luyện thành khôi lỗi nhưng đã dâng cho Vương Lâm khi giả vờ cầu hòa.","nguon":["@c0845"]},{"id":"tam-kinh-mi-tam","name":"Tấm kính mi tâm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lưu Thanh Vân"],"trangThai":"dang-co","blurb":"Pháp bảo trữ vật ẩn giữa mi tâm của Lưu Thanh Vân, bên trong chứa nguyên thần Khuy Niết và Viêm Linh Hỏa Thi.","detail":"Lưu Thanh Vân từ giữa mi tâm triệu xuất tấm kính này, bên trong chứa nguyên thần Khuy Niết tu sĩ và Viêm Linh Hỏa Thi. Dùng làm không gian trữ vật đặc biệt.","nguon":["@c0845"]},{"id":"chin-thanh-truong-kiem","name":"Chín thanh trường kiếm","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiết Nham"],"trangThai":"Đã tặng","blurb":"Chín thanh trường kiếm Vương Lâm tặng cho Thiết Nham tại Vân Thiên Tông khi giải quyết nhân quả.","detail":"Vương Lâm trước khi rời Vân Thiên Tông đã tặng thêm chín thanh trường kiếm cho Thiết Nham, ngoài lượng tiên ngọc chất thành núi trên quảng trường để giúp khôi phục tu vi. Đây là một phần trong việc giải quyết nhân quả — Thiết Nham vì Chu Như mà thoái hóa tu vi, Vương Lâm báo đáp bằng tiên ngọc và pháp bảo.","nguon":["@c0846"]},{"id":"binh-mau-loi-cat","name":"Bình máu Lôi Cát","cn":null,"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Sất Hổ"],"trangThai":"Đã tặng","blurb":"Bình nhỏ chứa máu của Lôi Cát — máu tổ tiên Cự Ma Tộc, có thể trợ giúp uy lực Thiên Phú Thần Thông.","detail":"Vương Lâm lấy máu Lôi Cát đựng trong một bình nhỏ tặng cho Sất Hổ, nói rằng trong bình có máu của tổ tiên Cự Ma Tộc. Máu này có thể trợ giúp uy lực Thiên Phú Thần Thông của Cự Ma Tộc. Lôi Cát chính là hậu duệ tổ tiên Cự Ma Tộc, huyết mạch trong máu hắn mang sức mạnh nguyên thủy của tộc.","nguon":["@c0846"]},{"id":"bay-dao-tinh-hon","name":"Bảy đạo tinh hồn","cn":"七道星魂","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã dùng (bơm vào Chu Tước Tinh)","blurb":"Bảy đạo tinh hồn rút từ các tinh cầu hoang tàn trong Liên Minh Tinh Vực, được Vương Lâm bơm vào Chu Tước Tinh khôi phục linh mạch.","detail":"Vương Lâm dùng tu vi Khuy Niết Sơ Kỳ bay đến vùng tinh không Liên Minh Tinh Vực, từ nhiều tinh cầu hoang tàn rút tinh hồn (mỗi nơi chỉ rút ba phần để không hủy hoại tinh cầu). Trong một ngày rút được bảy đạo tinh hồn mang trở về, lần lượt đưa vào lòng đất Chu Tước Tinh. Linh mạch hồi phục, Chu Tước Hồn chấn động, tiếng phượng kêu vang khắp tinh cầu, nửa bỏ hoang hồi sinh, linh khí nồng đậm trở lại. Phàm nhân cảm thấy ấm áp, bệnh tật biến mất; tu sĩ cảm nhận linh lực trong cơ thể tự vận chuyển.","nguon":["@c0846"]},{"id":"tien-cau-khoi-phuc","name":"Tiên cầu (khôi phục tu vi)","cn":null,"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thiết Nham"],"trangThai":"Đã dùng","blurb":"Quả cầu ngưng kết từ lượng lớn tiên ngọc, Vương Lâm đưa vào cơ thể Thiết Nham để giúp khôi phục tu vi đã thoái hóa.","detail":"Vương Lâm lấy lượng lớn tiên ngọc ngưng tụ thành tiên cầu rồi đưa vào cơ thể Thiết Nham, giúp khôi phục tu vi từ Hóa Thần Hậu Kỳ (đã thoái hóa) trở lại. Đây là phần giải quyết nhân quả: Thiết Nham vì hy sinh tuổi thọ và sức sống giúp Chu Như đạt Anh Biến mà thoái hóa, Vương Lâm dùng tiên ngọc báo đáp.","nguon":["@c0846"]},{"id":"phi-kiem-tang-hau-nhan-truong-ho","name":"Phi kiếm (tặng hậu nhân Trương Hổ)","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hậu nhân Trương Hổ"],"trangThai":"Đã tặng","blurb":"Phi kiếm Vương Lâm tặng cho nữ tử hậu nhân Trương Hổ tại Hợp Hoan Tông, Triệu Quốc.","detail":"Vương Lâm tìm thấy nữ tử hậu nhân của Trương Hổ đang là ngoại vi đệ tử Hợp Hoan Tông ở Triệu Quốc, tu luyện khí tầng thấp. Hắn tặng linh thạch, tiên ngọc và phi kiếm cho nàng, nói đây là quả của giao hảo với tổ tiên Trương Hổ năm đó.","nguon":["@c0846"]},{"id":"thu-cot-vuong-lam","name":"Thú Cốt","cn":"兽骨","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang sử dụng","blurb":"Pháp bảo trên tay phải Vương Lâm, mang u quang và sát khí tràn ngập, có thể phối hợp lôi đình để phá phong ấn.","detail":"Thú Cốt nằm trên tay phải Vương Lâm, khi kích phát sẽ biến ảo hiện ra với u quang bao phủ và sát khí tràn ngập. Tại tầng 16 hố sâu Tiên Di Tộc, Vương Lâm dùng Thú Cốt phối hợp với lôi đình đánh vào ký hiệu phong ấn trên hồ nước đen, khiến ký hiệu hóa đá, góp phần phá vỡ phong ấn mở đường xuống tầng 17.","nguon":["@c0847"]},{"id":"la-bua-dieu-gia","name":"Lá bùa của Diêu gia","cn":null,"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Còn trên thân Vương Lâm","blurb":"Lá bùa kỳ dị của tộc nhân Diêu gia, có sức mạnh phong ấn toàn bộ sức mạnh đối phương.","detail":"Năm đó tộc nhân Diêu gia dùng lá bùa này khi giao chiến với Vương Lâm ở La Thiên Tinh Vực, phát huy sức mạnh kỳ dị phong ấn toàn bộ sức mạnh của hắn. Trên thân Vương Lâm vẫn còn một lá bùa này. Đây chính là nguyên nhân chính khiến Vương Lâm quyết tâm xuống các tầng sâu hố Tiên Di Tộc để tìm hiểu bí mật, vì hắn nghi ngờ bí mật bên dưới có liên quan đến lá bùa.","nguon":["@c0847"]},{"id":"tien-dau-thanh-thuy","name":"Tiên đậu","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Vật phẩm do Thanh Thủy Tiên Quân tặng, nằm trong cơ thể Vương Lâm, chứa tiên nguyên lực.","detail":"Do Thanh Thủy Tiên Quân tặng Vương Lâm. Trong Hình Đường vận chuyển chậm chạp như chìm trong nước do môi trường áp chế. Vương Lâm phát hiện tiên nguyên khí từ thi hài tiên nhân bị tiêu diệt có thể dung hợp vào tiên đậu, bổ sung tiên nguyên lực — giải quyết vấn đề lâu nay không tìm được cách gia tăng (mỗi lần dùng đều hao, hết sạch thì tiên đậu tan vỡ).","nguon":["@c0848"]},{"id":"la-bua-mau-vang-ao-canh","name":"Lá bùa màu vàng","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Những lá bùa màu vàng kích thước khác nhau trong ảo cảnh đại chiến cổ xưa, mỗi lá có nhiều người Tiên Di Tộc kỳ dị đứng trên.","detail":"Trong ảo cảnh đại chiến giữa tiên nhân cưỡi mây và Tiên Di Tộc mà Vương Lâm nhìn thấy khi cảm ngộ bổn nguyên tầng mười tám, phía trước tiên nhân là những lá bùa màu vàng kích thước khác nhau, từ vài trượng đến vài trăm trượng, trên mỗi lá bùa có nhiều người kỳ dị của Tiên Di Tộc đứng.","nguon":["@c0850"]},{"id":"qua-cau-lua-ban-nguyen-phu-toc","name":"Quả cầu lửa bản nguyên Phù tộc","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Lão đạo chưởng môn Hằng Nhạc Phái"],"trangThai":"dang-co","blurb":"Lực lượng bản nguyên của Kim Diệp Phù Sĩ đại viên mãn của Phù tộc biến thành, cảm ngộ được sẽ có lợi cho tu vi.","detail":"Quả cầu lửa là lực lượng bản nguyên của Kim Diệp Phù Sĩ đại viên mãn của Phù tộc. Cảm ngộ được sẽ có lợi cho tu vi, là khảo nghiệm bắt buộc cho đệ tử nội môn Chu Tước trong Tứ Thánh Tông. Lão đạo sĩ chụp vào tay và hút lực lượng từ đó.","nguon":["@c0851"]},{"id":"bay-huyet-kiem-do-tham","name":"Bảy huyết kiếm đỏ thẫm","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"","soHuu":["Vu Phi"],"trangThai":"hong","blurb":"Bảy cây kiếm đỏ rực vờn quanh Vu Phi, có thể hóa phân thân hoặc hợp thành đại kiếm.","detail":"Bảy cây kiếm đỏ rực mang sát khí và mùi máu tanh vờn quanh người Vu Phi, có thể hóa phân thân hoặc hợp thành đại kiếm phòng thủ. Bị sấm sét ngưng tụ của Vương Lâm phá hủy toàn bộ ba mươi lăm thanh sau khi nhân phân thân.","nguon":["@c0851"]},{"id":"hon-da-to-ong","name":"Hòn đá tổ ong","category":"khac","categoryLabel":"Vật cưỡi","phamCap":"","soHuu":["Vu Phi"],"trangThai":"dang-co","blurb":"Khối đá khổng lồ dày đặc lỗ hổng to nhỏ giống tổ ong, di chuyển tốc độ cực nhanh.","detail":"Khối đá khổng lồ dày đặc lỗ hổng to nhỏ giống tổ ong. Vu Phi đứng trên đó di chuyển với tốc độ cực nhanh, ma sát tạo lửa đỏ.","nguon":["@c0851"]},{"id":"loi-thu-tan-chi","name":"Lôi Thụ Tàn Chi","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vu Phi"],"trangThai":"dang-co","blurb":"Cành cây bảo vật của Sát Vực Giới có thể át lực lượng sấm sét.","detail":"Cành cây trông bình thường nhưng toát vẻ tang thương, là bảo vật của Sát Vực Giới được Giới chủ nói có thể át lực lượng sấm sét. Vu Phi dùng nó hấp thu toàn bộ sấm sét mà Vương Lâm ngưng tụ từ chu vi mấy vạn dặm, khiến sấm sét tự động thay đổi phương hướng phóng vào cành cây mà không tổn thương Vu Phi.","nguon":["@c0852"]},{"id":"nam-thanh-kiem-do-tham-vu-phi","name":"Năm thanh kiếm đỏ thẫm","cn":"","category":"phap-bao","categoryLabel":"Phi kiếm","phamCap":"","soHuu":["Vu Phi"],"trangThai":"dang-co","blurb":"Năm thanh phi kiếm của Vu Phi.","detail":"Năm thanh phi kiếm đỏ thẫm của Vu Phi. Khi bị sấm sét đánh lên thì co rút rút lui, rồi lại gào thét tấn công cùng Vu Phi khi hắn xông lên.","nguon":["@c0852"]},{"id":"tui-linh-thao-tong-oanh","name":"Túi linh thảo","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Tống Oánh"],"trangThai":"dang-co","blurb":"Túi nhỏ Tống Oánh tự tay hái linh thảo may lại, có tác dụng định khí ngưng thần.","detail":"Tống Oánh tự tay hái linh thảo may lại thành túi nhỏ có tác dụng định khí ngưng thần, định tặng bản tôn Vương Lâm nhưng chưa kịp thì hắn đã bay đi.","nguon":["@c0852"]},{"id":"nam-phi-kiem-do-tham-vu-phi","name":"Năm cây phi kiếm đỏ thẫm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vu Phi"],"trangThai":"hong","blurb":"Năm thanh kiếm đỏ thẫm bay bên ngoài cơ thể Vu Phi, có thể hóa thành phân thân Khuy Niết sơ kỳ.","detail":"Năm thanh kiếm bay bên ngoài cơ thể Vu Phi, mỗi thanh có thể hóa thành phân thân tu vi Khuy Niết sơ kỳ. Trong trận với Vương Lâm, hai cây bị phá hủy cùng hai phân thân, bốn cây còn lại đâm vào nhục thân Vương Lâm chỉ phát ra tiếng kim loại rồi bị đánh văng.","nguon":["@c0853"]},{"id":"ban-menh-phap-bao-vu-phi","name":"Bản mệnh pháp bảo của Vu Phi","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Khuy Niết trung kỳ","soHuu":["Vu Phi"],"trangThai":"hong","blurb":"Bản mệnh pháp bảo của Vu Phi, huyết quang hoá thành đại kiếm hồng sắc dài mười trượng.","detail":"Huyết quang nồng đậm bay ra từ Thiên Linh của Vu Phi, hoá thành đại kiếm hồng sắc dài mười trượng. Bị Vương Lâm dùng thân xác hợp thể đập vỡ trực tiếp, khiến Vu Phi bị phản phệ phun máu.","nguon":["@c0854"]},{"id":"thien-dia-loi-thu-tan-chi","name":"Thiên Địa Lôi Thụ Tàn Chi","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Chí bảo Sát Vực Giới","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Chí bảo Sát Vực Giới, khi Vu Phi bị giết cành cây văng ra thành hai nửa; Vương Lâm chụp một nửa mang sát khí cấp Phó Tôn.","detail":"Khi Vu Phi bị giết, túi trữ vật vỡ và cành cây văng ra — Vương Lâm chụp được nửa, lão già tóc đỏ chộp được nửa còn lại. Trên nửa của Vương Lâm có dấu sát khí cấp Phó Tôn Sát Vực Giới. Vương Lâm dùng nó làm chứng cớ giết Vu Phi trình Viêm Lôi Tử và nhận định có thứ này có thể bảo vệ Liên Minh Tây Bộ bình an — đây chính là mục đích hắn mạo hiểm đoạt lấy.","nguon":["@c0855"]},{"id":"chien-phu-loi-cat","name":"Chiến phủ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Lôi Cát"],"trangThai":"dang-co","blurb":"Binh khí Lôi Cát từng cầm khi giết vào Tiên Di Tộc.","detail":"Trong hồi ức, Lôi Cát một mình cầm chiến phủ giết vào Tiên Di Tộc, liên tục chiến mấy người lấy đầu người báo đáp ân tình của Dạ Vô Ưu.","nguon":["@c0856"]},{"id":"truyen-tan-phu","name":"Truyền tấn phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tu sĩ sáu ngón"],"trangThai":"da-dung","blurb":"Phù truyền tin dùng cầu viện.","detail":"Tu sĩ sáu ngón bóp nát truyền tấn phù để cầu viện trước khi bị thân ảnh hư ảo chiếm xác trong kế hoạch Đồ La.","nguon":["@c0857"]},{"id":"tien-nguyen-chi-tinh","name":"Tiên nguyên chi tinh","cn":"仙元之精","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tinh thể tiên nguyên lớn bằng nắm tay trẻ con nằm trong cơ thể Vương Lâm, là nguồn tiên khí để thi triển tiên thuật.","detail":"Khi kích hoạt, toàn thân Vương Lâm phát ra tiên khí nồng đậm, trông như tiên nhân chân chính. Đồng tử đầu to kinh ngạc vì Vương Lâm có tiên nguyên mà không qua Thăng Tiên Trì. Sau khi thi triển bước một Tát Đậu Thành Binh, tiên nguyên chi tinh đã rút nhỏ gần sáu phần.","nguon":["@c0858"]},{"id":"hai-nguyen-than-khuy-niet-so-ky","name":"Hai nguyên thần Khuy Niết sơ kỳ","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Nguyên thần Khuy Niết sơ kỳ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hai nguyên thần Khuy Niết sơ kỳ cực kỳ trân quý mà Vương Lâm giữ lại để khôi phục tu vi.","detail":"Một là nguyên thần của phó điện chủ Nội Oán Điện Thi Âm Tông, một là vật người đó kính dâng để bảo mệnh. Cả hai đều là nguyên thần Khuy Niết sơ kỳ. Vương Lâm quyết định không đưa vào mười tám tầng địa ngục mà giữ lại để sau này khôi phục tu vi.","nguon":["@c0859"]},{"id":"thap-bat-la-phu-huyet-cau","name":"Thập Bát La Phù Huyết Cầu","cn":"十八罗浮血球","aliases":["Thập Bát La Phù","Mười tám La Phù"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Chí bảo hộ tộc thượng cổ","soHuu":["La Thiên Tinh Vực"],"trangThai":"dang-co","blurb":"Mười tám quả huyết cầu mười trượng màu đỏ, chí bảo của hai thượng cổ tu chân gia tộc La Thiên, tích lũy máu tươi vạn năm tế luyện.","detail":"Nguồn gốc từ La Phù Sơn thời thượng cổ — một đêm tất cả tu sĩ trên núi chết, máu ngưng tụ thành huyết cầu. Phóng uy áp đè ép tâm thần đối phương, tu sĩ đã dung huyết không bị ảnh hưởng mà còn được tăng tu vi. Viêm Lôi Tử triệu hoán để đè ép tu sĩ liên minh trong trận phản kích. Hắc Sát Ma Tôn định hủy nhưng bị Huyết Thần Tử ngăn cản.","nguon":["@c0860"]},{"id":"tham-thien-cu-moc-artifact","name":"Tham Thiên Cự Mộc","cn":"参天巨木","aliases":["Cự Mộc"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Viễn cổ tiên vực di vật","soHuu":["Lôi Tiên Điện","La Thiên Tinh Vực"],"trangThai":"dang-co","blurb":"Cây gỗ viễn cổ dài vạn trượng, to ngàn trượng, xưa chống đỡ viễn cổ tiên vực, do Lôi Tiên Điện tìm được ba vạn năm trước.","detail":"Trong tứ đại tiên giới chỉ có cây này của La Thiên còn bảo tồn tương đối hoàn chỉnh. Cần trên vạn tu sĩ cùng đẩy, phá tan hàng rào khe nứt không gian xông vào liên minh tây bộ, uy lực không gì không phá. Lão tổ Hướng gia, nam tử họ Công Tôn và lão giả Hứa gia cùng ở trên cự mộc hỗ trợ.","nguon":["@c0860"]},{"id":"qua-cau-mau-tim-chu-thien","name":"Quả cầu màu tím","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Chu Thiên"],"trangThai":"Đã bị phá hủy","blurb":"Vật phẩm phòng ngự của Chu Thiên, bóp nát tỏa ánh sáng tím bao phủ toàn thân.","detail":"Quả cầu màu tím được Chu Thiên bóp nát khi giao chiến với Vương Lâm, tỏa ra ánh sáng tím bao phủ toàn thân hình thành phòng ngự. Tuy nhiên bị Vương Lâm phá vỡ dễ dàng bằng một cú đá nổ tung cả thân thể Chu Thiên.","nguon":["@c0861"]},{"id":"kim-cham-nam-tu-trung-nien","name":"Kim châm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam tử trung niên (tu sĩ Liên Minh)"],"trangThai":"Không rõ","blurb":"Vũ khí tầm xa của nam tử trung niên Liên Minh, dùng để truy đuổi Tây Tử Phượng.","detail":"Kim châm được nam tử trung niên Liên Minh sử dụng tấn công Tây Tử Phượng từ xa. Dù nàng dùng vầng sáng vàng chặn lại nhưng vẫn bị lực xuyên thấu khiến phun máu.","nguon":["@c0861"]},{"id":"ngoc-gian-mau-xanh","name":"Ngọc giản màu xanh","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Mạnh Vân Tử"],"trangThai":"da-dung","blurb":"Ngọc giản bề ngoài bình thường của Mạnh Vân Tử, được lấy từ khe không gian. Khi ném về phía Vọng Nguyệt thì nổ tung, phát ra ngôn ngữ Cổ Thần khiến Vương Lâm biến sắc chấn động.","detail":"Ngọc giản màu xanh bề ngoài không có chút thần kỳ nào. Mạnh Vân Tử chộp vào khoảng không mở khe không gian lấy ra rồi ném về phía Vọng Nguyệt khi nó tấn công cự mộc. Ngọc giản nổ tung phát ra âm thanh cổ quái hết sức phức tạp khó hiểu, chính là ngôn ngữ Cổ Thần. Tu sĩ bình thường không hiểu, chỉ Vương Lâm nhờ mang bổn tôn Cổ Thần mà hiểu được ý nghĩa và biến sắc.","nguon":["@c0862"]},{"id":"manh-tien-gioi","name":"Mảnh tiên giới","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Vật thể","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử"],"trangThai":"da-dung","blurb":"Các mảnh tiên giới được Viêm Lôi Tử triệu hoán xoay tròn dùng để vây khốn đối thủ.","detail":"Viêm Lôi Tử triệu hoán mấy mảnh tiên giới đầy trời xoay tròn tạo gió lốc vây khốn Cực Hiền Thiên. Bị cây khổng lồ đánh vỡ nát, mảnh vỡ nổ tung sức công phá ngang một tinh cầu tu chân, bắn vào người Cực Hiền Thiên.","nguon":["@c0864"]},{"id":"bao-vat-phong-than-viem-loi-tu","name":"Bảo vật phòng thân (Viêm Lôi Tử hứa tặng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực mạnh)","soHuu":["Vương Lâm"],"trangThai":"Chưa trao","blurb":"Bảo vật Viêm Lôi Tử hứa tặng Vương Lâm sau trận chiến. Có nó, trong tinh vực Liên Minh chỉ trừ vài người ra không ai có thể hại được tính mạng Vương Lâm.","detail":"Viêm Lôi Tử hứa tặng sau khi Vương Lâm lập công trạng lớn trong trận tiêu diệt Cực Hiền Thiên. Chưa được trao cụ thể, chưa rõ hình dáng hay công năng chi tiết.","nguon":["@c0865"]},{"id":"tram-ngon-thap-lien-minh","name":"Trăm ngọn tháp","category":"phap-bao","categoryLabel":"Pháp bảo tấn công","phamCap":"Không rõ","soHuu":["Liên Minh tu chân"],"trangThai":"da-dung","blurb":"Gần trăm ngọn tháp ngưng luyện từ vật liệu đặc biệt, thành phần chính của trận Bách Vạn Thú Huyết Tỏa Thiên Thần.","detail":"Lao tới mục tiêu như những thanh kiếm xẻ đôi bầu trời. Khi nổ tung hóa bụi đen bao quanh mục tiêu, phối hợp cùng máu huyết yêu thú tạo thành phong ấn. Phần lớn tháp bị xúc tua Vọng Nguyệt cuốn thì nổ tung, một số tránh được xúc tua đâm trúng thân Vọng Nguyệt rồi cũng nổ.","nguon":["@c0866"]},{"id":"bong-sen-tam-canh","name":"Bông sen tám cánh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nữ nhân váy lam"],"trangThai":"dang-co","blurb":"Pháp bảo hình bông sen tám cánh do nữ nhân váy lam cầm trên tay phải, gỡ một đóa hoa vất ra tạo uy áp kinh hoàng.","detail":"Nữ nhân váy lam gỡ một đóa hoa từ bông sen tám cánh trên tay phải vất ra, cánh hoa bay trong gió phóng to hơn mười trượng, tạo uy áp kinh hoàng đè xuống Vương Lâm khiến không gian sụp đổ, nứt khe lớn dưới chân hắn, thân thể bị sức ép chực đẩy vào khe.","nguon":["@c0868"]},{"id":"dai-hoa-sen-bay-canh","name":"Đài hoa sen bảy cánh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thủy La"],"trangThai":"dang-co","blurb":"Pháp bảo của nữ tử Thủy La, phát ra cánh hoa sen tạo uy áp khiến nguyên lực đối phương ngưng trệ, có thể hấp thu công kích và phát hư ảnh phòng ngự.","detail":"Đài hoa sen bảy cánh phát ra cánh hoa sen giáng xuống tạo uy áp mạnh mẽ khiến nguyên lực trong cơ thể đối phương bị ngưng trệ. Cánh hoa sen có khả năng hấp thu công kích và lộ ra lục ý, uy áp càng mạnh thêm. Khi bị phản công thì phát hư ảnh hoa sen phòng ngự. Bị Hoán Vũ của Vương Lâm phá tan.","nguon":["@c0869"]},{"id":"luyen-thi","name":"Luyện Thi","cn":"炼尸","category":"khac","categoryLabel":"Vật phẩm chiến tranh","phamCap":"Khuy Niết hậu kỳ (thường) / Tịnh Niết sơ kỳ (đặc biệt)","soHuu":["Thủy La"],"trangThai":"dang-co","blurb":"18 khối thi hài khổng lồ cao mười trượng, do Thi Âm Tông cung cấp thi hài, Hài Ngục Giới luyện hóa qua mấy vạn năm, dùng làm binh khí trong đại chiến.","detail":"Tổng cộng 18 khối Luyện Thi, mỗi khối cao mười trượng, toàn thân xanh đỏ, quấn thiết liên tím dùng làm vũ khí. Gào rít ảnh hưởng nguyên thần đối phương. 15 khối thường có tu vi tương đương Khuy Niết hậu kỳ. 2 khối bạc (một nam một nữ) phát ngân quang, mặc áo bạc, chỉ có hai thiết liên, uy áp đạt Tịnh Niết sơ kỳ. 1 khối cuối cùng là nam tử trung niên mặc long bào, đội cao quan, không có thiết liên, có 5 tấm chỉ phù vàng xoay quanh thiên linh loé lôi quang, toàn thân tràn ngập ngũ hành lực — là Ngũ hành linh thể.","nguon":["@c0869"]},{"id":"thiet-lien-tim","name":"Thiết liên tím","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Dây xích sắt tím quấn quanh thân Luyện Thi, dùng quét công kích, có khả năng đánh chết tu sĩ và khóa nguyên thần trên dây.","detail":"Thiết liên tím quấn quanh thân các khối Luyện Thi, vừa là xiềng xích vừa là vũ khí. Khi quét trúng tu sĩ, thân thể tan nát, nguyên thần bị khóa trên thiết liên không thể thoát. Cũng được phóng ra từ trận pháp Hài Ngục Giới.","nguon":["@c0869"]},{"id":"buc-tuong-go-hinh-nguoi","name":"Bức tượng gỗ hình người khoanh tay","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cấp cực cao)","soHuu":["Hắc Sát Ma Tôn"],"trangThai":"bi-ton-hai","blurb":"Tượng gỗ hình người hai tay khoanh trước ngực, toàn thân bị thực vật bao phủ, không rõ mặt. Khi kích hoạt sống dậy, hoá năm đoá hoa đen trăm trượng phun hắc khí.","detail":"Pháp bảo của Hắc Sát Ma Tôn, hình dạng người khoanh tay trước ngực bị thực vật bao phủ. Khi ném ra phát hắc quang sống dậy, hoá năm đoá hoa đen trăm trượng phun hắc khí âm hàn, đồng thời duỗi tay ôm đầu ngón Cổ Thần Chỉ dùng tơ đen trói buộc. Sau Cổ Thần Chỉ tự bạo, bức tượng bị tổn hại chỉ còn nửa. Vương Lâm nhắm đoạt lấy.","nguon":["@c0870"]},{"id":"nu-ngan-thi","name":"Nữ Ngân Thi","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo (Luyện Thi)","phamCap":"Ngân Thi (bạc)","soHuu":["Liên Minh Tinh Vực"],"trangThai":"ton-thuong","blurb":"Một trong hai Ngân Thi phía Liên Minh, hình dạng nữ thi xinh đẹp. Sau Cổ Thần Chỉ tự bạo bị đánh văng, thiết liên sụp đổ.","detail":"Ngân Thi cấp bạc thuộc phe Liên Minh Tinh Vực, mang hình dạng nữ tử xinh đẹp. Trong đại chiến tại Liên Minh Bắc Vực, sau khi Cổ Thần Chỉ tự bạo, bị đánh văng về phía Vương Lâm, thiết liên trên thân sụp đổ. Vương Lâm nhắm đoạt lấy.","nguon":["@c0870"]},{"id":"thu-khong-niet-tien","name":"Thứ Không Niết Tiễn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cực phẩm","soHuu":["Huyền Bảo thượng nhân"],"trangThai":"dang-co","blurb":"Pháp bảo của Huyền Bào Thượng nhân, có lực lượng khiến Vương Lâm liên tưởng khi thanh kiếm thép khớp với vỏ kiếm thứ ba. Tên pháp bảo được nhắc trực tiếp là Thử Không Niết tiễn. (+) Mũi tên xanh khổng lồ dài hơn ba mươi trượng, có lông chim tím và vết máu xám đen, được Huyền Bảo thượng nhân dẫn ra từ khe hư không. [CAN-SOAT-GOP]","detail":"Khi xuất hiện, Thứ Không Niết Tiễn khiến tu sĩ trong phạm vi mấy vạn dặm chấn động, ngay cả Huyết Thần Tử và Viêm Lôi Tử đang giao chiến cũng biến sắc. Là át chủ bài cấp chiến trường mà Huyền Bảo thượng nhân dùng để trấn áp Vọng Nguyệt và phe La Thiên.","nguon":["@c0872","@c0981"]},{"id":"chin-hac-ho-diep","name":"Chín hắc Hồ Điệp","cn":"","aliases":["Hồ Điệp đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Bảo thượng nhân"],"trangThai":"dang-co","blurb":"Chín Hồ Điệp toàn thân đen do Huyền Bảo thượng nhân gọi ra, tạo gió lốc và hắc tuyến thành lưới vây Vọng Nguyệt.","detail":"Vương Lâm nhận ra chúng giống Hồ Điệp do Xạ Thần xa biến ảo nhưng có sắc đen cực đoan khác biệt. Chín hắc Hồ Điệp phối hợp với bốn Tiên vệ kim phẩm tạo thành trận vây khốn.","nguon":["@c0872"]},{"id":"bon-kim-giap-tien-ve","name":"Bốn kim giáp Tiên vệ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Kim phẩm","soHuu":["Huyền Bảo thượng nhân"],"trangThai":"dang-co","blurb":"Bốn Tiên vệ kim phẩm triệu từ khe hư không, thuộc bí thuật của Tiên Đế Thanh Lâm, cùng khí tức với Tháp Sơn.","detail":"Bước ra từ khe hư không trước Huyền Bảo thượng nhân, chia bốn phương Đông Tây Nam Bắc vây Vọng Nguyệt, sau hóa thành người khổng lồ trăm trượng cùng công kích. Huyết Thần Tử dùng huyết hải đánh vào chỉ khiến chúng chấn động nhẹ.","nguon":["@c0872"]},{"id":"nua-buc-tuong-go","name":"Nửa bức tượng gỗ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Một nửa bức tượng gỗ do Hắc Sát Ma Tôn xuất ra trước đó, chỉ còn một nửa nhưng vẫn tràn ngập uy áp.","detail":"Bị nhiều tu sĩ tranh đoạt trên chiến trường, Vương Lâm dùng Cổ Thần Đỉnh hoán đổi vị trí rồi ôm lấy bảo vật. Thần Long tuyên bố đây là vật của Đại La Kiếm Tông nhưng bị Vương Lâm áp chế.","nguon":["@c0872"]},{"id":"tien-gioi-toai-phien","name":"Tiên Giới Toái Phiến","cn":"仙界碎片","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Viêm Lôi Tử","Vương Lâm"],"trangThai":"dang-co","blurb":"Mảnh vỡ của Tiên giới, Viêm Lôi Tử sở hữu hơn mười khối lớn dùng tạo lốc xoáy phong bạo tấn công. Trao cho Vương Lâm một mảnh nhỏ bằng nắm tay có tác dụng bảo hộ và định vị phương vị, bên trong chứa khí tức Lôi Thú. (+) Tiên giới toái phiến là mảnh vỡ do Viêm Lôi Tử từng tặng Vương Lâm sau công lao ở La Thiên. Trong chương này, nó được phóng đại thành một đại lục khổng lồ để chặn một chỉ của Thiên Vận Tử. [CAN-SOAT-GOP]","detail":"Viêm Lôi Tử dùng hơn mười khối Tiên Giới Toái Phiến lớn tạo lốc xoáy phong bạo tấn công Huyền Bảo thượng nhân. Sau đó ném cho Vương Lâm một mảnh nhỏ bằng nắm tay, nói rằng vật này vừa bảo hộ an toàn vừa giúp lão định vị phương vị để sau cứu Vương Lâm và Thanh Thủy ra. Vương Lâm cảm nhận bên trong có khí tức Lôi Thú, suy đoán không chỉ phong ấn Chủ hồn mà còn có cả Lôi Thú.","nguon":["@c0875","@c0911"]},{"id":"kim-y","name":"Kim y","cn":"金衣","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Huyền Bảo thượng nhân"],"trangThai":"hong","blurb":"Lớp áo vàng bảo hộ bên ngoài nguyên thần Huyền Bảo thượng nhân, không ngừng triệt tiêu lực công kích nhưng cuối cùng vỡ tan trong trận chiến.","detail":"Lớp kim y bảo hộ bên ngoài nguyên thần Huyền Bảo thượng nhân, liên tục triệt tiêu lực công kích từ ba phía. Tuy nhiên cuối cùng không chịu nổi sức tấn công tổng hợp, vỡ tan hoàn toàn.","nguon":["@c0875"]},{"id":"nam-tam-hoang-chi-phu","name":"Năm tấm hoàng chỉ phù","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Kim Thi"],"trangThai":"dang-co","blurb":"Năm tấm chỉ phù vàng phiêu phù trên đỉnh đầu Kim Thi, tỏa ra kiềm chế lực. Trong đó một tấm có thể kích hoạt Độc hỏa, một tấm nhả ra đất đen chứa tử khí (Táng thổ).","detail":"Năm tấm hoàng chỉ phù phiêu phù trên đỉnh đầu Kim Thi, tỏa ra lực kiềm chế. Khi Kim Thi được giải phong hóa thành kim long, chỉ phù ngừng xoay. Một tấm kích hoạt Độc hỏa khiến toàn thân kim long tràn đầy viêm hỏa kịch độc cực mạnh. Một tấm khác dùng chiêu Táng thổ nhả ra mẩu đất đen chứa tử khí nồng đậm để chống lại Nhất Mộc Tử.","nguon":["@c0875"]},{"id":"kim-lan-kiem","name":"Kim Lân Kiếm","cn":"金鳞剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Kim Thi"],"trangThai":"dang-co","blurb":"Vảy trên thân kim long bay ra ngưng tụ thành kiếm, mang theo thiên uy và long khí.","detail":"Hơn trăm chiếc vảy trên thân kim long bay ra ngưng tụ thành kim lân kiếm mang theo thiên uy và long khí, dùng để đối kháng với Thanh Thủy trong thông đạo Vọng Nguyệt.","nguon":["@c0878"]},{"id":"vien-tu-tinh","name":"Viên tử tinh","cn":"","aliases":["Lực lượng truyền thừa"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Viên tử tinh to bằng nắm tay tản mát quang mang dìu dịu, ẩn chứa một cỗ Cổ Thần lực, là lực lượng truyền thừa của Cổ Thần tộc.","detail":"Nằm trong huyết nhục tan nát của Cực Hiền Thiên sau khi bị tiêu diệt. Viên tử tinh to bằng nắm tay, tản mát quang mang dìu dịu, ẩn chứa Cổ Thần lực. Vương Lâm triệu Cổ Thần Đỉnh tới gần, cắn đầu lưỡi phun máu phát ra âm thanh quỷ dị rồi há mồm hút lấy viên tử tinh này.","nguon":["@c0880"]},{"id":"moc-bai-kim-thi","name":"Mộc bài (Kim Thi)","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Kim Thi"],"trangThai":"da-dung","blurb":"Mộc bài trong túi trữ vật của Kim Thi, bóp nát hoá khói mở thông đạo để bỏ trốn.","detail":"Mộc bài dùng một lần trong túi trữ vật của Kim Thi. Khi bóp nát sẽ hoá khói mở thông đạo cho phép bỏ trốn. Kim Thi định dùng để chạy khỏi Vương Lâm nhưng chưa kịp trốn đã bị Long Tôn ngũ hành quan thu phục.","nguon":["@c0881"]},{"id":"co-than-nhat-tinh","name":"Cổ Thần nhất tinh","cn":"","aliases":["tử tinh"],"category":"nguyen-lieu","categoryLabel":"Tinh thể","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Viên tinh thể tím (tử tinh) mà Vương Lâm nuốt vào, giúp thăng từ Tam tinh rưỡi lên Tứ tinh vương tộc Cổ Thần chân chính.","detail":"Viên tử tinh bị Vương Lâm hút về phía mình trong cuộc tranh đoạt với Nhất Mộc Tử và Võ Đông Thiện. Khi nuốt vào, lực lượng vô biên bùng nổ trong cơ thể, chi tinh trên mi tâm từ Tam tinh rưỡi thăng lên Tứ tinh chân chính — Tứ tinh vương tộc Cổ Thần kế thừa Đồ Ti.","nguon":["@c0881"]},{"id":"diet-than-mau","name":"Diệt Thần Mâu","cn":"灭神矛","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí vương tộc Cổ Thần","soHuu":["Vương Lâm","Đồ Ti"],"trangThai":"Hư huyễn hóa (Vương Lâm dùng lực Tứ Tinh ngưng tụ phiên bản hư huyễn)","blurb":"Bản mệnh pháp khí của Cổ Thần Đồ Ti, chỉ vương tộc Cổ Thần mới có thể thi triển. Vương Lâm dùng lực Tứ Tinh huyễn hóa ra phiên bản hư huyễn. (+) Vũ khí công kích do Vương Lâm cưỡng ép biến ra trong lúc trọng thương. Nó đâm vào tay Thiên Vận Tử nhưng bị đánh tan thành tinh quang. [CAN-SOAT-GOP]","detail":"Diệt Thần Mâu là pháp khí Cổ Thần truyền thừa từ thời xa xưa, mỗi Cổ Thần vương tộc khi trưởng thành đều có thể đoạt được. Nguyên bản là bản mệnh pháp khí của Đồ Ti. Vương Lâm nhớ lại pháp bảo này trong ký ức về cơ thể Cổ Thần, dùng lực Tứ Tinh huyễn hóa ra trường mâu dài trăm trượng phát hồng quang, được ngưng tụ từ sương mù đỏ. Khi Diệt Thần Mâu xuất hiện, hư vô bị vặn vẹo; quét qua khiến Tuyệt Nguyên Đại Trận hiện nguyên hình dưới dạng mạng lưới khổng lồ. La Trần nhìn thấy Diệt Thần Mâu liền xác nhận truyền thừa của Vương Lâm đến từ Đồ Ti. Phiên bản hư huyễn tuy chưa đạt uy lực tối đa nhưng vẫn đủ sức phá lộ trận pháp phong ấn hư vô.","nguon":["@c0882","@c1007","@c1042"],"tabs":{}},{"id":"khai-thien-phu","name":"Khai Thiên Phủ","cn":"开天斧","aliases":["Linh Khai Thiên Phủ"],"category":"than-khi","categoryLabel":"Thánh vật","phamCap":"Thánh vật tộc Cổ Thần","soHuu":["Lão già tóc bạc (sư tôn của thanh niên trăng lưỡi liềm)"],"trangThai":"dang-dung","blurb":"Thánh vật của tộc Cổ Thần, do La Trần nhận diện. Được lão già tóc bạc kích hoạt qua trận pháp Linh Khai Thiên Phủ, ngưng tụ thành chiến phủ khổng lồ trăm trượng mang khí hồng hoang.","detail":"La Trần nhận ra Khai Thiên Phủ là thánh vật tộc Cổ Thần và hét với Vương Lâm rằng trong truyền thừa Cổ Thần của Vương Lâm cũng tồn tại thứ này. Chiến phủ ngưng tụ từ tinh điểm khắp hư không chu vi nghìn vạn dặm, mang khí hồng hoang, tốc độ vượt quy tắc hạn chế. Đánh bại đồng thời ba người Vương Lâm, Thanh Thủy, La Trần.","nguon":["@c0884"]},{"id":"hai-co-than-tinh","name":"Hai Cổ Thần Tinh (lễ vật trưởng thành)","cn":"","category":"nguyen-lieu","categoryLabel":"Bảo vật","phamCap":"Tinh điểm Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Hai tinh điểm Cổ Thần cuối cùng mà La Trần tự móc trên mi tâm ném tặng Vương Lâm làm lễ vật trưởng thành theo tục tộc Cổ Thần.","detail":"La Trần trong khoảnh khắc sắp bị bắt đã quyết đoán tự móc hai tinh điểm Cổ Thần cuối cùng trên mi tâm ném cho Vương Lâm, gọi đây là lễ vật trưởng thành theo tục lệ mỗi đứa trẻ Cổ Thần chấp nhận khiêu chiến trưởng thành sẽ được nhận.","nguon":["@c0884"]},{"id":"nguyen-than-huyen-bao","name":"Nguyên thần Huyền Bảo","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nguyên thần của Huyền Bảo thượng nhân, chứa tiên nguyên có tác dụng cực lớn.","detail":"Thanh Thủy dặn Vương Lâm giữ lại nguyên thần của Huyền Bảo sau khi lão lấy ký ức bên trong, vì nguyên thần này chứa tiên nguyên có tác dụng cực lớn cho Vương Lâm.","nguon":["@c0886"]},{"id":"binh-ngoc-tro-cot-ton-thai","name":"Bình ngọc nhỏ (tro cốt Tôn Thái)","cn":"","aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Bình ngọc chứa tro cốt Tôn Thái, được Vương Lâm giữ trong túi trữ vật và mang đến Hạnh Hoa Thôn an táng, thực hiện lời ủy thác năm xưa.","detail":"Bình ngọc nhỏ chứa tro cốt của Tôn Thái. Tôn Thái khi hấp hối đã ủy thác Vương Lâm mang hài cốt về quê hương Ám Nguyệt Tinh, thôn nhỏ dưới Thiên Sơn. Vương Lâm mang bình đến vùng mộ phía sau Hạnh Hoa Thôn, tuyên bố ân oán đã xong.","nguon":["@c0887"]},{"id":"phi-kiem-thu-tu-dai-chien","name":"Phi kiếm thu được từ đại chiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"Được Vương Lâm nén nguyên lực làm hậu thủ trong thân Vọng Nguyệt","blurb":"Hơn mười thanh phi kiếm Vương Lâm thu được trong đại chiến, được nén nguyên lực để tự bạo và gây biến hóa.","detail":"Đây là hơn mười thanh phi kiếm Vương Lâm lấy ra từ túi trữ vật, đều thu được trong cuộc đại chiến vừa rồi. Hắn nén nguyên lực vào từng thanh rồi phóng tới những điểm mẫn cảm mà hắn biết rõ trong thân thể Vọng Nguyệt, dùng làm hậu thủ nhằm khiến cơ thể Vọng Nguyệt sinh biến hóa và tăng tiêu hao nguyên lực của các lão quái. Một số thanh còn được gắn thần thức để dò xét lốc xoáy và thông đạo.","nguon":["@c0878"]},{"id":"nam-tam-chi-phu-kim-long","name":"Năm tấm chỉ phù trên kim long","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Kim long"],"trangThai":"Được kim long dùng để phát động Ngũ hành nghịch chuyển","blurb":"Năm tấm chỉ phù trên thân kim long, phát động ngũ hành nghịch chuyển ngăn cách thông đạo.","detail":"Trên thân kim long có năm tấm chỉ phù, khi giao chiến với Thanh Thuỷ chúng phát ra điện quang, xoay tròn rồi ấn vào thân nó để phát động Ngũ hành nghịch chuyển — tạo ra năm đạo khuyết kiên kim, hình phạt mộc, hóa cống thủy, tuyệt độc hỏa, táng tiên thổ, ngăn cách thông đạo thành một mảnh thiên địa nhằm đối đầu Thanh Thuỷ.","nguon":["@c0878"]},{"id":"con-dau-trang-luoi-liem","name":"Con dấu trăng lưỡi liềm","cn":"","aliases":["Dấu ấn trăng lưỡi liềm"],"category":"phap-bao","categoryLabel":"Dấu ấn","phamCap":"không rõ","soHuu":["Lão già tóc bạc (sư tôn của thanh niên trăng lưỡi liềm)"],"trangThai":"bị kéo khỏi mi tâm","blurb":"Dấu ấn nằm trên mi tâm lão già tộc Nguyệt Phệ, là cơ sở để thi triển Nguyệt Tiên Thôn Thần. Khi thần thông thất bại, dấu ấn nứt làm hai rồi bị Nghịch Thiên Châu kéo ra khỏi mi tâm lão.","detail":"Con dấu trăng lưỡi liềm hóa thành hư ảnh dài và vầng trăng tròn để thôn phệ Vương Lâm trong Nguyệt Tiên Thôn Thần. Sau khi Nghịch Thiên Châu tự động vận chuyển, dấu ấn nổ vỡ, làm lão già phun máu; cuối chương hai luồng khí đen trắng tạo vòng xoáy, một bàn tay thò ra triệu hồi và kéo dấu ấn gãy đôi khỏi mi tâm lão.","nguon":["@c0885"]},{"id":"long-ton-ngu-hanh-quan","name":"Long Tôn ngũ hành quan","aliases":["vương miện","ngũ hành vương miện"],"cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Vương Lâm"],"trangThai":"đang thuộc Vương Lâm","blurb":"Long Tôn ngũ hành quan là vương miện Vương Lâm lấy ra trong lúc Kim Thi phản kích. Bên trong có hồn nữ tử tuyệt luân, khi kích hoạt có thể thu Kim Thi hoá thành kim quang vào trong.","detail":"Trong chương 881, Vương Lâm lấy Long Tôn ngũ hành quan từ túi trữ vật khiến Kim Thi kinh hoàng nhận ra. Vương miện phóng hào quang nhiều màu, biến ảo đóa hoa hồng và gọi ra hư ảnh nữ tử toàn thân ngạo khí; nàng chỉ một ngón tay về phía Kim Thi đang định bỏ chạy, khiến Kim Thi hóa kim quang bị hút vào vương miện. Sau đó hư ảnh nữ tử nhìn kỹ Vương Lâm như muốn nói điều gì nhưng không phát ra thanh âm rồi biến mất.","nguon":["@c0881"]}]};